// CSS injection helper. In Tauri 2 production builds the runtime
// auto-adds a CSP nonce to style-src, which makes 'unsafe-inline'
// ineffective and silently blocks every dynamically-created <style>
// element. The fix: steal the nonce from a known Tauri-injected
// existing <style> (index.html ships one) and propagate it to every
// new <style> we create, so the browser's CSP enforcer accepts the
// rule. In dev mode (no nonce injected) the nonce is empty and we
// fall back to the unprefixed pathway, which CSP still allows because
// dev mode keeps 'unsafe-inline' active.
const __TAURI_CSP_NONCE = (() => {
  if (typeof document === "undefined") return "";
  const probe = document.querySelector("style[nonce], script[nonce]");
  return probe ? (probe.getAttribute("nonce") || probe.nonce || "") : "";
})();

function __injectStyleOnce(id, css) {
  if (typeof document === "undefined") return;
  if (document.getElementById(id)) return;
  const s = document.createElement("style");
  s.id = id;
  if (__TAURI_CSP_NONCE) {
    s.setAttribute("nonce", __TAURI_CSP_NONCE);
    s.nonce = __TAURI_CSP_NONCE;
  }
  s.textContent = css;
  document.head.appendChild(s);
}

// ------------------------------------------------------------------
// Module-scope keyframe injection — fires ONCE at module load, BEFORE
// any React component renders.
//
// Why it has to be here (and NOT inside a component render):
// The boot-modal → main-app transition uses the inline style
// `animation: "btx-app-fade-in 280ms ease-out"` on the main wrapper.
// If the `@keyframes btx-app-fade-in` rule isn't in the document at
// the moment the browser computes that wrapper's style, it falls
// back to "no animation" — the div paints at opacity 1 instantly,
// producing the visible snap-flash the v14 fix was supposed to
// eliminate. v14 injected the keyframes as a child of the main
// wrapper, which lost the race: the parent's style was resolved
// before children mounted, so the first paint flashed and only the
// second paint had the animation. Moving the injection to module
// scope makes the rule available on every render thereafter.
//
// The `__injectStyleOnce` guard (id check) means subsequent calls
// elsewhere in the file are still safe no-ops.
if (typeof document !== "undefined") {
  __injectStyleOnce("__btx_style_app_fade_in", `
    @keyframes btx-app-fade-in {
      from { opacity: 0; }
      to   { opacity: 1; }
    }
  `);
}

