// =============================================================================
// SFX — Web Audio synthesized casino sound layer
// Module-level singleton AudioContext, lazy-init on first user gesture.
// All sounds are synthesized (no sample files). Master mute via setSfxMuted.
// Default-muted (`_sfxMuted = true`) so a fresh launch doesn't blast audio
// on the first interaction; the SoundToggle button in the footer flips it.
// =============================================================================
let _sfxCtx = null;
let _sfxMuted = true;
const _sfxListeners = new Set();

function getSfxCtx() {
  if (typeof window === "undefined") return null;
  if (!_sfxCtx) {
    try {
      const Ctor = window.AudioContext || window.webkitAudioContext;
      if (!Ctor) return null;
      _sfxCtx = new Ctor();
    } catch (e) { return null; }
  }
  if (_sfxCtx.state === "suspended") { try { _sfxCtx.resume(); } catch (e) {} }
  return _sfxCtx;
}
function setSfxMuted(v) { _sfxMuted = !!v; _sfxListeners.forEach((fn) => fn(_sfxMuted)); }
function isSfxMuted() { return _sfxMuted; }
function onSfxMuteChange(fn) { _sfxListeners.add(fn); return () => _sfxListeners.delete(fn); }

// generic UI tick (used for picks, button clicks if wanted)
function sfxClick() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const osc = ctx.createOscillator(), gain = ctx.createGain();
  osc.frequency.setValueAtTime(900, t);
  osc.frequency.exponentialRampToValueAtTime(420, t + 0.04);
  gain.gain.setValueAtTime(0.14, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.06);
  osc.connect(gain); gain.connect(ctx.destination);
  osc.start(t); osc.stop(t + 0.08);
}

// roulette ball tick — sharp, brief, square wave click
function sfxRouletteTick() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const osc = ctx.createOscillator(), gain = ctx.createGain();
  osc.type = "square";
  osc.frequency.setValueAtTime(2400, t);
  osc.frequency.exponentialRampToValueAtTime(900, t + 0.02);
  gain.gain.setValueAtTime(0.05, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.03);
  osc.connect(gain); gain.connect(ctx.destination);
  osc.start(t); osc.stop(t + 0.04);
}

// reel stop clunk — heavy lowpass'd saw thud
function sfxReelStop() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const osc = ctx.createOscillator(), gain = ctx.createGain();
  const filter = ctx.createBiquadFilter();
  osc.type = "sawtooth";
  osc.frequency.setValueAtTime(180, t);
  osc.frequency.exponentialRampToValueAtTime(55, t + 0.16);
  filter.type = "lowpass";
  filter.frequency.setValueAtTime(900, t);
  filter.frequency.exponentialRampToValueAtTime(140, t + 0.18);
  gain.gain.setValueAtTime(0.38, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.2);
  osc.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
  osc.start(t); osc.stop(t + 0.22);
}

// coin ping — bright dual-osc dink
function sfxCoin(delay = 0) {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime + delay;
  const o1 = ctx.createOscillator(), o2 = ctx.createOscillator(), gain = ctx.createGain();
  o1.frequency.setValueAtTime(2200, t);
  o1.frequency.exponentialRampToValueAtTime(1500, t + 0.2);
  o2.frequency.setValueAtTime(3200, t);
  o2.frequency.exponentialRampToValueAtTime(2200, t + 0.2);
  gain.gain.setValueAtTime(0, t);
  gain.gain.linearRampToValueAtTime(0.12, t + 0.005);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.28);
  o1.connect(gain); o2.connect(gain); gain.connect(ctx.destination);
  o1.start(t); o2.start(t); o1.stop(t + 0.3); o2.stop(t + 0.3);
}

// win fanfare — 4 ascending triangle notes (C5→C6 arpeggio)
function sfxWinHorn() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const notes = [523.25, 659.25, 783.99, 1046.50];
  const t0 = ctx.currentTime;
  notes.forEach((freq, i) => {
    const t = t0 + i * 0.11;
    const osc = ctx.createOscillator(), gain = ctx.createGain();
    osc.type = "triangle";
    osc.frequency.setValueAtTime(freq, t);
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.2, t + 0.02);
    gain.gain.linearRampToValueAtTime(0.16, t + 0.16);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.42);
    osc.connect(gain); gain.connect(ctx.destination);
    osc.start(t); osc.stop(t + 0.45);
  });
 // sparkle on top
  for (let i = 0; i < 6; i++) sfxCoin(0.05 + i * 0.08 + Math.random() * 0.04);
}

// miss thud — descending muffled blip
function sfxMiss() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const osc = ctx.createOscillator(), gain = ctx.createGain();
  const filter = ctx.createBiquadFilter();
  osc.type = "sine";
  osc.frequency.setValueAtTime(220, t);
  osc.frequency.exponentialRampToValueAtTime(80, t + 0.32);
  filter.type = "lowpass";
  filter.frequency.value = 420;
  gain.gain.setValueAtTime(0.22, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.32);
  osc.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
  osc.start(t); osc.stop(t + 0.34);
}

// lever pull — pneumatic noise sweep
function sfxLever() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const bufSize = Math.floor(ctx.sampleRate * 0.42);
  const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for (let i = 0; i < bufSize; i++) data[i] = (Math.random() * 2 - 1) * 0.5;
  const noise = ctx.createBufferSource(); noise.buffer = buf;
  const filter = ctx.createBiquadFilter();
  filter.type = "bandpass";
  filter.frequency.setValueAtTime(2200, t);
  filter.frequency.exponentialRampToValueAtTime(220, t + 0.4);
  filter.Q.value = 5;
  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0, t);
  gain.gain.linearRampToValueAtTime(0.32, t + 0.05);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.42);
  noise.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
  noise.start(t); noise.stop(t + 0.42);
}

// card flip — short paper-y high-pass noise burst
function sfxFlip() {
  const ctx = getSfxCtx(); if (!ctx || _sfxMuted) return;
  const t = ctx.currentTime;
  const bufSize = Math.floor(ctx.sampleRate * 0.14);
  const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for (let i = 0; i < bufSize; i++) data[i] = (Math.random() * 2 - 1) * 0.4;
  const noise = ctx.createBufferSource(); noise.buffer = buf;
  const filter = ctx.createBiquadFilter();
  filter.type = "highpass";
  filter.frequency.value = 2200;
  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.28, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);
  noise.connect(filter); filter.connect(gain); gain.connect(ctx.destination);
  noise.start(t); noise.stop(t + 0.16);
}

// schedule N roulette ticks across `ms` total, decelerating (faster at start)
function scheduleRouletteTicks(totalMs, count) {
  const timers = [];
  for (let i = 0; i < count; i++) {
 // ease-out distribution: t = 1 - (1 - p)^2; faster at start, slower at end
    const p = i / count;
    const eased = 1 - Math.pow(1 - p, 2.2);
    const at = eased * totalMs;
    timers.push(setTimeout(sfxRouletteTick, at));
  }
  return () => timers.forEach(clearTimeout);
}

