const HEX = "0123456789abcdef".split("");
// Visual layout of the 16 hex characters around the BRONZE roulette wheel.
// Fixed (not random) so the wheel mimics a real casino layout players can
// learn — the spread mirrors European roulette's "no two adjacent values
// cluster" feel. The actual game outcome is decided by hash[-1] regardless
// of where a hex char visually sits, so this is purely cosmetic ordering.
const HEX_WHEEL_LAYOUT = ["0", "9", "5", "c", "2", "e", "7", "a", "1", "d", "4", "b", "8", "f", "3", "6"];
const ROMAN_GLYPH = { "0": "O", "1": "I", "2": "II", "3": "III", "4": "IV", "5": "V", "6": "VI", "7": "VII", "8": "VIII", "9": "IX", "a": "A", "b": "B", "c": "C", "d": "D", "e": "E", "f": "F" };
function glyphFor(c) { return ROMAN_GLYPH[c.toLowerCase()] || c.toUpperCase(); }
const SLOT_STYLE = {
  "0": "gold", "5": "gold", "a": "gold",
  "1": "diamond", "6": "diamond", "b": "diamond",
  "2": "ruby", "7": "ruby", "c": "ruby",
  "3": "emerald", "8": "emerald", "d": "emerald",
  "4": "sapphire", "9": "sapphire", "e": "sapphire",
  "f": "amethyst",
};
function reelStyleFor(c) { return SLOT_STYLE[c.toLowerCase()] || "gold"; }
const HEXU = HEX.map((h) => h.toUpperCase());

// =============================================================================
// HELPERS
// =============================================================================
// Hash output is canonically lowercase. HEX itself is lowercase so the
// `.toLowerCase()` is a defensive fence — if HEX is ever rewritten with
// uppercase chars (e.g., to match a UI tweak), every downstream slice still
// gets the lowercase form expected by isHit / HEX.indexOf / etc.
const randomHash = () =>
  Array.from({ length: 64 }, () => HEX[Math.floor(Math.random() * 16)]).join("").toLowerCase();

// V2 PROTOCOL — combine two block hashes via per-character XOR. The last K
// hex chars of the result are the settlement tail (matches
// luckyprotocol-indexer/src/protocol.rs::settlement_tail). Mock settle uses this
// to fold hash_N and hash_{N+1} into a single 64-char hex string that the
// existing `.slice(-K)` display code can read unchanged.
const combineHashes = (hashN, hashNplus1) => {
  const a = (hashN || "").toLowerCase();
  const b = (hashNplus1 || "").toLowerCase();
  const len = Math.min(a.length, b.length);
  if (len === 0) return "";
  let out = "";
  for (let i = 0; i < len; i++) {
    const av = parseInt(a[i], 16);
    const bv = parseInt(b[i], 16);
    if (Number.isNaN(av) || Number.isNaN(bv)) {
      out += "0";
    } else {
      out += (av ^ bv).toString(16);
    }
  }
  return out;
};

// derive a single die value from the last hex char of a hash (1..6)
const diceFromHash = (hash) => {
  const c = hash.toLowerCase().slice(-1);
  return (parseInt(c, 16) % 6) + 1;
};

// Game-phase RNG: the room's game animation visually "produces" the player's
// pick using local randomness. This pick is then locked into the mine pool
// and matched against the next block's hash tail when the block settles.
// Per the LUCKYPROTOCOL protocol white-paper, the GAME generates the guess; the
// BLOCK HASH decides win/miss.
const rollPickFor = (tier) => {
  if (tier === "iron") {
    const die = 1 + Math.floor(Math.random() * 6);
    return { pick: die % 2 === 1 ? "odd" : "even", die };
  }
  if (tier === "bronze") {
    const idx = Math.floor(Math.random() * 16);
    return { pick: HEX[idx], idx };
  }
  if (tier === "silver") {
    const i = Math.floor(Math.random() * 16);
    const j = Math.floor(Math.random() * 16);
    return { pick: HEX[i] + HEX[j], indices: [i, j] };
  }
  if (tier === "gold") {
    const a = Math.floor(Math.random() * 16);
    const b = Math.floor(Math.random() * 16);
    const c = Math.floor(Math.random() * 16);
    return { pick: HEX[a] + HEX[b] + HEX[c], indices: [a, b, c] };
  }
  return { pick: null };
};

// 1:1 copy of the LUCKYPROTOCOL protocol's settlement predicate. Mirrors luckyprotocol-indexer/src/protocol.rs::is_hit.
// Iron picks are strictly "odd" | "even" — earlier code accepted aliases
// (big/high/small/low/triple) but those never made it on-chain (the Rust
// protocol has always rejected them in `valid_pick`), so accepting them
// here would make local-mock outcomes diverge from indexer outcomes. Dropped.
const isHit = (tier, pick, hash) => {
  const h = hash.toLowerCase();
  if (tier === "iron") {
    const die = diceFromHash(h);
    if (pick === "odd")  return die % 2 === 1;
    if (pick === "even") return die % 2 === 0;
    return false;
  }
  if (tier === "bronze") return h.slice(-1) === pick;
  if (tier === "silver") return h.slice(-2) === pick;
  return h.slice(-3) === pick;
};

// =============================================================================
// EXPLORER URL HELPERS — every txid / block hash / address surface in the UI
// is a clickable link to mempool.space.
// Mainnet only — LUCKYPROTOCOL dropped testnet/signet support. The `network`
// arg is kept for API symmetry with other helpers but always resolves
// to mempool.space's mainnet host (no subpath).
// =============================================================================
const explorerBaseFor = (_network) => {
  return "https://mempool.space"; // mainnet only
};
const txExplorerUrl    = (network, txid) => `${explorerBaseFor(network)}/tx/${txid}`;
const blockExplorerUrl = (network, hash) => `${explorerBaseFor(network)}/block/${hash}`;
const addrExplorerUrl  = (network, addr) => `${explorerBaseFor(network)}/address/${addr}`;

// Open a URL in the user's DEFAULT BROWSER.
// Tauri's WebView2 (the desktop runtime) does NOT honor `<a target="_blank">`
// or `window.open(url, "_blank")` — both attempt to open a new WebView2
// child window which silently fails. Routes through our custom
// `cmd_open_external` Tauri command, which delegates to the OS shell
// (Windows `cmd /c start`, macOS `open`, Linux `xdg-open`) and pops
// the URL in the user's actual default browser.
// We use a custom command rather than the shell plugin's
// `plugin:shell|open` because the latter requires a `shell:allow-open`
// capability with an URL-validator regex that is easy to misconfigure;
// our wrapper just enforces http(s) on the Rust side and is auto-allowed.
// On failure we copy the URL to the clipboard and dispatch a
// `luckyprotocol:open-external-failed` event that App handles into a toast
// so the user always has a recovery path — silent failure is the worst
// possible outcome here. In the browser-only Vite preview falls back
// to `window.open` so dev preview links still work.
// Direct setToast bridge — App publishes its setToast on
// `window.__luckyprotocolToast` so module-level helpers can show toasts
// without needing to thread setToast through event listeners. The
// previous indirect "dispatchEvent → useEffect handler → setToast"
// chain had three points of failure (event might not bubble, listener
// might be unmounted, dispatch might throw) and one of them was
// silently dropping the "ok" toast.
const showToast = (kind, msg) => {
  console.log(`[toast/${kind}] ${msg}`);
  try {
    if (typeof window !== "undefined" && typeof window.__luckyprotocolToast === "function") {
      window.__luckyprotocolToast({ kind, msg });
    }
  } catch (_) {}
};

// Wrap a promise with a hard timeout. Without this, a hung Tauri IPC
// call (which we observed happening with explorer.exe + child.wait())
// would leave the UI showing "opening…" forever with no resolution.
// 4s is generous for an IPC round-trip — if it takes longer than that
// something is really wrong and we want to fall through to the
// clipboard path.
const withTimeout = (promise, ms, label) => Promise.race([
  promise,
  new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms)
  ),
]);

const openExternal = (url) => {
  if (!url) return;
  const host = (() => { try { return new URL(url).host; } catch { return url; } })();

  if (typeof window !== "undefined" && window.__TAURI_INTERNALS__) {
    showToast("warn", `opening ${host} in browser…`);

    const tryPlugin = () => withTimeout(
      invoke("plugin:opener|open_url", { url }),
      4000,
      "plugin:opener|open_url"
    );
    const tryCustom = () => withTimeout(
      invoke("cmd_open_external", { url }),
      4000,
      "cmd_open_external"
    );

    const onOk = () => showToast("ok", `opened ${host}`);
    const onFail = async (err) => {
      const errStr = String(err?.message ?? err);
      console.warn("[openExternal] all strategies failed:", errStr);
      let copied = false;
      try {
        if (navigator?.clipboard?.writeText) {
          await navigator.clipboard.writeText(url);
          copied = true;
        }
      } catch (_) {}
      showToast(
        "err",
        copied
          ? `couldn't open browser — URL copied to clipboard`
          : `couldn't open browser: ${errStr.slice(0, 100)}`
      );
    };

    tryPlugin()
      .then(onOk)
      .catch((pluginErr) => {
        console.warn(
          "[openExternal] plugin:opener failed, trying custom:",
          pluginErr?.message ?? pluginErr
        );
        tryCustom().then(onOk).catch(onFail);
      });
    return;
  }
  try { window.open(url, "_blank", "noopener,noreferrer"); } catch (e) {
    console.warn("[openExternal] window.open failed:", e);
  }
};

const fmt = (n) => Number(n).toLocaleString();
// Compact magnitude formatter — used for token supply display (21M, 1.05B, 2.10T)
const fmtCompact = (n) => {
  const v = Number(n) || 0;
  if (v >= 1e12) return (v / 1e12).toFixed(2) + "T";
  if (v >= 1e9)  return (v / 1e9).toFixed(2)  + "B";
  if (v >= 1e6)  return (v / 1e6).toFixed(2)  + "M";
  if (v >= 1e3)  return (v / 1e3).toFixed(2)  + "K";
  return v.toLocaleString();
};
const fmt2 = (n, dp = 8) => Number(n).toFixed(dp);
const ts = () => {
  const d = new Date();
  return [d.getHours(), d.getMinutes(), d.getSeconds()]
    .map((n) => String(n).padStart(2, "0")).join(":");
};
const utxoKey = (u) => `${u.txid}:${u.vout}`;

// Extract the ticker from a LUCKYPROTOCOL OP_RETURN payload, regardless of opcode.
// Used to tag 546-sat UTXOs created by LUCKYPROTOCOL txs as "token UTXOs" of a
// specific ticker so the wallet's UTXO panel and asset cards can show real
// on-chain counts instead of synthetic JS bookkeeping.
// Payload shapes (post-rename — prefix is "LUCKYPROTOCOL", not "LUCKYPROTOCOL"):
// BET: LUCKYPROTOCOL|<tier>|<pick>|<ticker> ← ticker = parts[3]
// DEPLOY: LUCKYPROTOCOL|DEPLOY|<ticker>|<supply> ← ticker = parts[2]
// XFER: LUCKYPROTOCOL|XFER|<ticker>|<amount>|<addr> ← ticker = parts[2]
// Old "LUCKYPROTOCOL"-prefixed payloads (pre-rename) are deliberately ignored
// — they only exist below the protocol activation height anyway.
function lckminerTickerFromPayload(payload) {
  if (!payload || typeof payload !== "string") return null;
  const parts = payload.split("|");
  if (parts[0] !== "LUCKYPROTOCOL") return null;
  const op = parts[1];
  if (op === "DEPLOY" || op === "SEND") return parts[2] || null;
  if (op === "iron" || op === "bronze" || op === "silver" || op === "gold") {
    return parts[3] || null;
  }
  return null;
}

