const LS_KEYS = {
  wallet:     "luckyprotocol.wallet.v1",       // { mnemonic, address, createdAt }
  pwHash:     "luckyprotocol.pwhash.v1",       // base64 of (sha256-ish) — see hashPw
  endpoints:  "luckyprotocol.endpoints.v1",    // [{kind,url,user?,password?}]
  feeRate:    "luckyprotocol.fee_rate.v1",     // string sat/vB
  alchemyKey: "luckyprotocol.alchemy_key.v1",  // bare key suffix only (URL rebuilt at read)
 // Deployed-token registry — persists user's own DEPLOYs + any tokens
 // discovered via incoming balances. Without this every app restart
 // would wipe the local registry, even though the underlying DEPLOY
 // tx is forever on-chain.
  deployed:   "luckyprotocol.deployed_tokens.v1",
 // Mandatory risk-acknowledgment flag — set to a timestamp on first
 // ack so future launches skip the modal. Storing the ack date (not
 // just a boolean) lets us re-prompt if we ever revise the disclosure
 // wording.
  riskAck:    "luckyprotocol.risk_ack.v1",
 // Per-day spending cap (sats). Optional opt-in safeguard. Format:
 // { daily_sat: <number>, set_at: <unix_ms> }. The bet/send flow
 // sums today's outflow + the pending op and refuses if it would
 // exceed daily_sat. Stored daily roll-up at `luckyprotocol.spend_today.v1`.
  spendLimit: "luckyprotocol.spend_limit.v1",
  spendDay:   "luckyprotocol.spend_today.v1",
};

// Unified local-broadcast log. Every successful tx broadcast (bet, deploy,
// xfer, BTC send, split) appends one entry here. TransactionsScreen merges
// this with Esplora's `/address/{addr}/txs` so the user's just-broadcast
// txs appear instantly — even before mempool.space's address index has
// caught up, AND for txs that only touch internal-keychain change
// addresses (which Esplora's per-address endpoint can't surface).
// Entry shape:
// {
// txid,
// kind: "bet"|"deploy"|"xfer"|"send"|"split",
// payload, // LUCKYPROTOCOL OP_RETURN string (null for pure BTC)
// fee_sats, vsize,
// network,
// broadcast_at, // ms since epoch
// sent_sats, received_sats, // approximate, for the NET column
// }
const LS_LOCAL_TXS_KEY = "luckyprotocol.local_txs.v1";

function recordLocalTx(entry) {
  if (!entry || !entry.txid) return;
  try {
    const raw = window.localStorage.getItem(LS_LOCAL_TXS_KEY);
    const list = raw ? JSON.parse(raw) : [];
 // Dedupe by txid — last write wins (latest payload/fees stick).
    const filtered = list.filter((e) => e.txid !== entry.txid);
    const next = [
      { ...entry, broadcast_at: entry.broadcast_at ?? Date.now() },
      ...filtered,
    ].slice(0, 100);
    window.localStorage.setItem(LS_LOCAL_TXS_KEY, JSON.stringify(next));
  } catch (e) {
    console.warn("[local-tx store]", e);
  }
}

