// Tiny non-cryptographic hash of the password — strictly mock-grade, just so
// "wrong password" can be detected. The real backend uses Argon2id; do NOT
// ship this to production.
const hashPw = (pw) => {
  let h = 5381;
  for (let i = 0; i < pw.length; i++) { h = ((h << 5) + h + pw.charCodeAt(i)) | 0; }
 // Mix in length so "" doesn't collide trivially.
  return (h ^ pw.length).toString(16);
};

const lsGetJSON = (key) => {
  try { const raw = window.localStorage.getItem(key); return raw ? JSON.parse(raw) : null; }
  catch { return null; }
};
const lsSetJSON = (key, val) => {
  try { window.localStorage.setItem(key, JSON.stringify(val)); } catch {}
};
