const NAV = [
  { key: "dashboard",    label: "DASHBOARD",   icon: LayoutDashboard, screen: "dashboard" },
  { key: "mining",       label: "MINE",        icon: Layers,          screen: "iron" },
  { key: "transactions", label: "LEDGER",      icon: FileText,        screen: "transactions" },
  { key: "almanac",      label: "ALMANAC",     icon: ScanSearch,      screen: "almanac" },
  { key: "index",        label: "INDEX",       icon: Database,        screen: "index" },
  { key: "deploy",       label: "DEPLOY",      icon: Rocket,          screen: "deploy" },
  { key: "wallet",       label: "WALLET",      icon: Wallet,          screen: "wallet" },
  { key: "utxo",         label: "UTXO",        icon: Boxes,           screen: "utxo" },
  { key: "transfers",    label: "TRANSFERS",   icon: ArrowLeftRight,  screen: "transfers" },
 // BRIDGE — placeholder slot for the cross-chain bridge feature. Lands
 // on a "COMING SOON" splash for now; the screen renders the casino
 // interior backdrop (same image used by OnboardModal's
 // `.btx-modal-blocker::before` layer) so the empty state still feels
 // like part of the app, not a 404.
  { key: "bridge",       label: "BRIDGE",      icon: Cable,           screen: "bridge" },
  { key: "settings",     label: "SETTINGS",    icon: Settings,        screen: "settings" },
];

function LocalTimeClock() {
  const [t, setT] = useState(() => new Date());
  useEffect(() => {
    const id = setInterval(() => setT(new Date()), 1000);
    return () => clearInterval(id);
  }, []);
  return (
    <div className="hxm-vegas-time">
      <div className="hxm-bebas" style={{ fontSize: 9, color: "var(--hxm-text-mute)", letterSpacing: "0.3em" }}>LOCAL TIME</div>
      <div className="hxm-mono" style={{ fontSize: 18, color: "var(--hxm-amber)", marginTop: 2, fontWeight: 500 }}>
        {[t.getHours(), t.getMinutes(), t.getSeconds()].map((n) => String(n).padStart(2, "0")).join(":")}
      </div>
      <div className="hxm-bebas" style={{ fontSize: 9, color: "var(--hxm-text-mute)", marginTop: 1, letterSpacing: "0.18em" }}>
        {t.toLocaleString("en-US", { month: "short", day: "2-digit", year: "numeric" }).toUpperCase()}
      </div>
    </div>
  );
}

function SidebarLeft({ activeNav, setActiveNav, setScreen, onOpenDonate }) {
  const click = (item) => {
    setActiveNav(item.key);
    if (item.screen) setScreen(item.screen);
  };
  return (
    <aside className="hxm-sidebar-left">
      <div className="hxm-logo">
        <img
          src={BRAND_ICON_SRC}
          alt="LuckyProtocol"
          style={{
            width: "100%",
            // Shrunk from 140 → 120 to claw back ~20px vertical space
            // (image is square; auto height scales with width). Keeps
            // the gold-frame readable but stops the sidebar from
            // pushing DONATE off the bottom on ~900px viewports.
            maxWidth: 120,
            height: "auto",
            display: "block",
            margin: "0 auto",
            // Icon PNG: rounded gold frame with transparent corners.
            // Three iterations to dial in the right clip:
            //   * borderRadius 18%: too small radius, residual edge
            //   * inset 6% round 22%: too aggressive, ate the frame
            //   * borderRadius 22% (no inset): frame intact but a
            //     1-2px cream/white outline persisted — that's the
            //     PNG's anti-aliased edge pixels blending with the
            //     dark sidebar bg, plus the gold-frame's own outer
            //     bright highlight ring at the original resolution.
            //     Both compress down to a ~1px halo at 140px scale.
            //
            // Final answer: 2% inset to crop exactly those 1-2 AA
            // pixels at every edge, paired with a slightly higher
            // rounded radius (24%) to match the gold-frame curvature
            // after the inset shrinks the visible rectangle. This
            // crops the halo without touching the gold frame meat —
            // sweet spot between v3 (6%, ate frame) and v4 (0%, left
            // halo). The asset's interior detail and the four-sided
            // gold frame are fully preserved.
            //
            // We use clip-path instead of overflow:hidden on a
            // wrapper so the gold drop-shadow filter below correctly
            // outlines the CLIPPED silhouette, not the original
            // rectangular bounding box.
            clipPath: "inset(2% round 24%)",
            filter: "drop-shadow(0 4px 14px rgba(212,162,58,0.25))",
          }}
          draggable={false}
        />
        <div className="hxm-bebas" style={{ fontSize: 9, color: "var(--hxm-text-mute)", marginTop: 6 }}>
          v0.1.0 · GENESIS
        </div>
      </div>

      {NAV.map((item) => {
        const Icon = item.icon;
        const active = activeNav === item.key;
        return (
          <button key={item.key} className={`hxm-nav-btn ${active ? "is-active" : ""}`} onClick={() => click(item)}>
            <Icon size={14} />
            {item.label}
          </button>
        );
      })}

      <div className="hxm-vegas">
        <VegasBadge />
        {/* Clock is its own leaf component with its own 1s setInterval.
            Previously the App root carried a `now: Date` state ticking
            every second, which re-rendered ALL 78 components in the
            tree (including Three.js scenes, paginated tables) every
            tick. Moving the tick into a leaf scoped the re-render to
            this small clock node. Audit F4. */}
        <LocalTimeClock />

        {/* Tiny DONATE pill — sits below the local-time clock so it
            occupies the corner-most spot on the sidebar without
            looking like a nav item. Pulsing pink heart draws the eye
            to it; everything else is muted so it doesn't fight with
            the nav buttons above. Click opens DonateModal. */}
        <button
          type="button"
          className="hxm-donate-pill"
          onClick={onOpenDonate}
          title="Support LUCKYPROTOCOL protocol development"
        >
          <Heart size={11} />
          <span>DONATE</span>
        </button>
      </div>
    </aside>
  );
}

// =============================================================================
// DONATE MODAL
// =============================================================================
// Displayed when the user clicks the DONATE button at the bottom of the
// sidebar. Shows the protocol's BTC funding address, a pitch describing
// what the funds get spent on, an explicit no-reciprocal-reward disclaimer,
// and a click-to-copy + QR code for easy on-phone scanning.
// The address is hard-coded — these donations fund protocol-side work
// (server infra, plugin wallet, web tooling, community ops) that the
// user-installed desktop app can't ship by itself.
// =============================================================================
const DONATE_ADDRESS = "bc1pyefhtnuz2gw04fsynlsseeh847cqy20dw7yt6fnavm9fgnewcr7q88gqf3";

function DonateModal({ onClose, setToast }) {
  const [qrSrc, setQrSrc] = useState("");
  const [copied, setCopied] = useState(false);

 // Render the QR once on mount. Black-on-near-black with a slight
 // amber tint so it sits naturally inside the gold-bordered modal.
  useEffect(() => {
    let cancelled = false;
    QRCode.toDataURL(`bitcoin:${DONATE_ADDRESS}`, {
      errorCorrectionLevel: "M",
      margin: 1,
      width: 220,
      color: { dark: "#0a0506", light: "#f5e9c4" },
    })
      .then((url) => { if (!cancelled) setQrSrc(url); })
      .catch((e) => { console.warn("[donate qr]", e); });
    return () => { cancelled = true; };
  }, []);

  const copyAddress = async () => {
    try {
      await navigator.clipboard.writeText(DONATE_ADDRESS);
      setCopied(true);
      setTimeout(() => setCopied(false), 1500);
    } catch {
      if (setToast) setToast({ kind: "warn", msg: "clipboard write blocked — copy the address manually" });
    }
  };

 // ESC closes — same UX as other modals
  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  return (
    <div
      className="btx-modal-blocker"
      onClick={onClose}
 // Override the casino-interior backdrop: Donate is opened from
 // the main UI (not the boot flow), and the busy photo + dark
 // overlay clashes with the already-busy main app behind it.
 // Keep the modal card itself but flatten the backdrop to a
 // simple dark wash so attention reads cleanly to the donate
 // content.
      style={{
        background:
          "radial-gradient(ellipse at center, rgba(20,8,8,0.92), rgba(0,0,0,0.98))",
      }}
    >
      <div
        className="btx-modal-card"
 // Donate is the ONE modal that opts back into a wider footprint.
 // The rest of the popup family (Transfer/Deploy success, Wipe,
 // Onboard, Risk, Alchemy) was unified to 400px in the
 // "modal too big" pass, but Donate carries genuinely more
 // content — pitch paragraph, USE OF FUNDS list, disclaimer
 // box, the 36-char BTC address, AND a 220-280px QR. Cramming
 // that into 400 single-column pushes the modal past the
 // viewport vertically and makes the QR fight the disclaimer
 // for space. 760px + 2-column layout (text on left, address +
 // QR on right) gets everything on a single 1080p screen
 // without scroll.
        style={{
 // 800 to match the onboarding-modal card. Earlier 620 was
 // tight on the right column — the 42-char bech32 address
 // (`bc1q…`) at the default monospace size barely fit the
 // input box, with the last 6 chars getting visually cramped
 // against the border. 800 widens the right column by ~90px
 // which is more than enough to render the full address
 // comfortably + leaves room for the QR.
          width: "min(800px, 96vw)",
          maxHeight: "92vh",
          padding: "20px 26px 22px",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="btx-modal-corner btx-modal-corner-tl" />
        <div className="btx-modal-corner btx-modal-corner-tr" />
        <div className="btx-modal-corner btx-modal-corner-bl" />
        <div className="btx-modal-corner btx-modal-corner-br" />

        {/* Two-column layout — left: title + pitch + use-of-funds +
            disclaimer; right: address + QR + verify note. Lets the
            whole modal fit on a typical 1080p viewport without
            scrolling, where the previous single-column version had
            to scroll to reveal the QR. */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          marginBottom: 8,
        }}>
          <div className="hxm-bebas" style={{ fontSize: 10.5, color: "var(--hxm-text-mute)", letterSpacing: "0.32em" }}>
            LUCKYPROTOCOL · PROTOCOL FUND
          </div>
          <button
            onClick={onClose}
            style={{
              background: "transparent", border: "none", cursor: "pointer",
              color: "var(--hxm-text-dim)", padding: 2,
              display: "inline-flex", alignItems: "center",
            }}
            aria-label="close donate modal"
          >
            <X size={16} />
          </button>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 2 }}>
          <Heart size={18} color="var(--hxm-gold-bright)" style={{ filter: "drop-shadow(0 0 6px rgba(212,162,58,0.4))" }} />
          <h2 className="hxm-cinzel metal-gold" style={{ margin: 0, fontSize: 19, fontWeight: 900, letterSpacing: "0.06em" }}>
            SUPPORT LUCKYPROTOCOL
          </h2>
        </div>
        <div className="btx-modal-divider" style={{ margin: "10px 0 12px" }} />

        <div style={{ display: "grid", gridTemplateColumns: "1fr 240px", gap: 16 }}>
          {/* === LEFT COLUMN === */}
          <div>
            <p style={{ fontSize: 12, lineHeight: 1.6, color: "var(--hxm-text)", margin: 0 }}>
              LUCKYPROTOCOL is an open Bitcoin protocol — no token sale, no VC round,
              no premine. Donations fund the work that the desktop app alone
              can't ship: backend infra, ecosystem tooling, and the people
              running it.
            </p>

            <div className="hxm-bebas" style={{
              fontSize: 9.5, color: "var(--hxm-gold-bright)", letterSpacing: "0.22em",
              marginTop: 12, marginBottom: 4,
            }}>
              USE OF FUNDS
            </div>
            <ul style={{
              margin: 0, paddingLeft: 16,
              fontSize: 11, color: "var(--hxm-text-dim)", lineHeight: 1.55,
            }}>
              <li><b style={{ color: "var(--hxm-text)" }}>Protocol &amp; client maintenance</b> — bug fixes, security audits, feature upgrades, new releases</li>
              <li><b style={{ color: "var(--hxm-text)" }}>Enterprise indexer servers</b> — uptime SLA, redundant Esplora, public API</li>
              <li><b style={{ color: "var(--hxm-text)" }}>Browser-extension wallet</b> — bets / transfers / deploys without the desktop app</li>
              <li><b style={{ color: "var(--hxm-text)" }}>Web app &amp; explorer</b> — public block / token / address browser</li>
              <li><b style={{ color: "var(--hxm-text)" }}>Community ops</b> — moderators, support, documentation</li>
              <li><b style={{ color: "var(--hxm-text)" }}>Promotion</b> — outreach, partnerships, social presence</li>
            </ul>

            <div className="btx-warn-box" style={{
              marginTop: 12, padding: "8px 10px",
              borderColor: "var(--hxm-amber)",
            }}>
              <div className="hxm-bebas" style={{ fontSize: 10, letterSpacing: "0.22em", marginBottom: 3, color: "var(--hxm-amber)" }}>
                NO RECIPROCAL REWARD
              </div>
              <div style={{ fontSize: 10.5, lineHeight: 1.55 }}>
                Donations are <b>voluntary</b> and <b>non-refundable</b>. They do <b>not</b>{" "}
                entitle the donor to tokens, equity, profit share, governance
                rights, or any other reciprocal benefit — financial or otherwise.
              </div>
            </div>
          </div>

          {/* === RIGHT COLUMN: address + QR === */}
          <div>
            <div className="hxm-bebas" style={{
              fontSize: 9.5, color: "var(--hxm-gold-bright)", letterSpacing: "0.22em",
              marginBottom: 4,
            }}>
              BTC MAINNET ADDRESS
            </div>
            <div style={{
              border: "1px solid var(--hxm-line-2)",
              background: "rgba(0,0,0,0.55)",
              padding: "8px 10px",
              borderRadius: 4,
              marginBottom: 8,
            }}>
              <code className="hxm-mono" style={{
                display: "block",
                color: "var(--hxm-gold-bright)", fontSize: 11,
                lineHeight: 1.5, marginBottom: 6,
 // P2TR addresses are 62 chars — too long for one line
 // in the donate modal's right column. wordBreak +
 // overflowWrap lets the address wrap mid-string so the
 // full thing is visible (typically 2 lines at this
 // width). Removed the previous `whiteSpace: nowrap`.
                wordBreak: "break-all",
                overflowWrap: "anywhere",
                letterSpacing: "0.01em",
                textAlign: "left",
              }}>
                {DONATE_ADDRESS}
              </code>
              <button
                type="button"
                onClick={copyAddress}
                className="btx-btn-ghost"
                style={{
                  fontSize: 10.5, padding: "4px 10px", width: "100%",
                  display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 5,
                }}
                title="copy address to clipboard"
              >
                {copied ? <Check size={11} /> : <Copy size={11} />}
                {copied ? "COPIED" : "COPY ADDRESS"}
              </button>
            </div>

            {qrSrc && (
              <div style={{
                display: "flex", justifyContent: "center",
                padding: 8,
                background: "linear-gradient(180deg, rgba(245,233,196,0.04), rgba(245,233,196,0))",
                border: "1px solid var(--hxm-line)",
                borderRadius: 6,
              }}>
                <img src={qrSrc} alt="donation address QR code" width={200} height={200} style={{ display: "block" }} />
              </div>
            )}

            <p className="hxm-mono" style={{
              marginTop: 8, marginBottom: 0, fontSize: 9.5,
              color: "var(--hxm-text-mute)", lineHeight: 1.5, letterSpacing: "0.03em",
              textAlign: "center",
            }}>
              verify the address before sending — transactions are irreversible
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

function VegasBadge() {
  return (
    <div style={{ position: "relative", paddingTop: 0 }}>
      {/* Gold star above the diamond plate. The SVG's own viewBox has
          ~2px of empty above the star's top point, so visually the
          star sits very close to whatever's directly above (NAV's
          last button). Added marginTop to push the star down a touch
          so SETTINGS button → star has a bit of breathing room
          instead of the star bumping right against the button. */}
      <svg viewBox="0 0 140 30" width="130" height="28" style={{ display: "block", margin: "8px auto 0" }}>
        <polygon points="70,2 72,8 78,8 73,12 75,18 70,14 65,18 67,12 62,8 68,8" fill="#d4af37" />
      </svg>
      <div style={{
        position: "relative",
        width: 130, height: 70, margin: "0 auto",
        clipPath: "polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)",
        background: "linear-gradient(180deg, #260808 0%, #100404 100%)",
        border: "1px solid var(--hxm-gold)",
      }}>
        {/* dot bulbs around the diamond outline */}
        <svg viewBox="0 0 130 70" width="130" height="70" style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
          {Array.from({ length: 14 }).map((_, i) => {
            const t = i / 13;
 // top-left edge: from (65, 0) to (0, 35)
            const x = 65 - t * 65; const y = t * 35;
            return <circle key={`tl${i}`} cx={x} cy={y} r="1.6" fill="#ffae00" />;
          })}
          {Array.from({ length: 14 }).map((_, i) => {
            const t = i / 13;
 // top-right edge: from (65, 0) to (130, 35)
            const x = 65 + t * 65; const y = t * 35;
            return <circle key={`tr${i}`} cx={x} cy={y} r="1.6" fill="#ffae00" />;
          })}
          {Array.from({ length: 14 }).map((_, i) => {
            const t = i / 13;
 // bottom-left edge: from (0, 35) to (65, 70)
            const x = t * 65; const y = 35 + t * 35;
            return <circle key={`bl${i}`} cx={x} cy={y} r="1.6" fill="#ffae00" />;
          })}
          {Array.from({ length: 14 }).map((_, i) => {
            const t = i / 13;
 // bottom-right edge: from (130, 35) to (65, 70)
            const x = 130 - t * 65; const y = 35 + t * 35;
            return <circle key={`br${i}`} cx={x} cy={y} r="1.6" fill="#ffae00" />;
          })}
        </svg>
        <div style={{
          position: "absolute", inset: 0, display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center", textAlign: "center",
        }}>
          <div className="hxm-cinzel" style={{ fontSize: 13, color: "var(--hxm-gold-bright)", fontWeight: 900, letterSpacing: "0.06em", lineHeight: 1 }}>
            LUCKY
          </div>
          <div className="hxm-bebas" style={{
            // PROTOCOL is 8 chars vs MINER's 5 — shrink fontSize and
            // letter-spacing slightly so the word still fits within
            // the 130px diamond width at the same baseline.
            fontSize: 8, color: "var(--hxm-amber)", letterSpacing: "0.22em", marginTop: 2,
          }}>
            PROTOCOL
          </div>
        </div>
      </div>
    </div>
  );
}

// =============================================================================
// TOP STATS BAR (6 stats + status)
// =============================================================================
function TopStatsBar({ state, chainState, network, onChainBets }) {
  const sync = useSyncStatus();
  const w = state.wallet;
  const btc = (w.btc_sats / 1e8).toFixed(8);
 // PENDING bet count = on-chain bets that have been broadcast but
 // haven't settled yet (no outcome populated). `onChainBets` is the
 // shared LS-backed bets log (`luckyprotocol.bets.v1`), refreshed every
 // 5s by the App-level poller.
 // Previously the filter also excluded `b.expired`, but nothing in
 // the codebase ever sets that field — protocol-invalid bets get
 // `outcome.win = false` from the indexer, settled bets get a real
 // outcome. The `!b.expired` clause was a no-op. Removed.
  const pendingBetCount = Array.isArray(onChainBets)
    ? onChainBets.filter((b) => b && !b.outcome).length
    : 0;
 // Real chain tip from the most recent cmd_sync_address result. Falls
 // back to "—" when no sync has happened yet (very first boot before the
 // auto-sync useEffect lands).
  const tip = chainState?.tip_height ?? null;
  const synced = !!chainState;
  const netLabel = (network || chainState?.network || "bitcoin").toUpperCase();

 // Live next-unconfirmed-block fee profile — polled from mempool.space
 // every 60s. We display block[0].feeRange[0] (the lowest sat/vB rate
 // currently sitting in the next block) to 2 decimals so the user can
 // sanity-check their FEE stepper against the actual mining floor —
 // not the integer-rounded recommended bucket.:
  const [nextBlockFee, setNextBlockFee] = useState(null);
 // Gate the mempool.space fee poll on initialSyncComplete. While the
 // PREPARING THE INDEXER overlay is up the app should be 100% Alchemy
 // (no mempool.space background traffic), so we skip the fee fetch
 // entirely until the indexer catches up to chain tip. Once sync
 // completes the dep flips true and useEffect re-mounts, kicking off
 // the first fee tick + the 60s poll.
  const syncDone = sync.initialSyncComplete;
  useEffect(() => {
    if (!syncDone) return undefined;
    let cancelled = false;
    const tick = async () => {
      try {
        const f = await chainFetchNextBlockFee(network || "bitcoin");
        if (!cancelled && f) setNextBlockFee(f);
      } catch { /* keep last value on transient error */ }
    };
    tick();
    const id = setInterval(tick, 15_000);
    return () => { cancelled = true; clearInterval(id); };
  }, [network, syncDone]);

  const minRate = nextBlockFee?.minFee;

  return (
    <div className="hxm-topbar">
      <StatTile
        icon={<Bitcoin size={20} color="#f7a51b" />}
        label="WALLET BTC"
        value={btc}
        sub={`${w.btc_sats.toLocaleString()} sat · ${netLabel}`}
      />
      <StatTile
        icon={<BlockIcon />}
        label="CURRENT BLOCK"
        value={tip != null ? `#${fmt(tip)}` : "—"}
        sub={synced
          ? `synced ${new Date(chainState.fetched_at * 1000).toLocaleTimeString()}`
          : "no chain sync yet"}
        mono
      />
      <StatTile
        icon={<BlockIcon />}
        label="INDEXER SCAN"
        value={sync.scanHeight > 0 ? `#${fmt(sync.scanHeight)}` : "—"}
        sub={(() => {
          if (sync.scanHeight === 0) return "indexer probing…";
 // Lag is computed against the FRONTEND'S chain tip (`tip` from
 // chainState above), NOT the indexer's self-reported tip
 // (`sync.chainTip`). The two are async-independent polls:
 // mempool.space can report a new block seconds before the
 // indexer's own poll fires. Using indexer's tip would have the
 // sublabel say "caught up to tip" while CURRENT BLOCK (one tile
 // left) already shows a higher number — a confusing 1-block
 // false-positive every ~10 minutes (one per block arrival).
 // Using the frontend's tip makes both tiles agree on what "tip"
 // means and gracefully shows "1 block behind" until the indexer
 // catches up on its next poll (≤5s in fast-poll mode).
          const referenceTip = Math.max(tip ?? 0, sync.chainTip ?? 0);
          const lag = Math.max(0, referenceTip - sync.scanHeight);
          if (referenceTip > 0 && lag === 0) return "caught up to tip";
          return `${lag.toLocaleString()} block${lag === 1 ? "" : "s"} behind`;
        })()}
        mono
      />
      <StatTile
        icon={<Zap size={20} color="#f5dc89" />}
        label="MIN FEE RATE"
        value={minRate != null ? `${Number(minRate).toFixed(2)} sat/vB` : "—"}
        sub={nextBlockFee
          ? `floor of next block · ${nextBlockFee.nTx?.toLocaleString?.() ?? "—"} tx queued`
          : "fetching mempool…"}
        mono
      />
      <StatTile
        icon={<RoundIcon />}
        label="PENDING BETS"
        value={String(pendingBetCount)}
        sub={pendingBetCount === 0 ? "no bets in flight" : "awaiting block reveal"}
      />
      {(() => {
 // Three-tier STATUS ball: derived from the indexer's self-
 // reported stall flag (set server-side via /, see server.rs::health
 // and indexer::STALL_THRESHOLD_SECS = 120s). The three tiers map to
 // the three failure modes a user can actually do something about:
 //   green   ONLINE   — indexer is at tip; UI fully unlocked
 //   amber   SYNCING  — indexer behind tip but making progress
 //                       (boot catchup, post-block lag, post-reorg
 //                       rebuild). Transient; usually clears in
 //                       seconds to a minute.
 //   red     STALLED  — indexer behind tip AND no progress for 2+
 //                       minutes. User should open SETTINGS →
 //                       INDEXER DIAGNOSTICS to see why (network
 //                       failures, rate limits, etc.).
 // The "PENDING" tier (yellow, pre-first-poll) is collapsed into
 // SYNCING — the only practical difference was the sub-label, and
 // amber semantics carry it ("not yet at tip"). Frontend computes
 // its OWN stall judgment too (in case the sidecar is so wedged it
 // can't even update its own progress field — then `lastUpdatedAt`
 // not advancing on the FRONTEND side is what we fall back on).
        const stalledByServer = Boolean(sync.stalled);
        const everResponded = (sync.scanHeight ?? 0) > 0;
        const stalledByPollAge = everResponded
          && Math.max(0, (tip ?? 0) - (sync.scanHeight ?? 0)) > 0
 // 180s on frontend side; loose vs server's 120s to avoid
 // ping-ponging amber→red on a single missed poll cycle.
          && (Date.now() - (sync.lastUpdatedAt || Date.now())) > 180_000;
        const isStalled = stalledByServer || stalledByPollAge;
        const lag = Math.max(0, (tip ?? 0) - (sync.scanHeight ?? 0));

        let color;
        let label;
        let sub;
        if (isStalled) {
          color = "var(--hxm-red, #d24343)";
          label = "STALLED";
          sub = lag > 0
            ? `${lag} block${lag === 1 ? "" : "s"} behind · check diagnostics`
            : "no progress · check diagnostics";
        } else if (synced) {
          color = "var(--hxm-green)";
          label = "ONLINE";
          sub = `${netLabel} · esplora`;
        } else {
          color = "var(--hxm-amber)";
          label = "SYNCING";
          sub = lag > 0
            ? `${lag} block${lag === 1 ? "" : "s"} behind · catching up`
            : "syncing chain...";
        }
        return (
          <StatTile
            icon={<div style={{
              width: 14, height: 14, borderRadius: "50%",
              background: color,
              boxShadow: `0 0 8px ${color}`,
            }} />}
            label="STATUS"
            value={<span style={{ color }}>{label}</span>}
            sub={sub}
          />
        );
      })()}
    </div>
  );
}

// Top-right app-icon — ornate gold double-frame with hex coin emblem, casino-luxury feel.
// Top-right app-icon — uses the project's brand mark (cropped from BRAND_BANNER).
function StatTile({ icon, label, value, sub }) {
  return (
    <div className="hxm-stat">
      <div className="hxm-stat-icon">{icon}</div>
      <div className="hxm-stat-info">
        <span className="hxm-stat-label">{label}</span>
        <span className="hxm-stat-val">{value}</span>
        {sub && <span className="hxm-stat-sub">{sub}</span>}
      </div>
    </div>
  );
}

function HexIcon() {
  return (
    <svg viewBox="0 0 24 24" width="20" height="20">
      <polygon points="12,2 22,7 22,17 12,22 2,17 2,7" fill="none" stroke="#d4a23a" strokeWidth="1.5"/>
      <text x="12" y="16" fontFamily="Cinzel" fontWeight="900" fontSize="11" fill="#d4a23a" textAnchor="middle">H</text>
    </svg>
  );
}
function BlockIcon() {
  return (
    <svg viewBox="0 0 24 24" width="20" height="20">
      <rect x="3" y="3" width="18" height="18" rx="2" fill="none" stroke="#d4a23a" strokeWidth="1.5"/>
      <path d="M3 8 L21 8 M3 16 L21 16 M8 3 L8 21 M16 3 L16 21" stroke="#d4a23a" strokeWidth="0.75" opacity="0.5"/>
    </svg>
  );
}
function RoundIcon() {
  return (
    <svg viewBox="0 0 24 24" width="20" height="20">
      <circle cx="12" cy="12" r="9" fill="none" stroke="#d4a23a" strokeWidth="1.5"/>
      <circle cx="12" cy="12" r="5" fill="#d4a23a"/>
      <circle cx="12" cy="12" r="2" fill="#1a0a00"/>
    </svg>
  );
}

// =============================================================================
// RIGHT SIDEBAR (Active Token Selector + Wallet Summary + AI Copilot)
// =============================================================================
function SidebarRight({ state, setState, screen, selectToken, goIndex, aiMode, setAiMode, onChainBets }) {
 // Right-rail composition:
 // [ALL screens] ACTIVE TOKEN selector
 // [game rooms] MY BETS history (per-tier, mempool-linked) — sandwiched
 // between selector and wallet/AI so users see their
 // in-progress bets prominently above the global stats
 // [ALL screens] WALLET / UTXO SUMMARY
 // [ALL screens] AI COPILOT
 // Per the user's iteration: bring Wallet + AI panels back, but keep My
 // Bets in the rooms tucked between the selector and Wallet so the bet
 // story stays at eye-level.
  const tier = TIERS[screen];
  return (
    <aside className="hxm-sidebar-right hxm-scroll">
      <TokenSelectorPanel state={state} selectToken={selectToken} goIndex={goIndex} />
      {tier && <BetHistoryPanel state={state} tier={tier} variant="sidebar" onChainBets={onChainBets} />}
      <AICopilotPanel state={state} screen={screen} aiMode={aiMode} setAiMode={setAiMode} />
      <WalletSummaryPanel state={state} />
    </aside>
  );
}

// Compact mint-progress bar (used by selector panel and index rows).
function MintBar({ pct, height = 6 }) {
  const p = Math.max(0, Math.min(100, pct));
  const full = p >= 99.99;
  return (
    <div style={{
      height, width: "100%", borderRadius: 3,
      background: "rgba(0,0,0,0.55)", border: "1px solid var(--hxm-line)",
      overflow: "hidden", position: "relative",
    }}>
      <div style={{
        height: "100%", width: `${p}%`,
        background: full
          ? "linear-gradient(90deg, #6a8a3a, #9bc356)"
          : "linear-gradient(90deg, #8a5418, #d4a23a, #f5dc89)",
        boxShadow: full ? "0 0 6px rgba(155,195,86,0.4)" : "0 0 6px rgba(212,162,58,0.5)",
        transition: "width 0.3s ease",
      }} />
    </div>
  );
}

// Small reusable sort-chip group. options=[{key,label}], value=current key, dir='asc'|'desc'.
// Click an inactive chip → activate (default dir 'desc'). Click active chip → flip dir.
function SortChips({ options, value, dir, onChange }) {
  return (
    <div style={{
      display: "flex", gap: 4,
      padding: 3,
      background: "rgba(0,0,0,0.45)",
      border: "1px solid var(--hxm-line)",
      borderRadius: 5,
    }}>
      {options.map((opt) => {
        const active = opt.key === value;
        return (
          <button
            key={opt.key}
            onClick={() => {
              if (active) onChange(opt.key, dir === "asc" ? "desc" : "asc");
              else onChange(opt.key, "desc");
            }}
            className="hxm-bebas"
            style={{
              flex: 1,
              padding: "4px 6px",
              fontSize: 9,
              letterSpacing: "0.16em",
              background: active ? "rgba(212,162,58,0.15)" : "transparent",
              border: active ? "1px solid rgba(212,162,58,0.5)" : "1px solid transparent",
              borderRadius: 3,
              color: active ? "var(--hxm-gold-bright)" : "var(--hxm-text-dim)",
              cursor: "pointer",
              fontFamily: "inherit",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 3,
            }}
          >
            {opt.label}
            {active && (dir === "asc" ? <ChevronUp size={9} /> : <ChevronDown size={9} />)}
          </button>
        );
      })}
    </div>
  );
}

function TokenSelectorPanel({ state, selectToken, goIndex }) {
  const [pickerOpen, setPickerOpen] = useState(false);

  const active = state.deployedTokens.find((t) => t.ticker === state.wallet.tokenTicker)
    || { ticker: state.wallet.tokenTicker || "—", name: state.wallet.tokenTicker ? "—" : "(no token yet)", supply: 0, minted: 0, holders: 0 };
  const mintPct = active.supply > 0 ? (active.minted / active.supply) * 100 : 0;
 // Tokens are integer counts (raw smallest-units == whole tokens).
  const balance = Number(state.wallet.tokenBalance || 0).toLocaleString();

  const handlePick = (ticker) => {
    selectToken(ticker);
    setPickerOpen(false);
  };

  return (
    <div className="hxm-panel">
      <div className="hxm-panel-head" style={{ padding: "8px 12px" }}>
        <span className="hxm-panel-hex" style={{ width: 24, height: 26 }}>
          <Coins size={11} color="var(--hxm-gold-bright)" />
        </span>
        <span style={{ fontSize: 11.5 }}>MINE TARGET</span>
      </div>
      <div className="hxm-panel-body" style={{ padding: "10px 12px" }}>
        {/* Mine-target token display — compacted per user request: smaller
            paddings, single-line balance, half-height mint bar. Renamed
            from "ACTIVE TOKEN" when the wallet-side "active" concept was
            retired: this panel is now framed as "which ticker the MINE
            button will broadcast on right now", which the inner caption
            doesn't need to repeat since the panel header already says
            "MINE TARGET". */}
        <div style={{
          padding: "8px 10px",
          background: "rgba(212,162,58,0.06)",
          border: "1px solid rgba(212,162,58,0.35)",
          borderRadius: 5,
        }}>
          <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
            <div className="hxm-cinzel" style={{ fontSize: 15, color: "var(--hxm-gold-bright)", fontWeight: 700, letterSpacing: "0.08em" }}>
              {active.ticker}
            </div>
          </div>
          {/* Sub-line that used to render `active.name` was dropped — for
              deploys the name is just `${TICKER} Protocol`, which is
              visually noise next to the ticker lockup right above. */}
          <div style={{ marginTop: 6, display: "flex", alignItems: "baseline", justifyContent: "space-between", gap: 6 }}>
            <span className="hxm-bebas" style={{ fontSize: 8.5, color: "var(--hxm-text-dim)", letterSpacing: "0.18em" }}>BAL</span>
            <span className="hxm-mono" style={{ fontSize: 12, color: "var(--hxm-text)", fontWeight: 500 }}>
              {balance} <span style={{ fontSize: 9, color: "var(--hxm-text-dim)" }}>{active.ticker}</span>
            </span>
          </div>
          <div style={{ marginTop: 5 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
              <span className="hxm-bebas" style={{ fontSize: 8.5, color: "var(--hxm-text-dim)", letterSpacing: "0.18em" }}>MINT</span>
              <span className="hxm-mono" style={{
                fontSize: 9,
                color: mintPct >= 99.99 ? "var(--hxm-red)" : "var(--hxm-gold-bright)",
                fontWeight: mintPct >= 99.99 ? 700 : 500,
              }}>
                {mintPct.toFixed(1)}%
              </span>
            </div>
            <div style={{ marginTop: 3 }}>
              <MintBar pct={mintPct} height={4} />
            </div>
            {/* MINTED OUT banner — when supply is fully minted, surface
                a red warning so the user knows MINE clicks on this
                ticker will be refused. submitMine + submitDirect both
                enforce the same gate (no fees burned on dead tokens). */}
            {mintPct >= 99.99 && (
              <div className="hxm-bebas" style={{
                marginTop: 6, padding: "4px 6px",
                background: "rgba(80,16,16,0.55)",
                border: "1px solid var(--hxm-red-dim)",
                borderRadius: 3,
                color: "var(--hxm-red)",
                fontSize: 9, letterSpacing: "0.22em",
                textAlign: "center",
              }}>
                ⛔ MINTED OUT · MINE DISABLED
              </div>
            )}
          </div>
        </div>

        {/* Action buttons — same compact treatment */}
        <button
          className="hxm-btn-cta"
          onClick={() => setPickerOpen(true)}
          style={{
            marginTop: 8, width: "100%", fontSize: 10.5,
            padding: "8px 12px",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
          }}
        >
          <RefreshCw size={10} />
          CHANGE TOKEN
        </button>
        <button
          onClick={goIndex}
          style={{
            marginTop: 5, width: "100%",
            padding: "5px 10px",
            background: "transparent",
            border: "1px solid var(--hxm-line)",
            borderRadius: 4,
            color: "var(--hxm-text-dim)",
            fontSize: 9.5,
            letterSpacing: "0.16em",
            cursor: "pointer",
            fontFamily: "inherit",
          }}
          className="hxm-bebas"
        >
          VIEW FULL INDEX →
        </button>
      </div>

      {pickerOpen && (
        <TokenPickerModal
          state={state}
          onPick={handlePick}
          onClose={() => setPickerOpen(false)}
        />
      )}
    </div>
  );
}

// =============================================================================
// TOKEN PICKER MODAL — popup to switch active token
// Search + sort by deploy time / supply / mint, click row to select.
// =============================================================================
function TokenPickerModal({ state, onPick, onClose }) {
  const [query, setQuery] = useState("");
  const [sortKey, setSortKey] = useState("deployedBlock");
  const [sortDir, setSortDir] = useState("desc");
 // Page index (0-based). Resets when the user types in the search
 // box (so they always land on page 0 of the filtered results).
  const [page, setPage] = useState(0);
  const PAGE_SIZE = 10;

 // Close on Escape
  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

 // Same protocol-validity filter the INDEX screen uses — without it,
 // ghost tokens (e.g. CASINO from before LCKPROTOCOL_START_HEIGHT was
 // raised to 949,375) keep appearing in the picker even though they
 // were cleaned out of WALLET / INDEX / LEDGER. The four conditions:
 // - status pending → not yet confirmed, can't be selected as active
 // - status rejected → confirmed below activation height; protocol-invalid
 // - deployedBlock missing → locally-discovered placeholder w/ no DEPLOY tx
 // - deployedBlock < LCKPROTOCOL_START_HEIGHT → pre-activation, never recognized
 // Drop all four classes so the picker mirrors the canonical INDEX view.
 //
 // ALSO drop tokens whose supply is fully minted — they're cosmetic
 // entries in the registry, can't be mined further. Search bypasses
 // this filter so an advanced user can still inspect them by name.
  const validTokens = useMemo(() => state.deployedTokens.filter((t) => {
    if (t.status === "pending" || t.status === "rejected") return false;
    if (t.deployedBlock == null) return false;
    if (t.deployedBlock < LCKPROTOCOL_START_HEIGHT) return false;
    return true;
  }), [state.deployedTokens]);
  const tokens = useMemo(() => {
    const q = query.trim().toLowerCase();
    let list = validTokens.slice();
    if (q) {
      list = list.filter((t) => t.ticker.toLowerCase().includes(q) || t.name.toLowerCase().includes(q));
    } else {
 // Default view: only NOT-fully-minted tokens. The picker exists
 // for the user to choose a target to mine; a 100%-minted ticker
 // is a dead end (no reward issuance possible). Search lifts the
 // filter so they can still look up a fully-minted entry by name.
      list = list.filter((t) => t.supply > 0 && t.minted < t.supply);
    }
    const dir = sortDir === "asc" ? 1 : -1;
    list.sort((a, b) => {
      let av, bv;
      if (sortKey === "mint") { av = a.minted / a.supply; bv = b.minted / b.supply; }
      else { av = a[sortKey]; bv = b[sortKey]; }
      return (av - bv) * dir;
    });
    return list;
  }, [validTokens, query, sortKey, sortDir]);

 // Reset to page 0 whenever the result set changes (search query,
 // sort key, sort dir). Without this the user could be stranded
 // on page 5 after a search that returns 3 results.
  useEffect(() => { setPage(0); }, [query, sortKey, sortDir]);

  const totalPages = Math.max(1, Math.ceil(tokens.length / PAGE_SIZE));
  const safePage = Math.min(page, totalPages - 1);
  const pageStart = safePage * PAGE_SIZE;
  const pageItems = tokens.slice(pageStart, pageStart + PAGE_SIZE);

  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed", inset: 0, zIndex: 1000,
        background: "rgba(0,0,0,0.72)",
        backdropFilter: "blur(3px)",
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: 24,
      }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        className="hxm-bordered"
        style={{
          width: "100%", maxWidth: 720, maxHeight: "82vh",
          display: "flex", flexDirection: "column",
          background: "linear-gradient(180deg, #1a0f04 0%, #0f0703 100%)",
          boxShadow: "0 20px 60px rgba(0,0,0,0.6), 0 0 0 1px rgba(212,162,58,0.25), 0 0 40px rgba(212,162,58,0.15)",
          padding: 0,
          overflow: "hidden",
        }}
      >
        {/* Header */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "14px 18px",
          borderBottom: "1px solid var(--hxm-line-2)",
          background: "linear-gradient(135deg, rgba(212,162,58,0.08), rgba(212,162,58,0.02))",
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <Coins size={16} color="var(--hxm-gold-bright)" />
            <div>
              <div className="hxm-cinzel" style={{ fontSize: 14, fontWeight: 800, color: "var(--hxm-gold-bright)", letterSpacing: "0.18em" }}>
                SELECT MINE TARGET
              </div>
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: "transparent", border: "1px solid var(--hxm-line)", borderRadius: 4,
              color: "var(--hxm-text-dim)", cursor: "pointer",
              padding: 6, display: "flex",
            }}
            onMouseEnter={(e) => { e.currentTarget.style.color = "var(--hxm-gold-bright)"; e.currentTarget.style.borderColor = "rgba(212,162,58,0.5)"; }}
            onMouseLeave={(e) => { e.currentTarget.style.color = "var(--hxm-text-dim)"; e.currentTarget.style.borderColor = "var(--hxm-line)"; }}
          >
            <X size={14} />
          </button>
        </div>

        {/* Search + sort */}
        <div style={{ padding: "12px 18px", borderBottom: "1px solid var(--hxm-line)", display: "flex", flexDirection: "column", gap: 8 }}>
          <div style={{
            display: "flex", alignItems: "center", gap: 8,
            padding: "8px 12px",
            background: "rgba(0,0,0,0.5)",
            border: "1px solid var(--hxm-line-2)",
            borderRadius: 5,
          }}>
            <Search size={13} color="var(--hxm-text-dim)" />
            <input
              autoFocus
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search ticker or name..."
              className="hxm-mono"
              style={{
                flex: 1, background: "transparent", border: "none", outline: "none",
                color: "var(--hxm-text)", fontSize: 12,
              }}
            />
            {query && (
              <button onClick={() => setQuery("")} style={{ background: "transparent", border: "none", color: "var(--hxm-text-dim)", cursor: "pointer", padding: 0, display: "flex" }}>
                <X size={12} />
              </button>
            )}
          </div>
          <SortChips
            options={[
              { key: "deployedBlock", label: "TIME" },
              { key: "supply",        label: "SUPPLY" },
              { key: "mint",          label: "MINT" },
              { key: "holders",       label: "HOLDERS" },
            ]}
            value={sortKey}
            dir={sortDir}
            onChange={(k, d) => { setSortKey(k); setSortDir(d); }}
          />
        </div>

        {/* List */}
        <div className="hxm-scroll" style={{ flex: 1, overflowY: "auto", padding: "8px 12px" }}>
          {tokens.length === 0 ? (
            <div style={{ padding: 36, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 12 }}>
              {query
                ? `No tokens match "${query}"`
                : "No mintable tokens — every deployed ticker is fully minted. Search by name to inspect them."}
            </div>
          ) : pageItems.map((t) => {
            const pct = t.supply > 0 ? (t.minted / t.supply) * 100 : 0;
            const fullyMinted = pct >= 99.99;
            const isActive = t.ticker === state.wallet.tokenTicker;
            return (
              <button
                key={t.ticker}
                onClick={() => onPick(t.ticker)}
                style={{
                  width: "100%",
                  display: "grid",
 // Five-column layout deliberately echoes the four
 // SortChips above (TIME / SUPPLY / MINT / HOLDERS) —
 // each chip now sits roughly over its corresponding
 // data cell so the chips read as table headers, not
 // free-floating sort options:
 // Col 1 ticker ↔ TIME chip (ticker has
 // #blockNumber underneath,
 // which is the time stamp)
 // Col 2 supply ↔ SUPPLY chip
 // Col 3 mint bar ↔ MINT chip
 // Col 4 holders ↔ HOLDERS chip
 // Col 5 check/chev — trailing affordance, lines up
 // with the chips' right margin
 // Previously the layout was "120px 1fr 1fr auto" which
 // jammed supply + holders into a single 1fr cell.
 // Reading down from the HOLDERS sort chip, the user
 // landed on the MINT progress bar — reported as
 // "holdersholder. 60px is
 // enough for the holders integer (up to 6 digits, all
 // anyone is going to see while supply caps at 21M and
 // realistic holder counts are well under 1M).
                  gridTemplateColumns: "120px 1fr 1.5fr 60px auto",
                  gap: 12, alignItems: "center",
                  padding: "10px 12px",
                  margin: "3px 0",
                  background: isActive ? "rgba(212,162,58,0.1)" : "transparent",
                  border: isActive ? "1px solid rgba(212,162,58,0.5)" : "1px solid var(--hxm-line)",
                  borderRadius: 4,
                  color: "var(--hxm-text)",
                  cursor: "pointer",
                  fontFamily: "inherit",
                  textAlign: "left",
                  transition: "background 0.12s, border-color 0.12s",
                }}
                onMouseEnter={(e) => { if (!isActive) { e.currentTarget.style.background = "rgba(212,162,58,0.06)"; e.currentTarget.style.borderColor = "rgba(212,162,58,0.35)"; } }}
                onMouseLeave={(e) => { if (!isActive) { e.currentTarget.style.background = "transparent"; e.currentTarget.style.borderColor = "var(--hxm-line)"; } }}
              >
                {/* Col 1 — Ticker (↔ TIME chip; block number = the
                    deploy time). */}
                <div style={{ display: "flex", flexDirection: "column", minWidth: 0, overflow: "hidden" }}>
                  <span className="hxm-cinzel" style={{
                    fontSize: 14, fontWeight: 800,
                    color: isActive ? "var(--hxm-gold-bright)" : "var(--hxm-gold)",
                    letterSpacing: "0.1em",
                    whiteSpace: "nowrap",
                  }}>
                    {t.ticker}
                  </span>
                  <span className="hxm-mono" style={{ fontSize: 9, color: "var(--hxm-text-mute)" }}>
 #{fmt(t.deployedBlock)}
                  </span>
                </div>

                {/* Col 2 — Supply value (↔ SUPPLY chip). No "supply"
                    word — chip header above already says so. */}
                <div className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-text)" }}>
                  {fmtCompact(t.supply)}
                </div>

                {/* Col 3 — Mint progress (↔ MINT chip). */}
                <div style={{ display: "flex", flexDirection: "column", gap: 3, minWidth: 0 }}>
                  <div className="hxm-mono" style={{
                    fontSize: 10,
                    color: fullyMinted ? "var(--hxm-red)" : "var(--hxm-gold-bright)",
                    textAlign: "right",
                    fontWeight: fullyMinted ? 700 : 500,
                  }}>
                    {fullyMinted
                      ? <span style={{ letterSpacing: "0.18em" }}>MINTED OUT</span>
                      : `${pct.toFixed(2)}%`}
                  </div>
                  <MintBar pct={pct} height={4} />
                </div>

                {/* Col 4 — Holders count (↔ HOLDERS chip). Right-aligned
                    monospace matches the SUPPLY cell's typographic
                    feel so the table reads as a tabular grid. */}
                <div className="hxm-mono" style={{
                  fontSize: 11,
                  color: "var(--hxm-gold-bright)",
                  textAlign: "right",
                }}>
                  {holdersFor(t).display}
                </div>

                {/* Col 5 — Active check / chevron affordance. */}
                <div style={{ minWidth: 16, display: "flex", justifyContent: "center" }}>
                  {isActive
                    ? <Check size={14} color="var(--hxm-gold-bright)" />
                    : <ChevronRight size={13} color="var(--hxm-text-mute)" />}
                </div>
              </button>
            );
          })}
        </div>

        {/* Pagination bar — visible whenever the filtered set has more
            than one page. Hidden for empty lists (no rows to page over)
            and single-page lists (no UX value). */}
        {tokens.length > 0 && totalPages > 1 && (
          <div style={{
            display: "flex", alignItems: "center", justifyContent: "space-between",
            padding: "8px 18px",
            borderTop: "1px solid var(--hxm-line)",
            background: "rgba(0,0,0,0.4)",
            fontSize: 11, color: "var(--hxm-text-dim)",
          }}>
            <button
              onClick={() => setPage((p) => Math.max(0, p - 1))}
              disabled={safePage === 0}
              className="btx-btn-ghost"
              style={{
                padding: "4px 10px", fontSize: 10,
                opacity: safePage === 0 ? 0.4 : 1,
                cursor: safePage === 0 ? "not-allowed" : "pointer",
                display: "inline-flex", alignItems: "center", gap: 4,
              }}
            >
              <ChevronLeft size={11} /> PREV
            </button>
            <div className="hxm-mono" style={{ textAlign: "center", lineHeight: 1.4 }}>
              <div>page {safePage + 1} / {totalPages}</div>
              <div style={{ fontSize: 9, color: "var(--hxm-text-mute)" }}>
                showing {pageStart + 1}–{Math.min(pageStart + PAGE_SIZE, tokens.length)} of {tokens.length}
              </div>
            </div>
            <button
              onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
              disabled={safePage >= totalPages - 1}
              className="btx-btn-ghost"
              style={{
                padding: "4px 10px", fontSize: 10,
                opacity: safePage >= totalPages - 1 ? 0.4 : 1,
                cursor: safePage >= totalPages - 1 ? "not-allowed" : "pointer",
                display: "inline-flex", alignItems: "center", gap: 4,
              }}
            >
              NEXT <ChevronRight size={11} />
            </button>
          </div>
        )}

        {/* Footer hint */}
        <div style={{
          padding: "8px 18px",
          borderTop: "1px solid var(--hxm-line)",
          background: "rgba(0,0,0,0.3)",
          fontSize: 10, color: "var(--hxm-text-mute)",
          display: "flex", justifyContent: "space-between", alignItems: "center",
        }}>
          <span>
            {query
              ? `Click any token to select for mining`
              : `Showing not-fully-minted tokens. Search to find any deployed ticker.`}
          </span>
          <span className="hxm-mono">ESC to close</span>
        </div>
      </div>
    </div>
  );
}

