function SoundToggle() {
  const [muted, setMutedState] = useState(isSfxMuted());
  useEffect(() => onSfxMuteChange(setMutedState), []);
  const toggle = () => {
    const next = !isSfxMuted();
    setSfxMuted(next);
 // play a confirmation tick when un-muting (also lazy-inits the
 // AudioContext on first user gesture — required for browser autoplay
 // policies).
    if (!next) sfxClick();
  };
  return (
    <button
      className="hxm-btn"
      onClick={toggle}
      title={muted ? "sound off — click to enable" : "sound on — click to mute"}
      style={{
        fontSize: 11, padding: "6px 10px",
        color: muted ? "var(--hxm-text-mute)" : "var(--hxm-gold-bright)",
        borderColor: muted ? "var(--hxm-line)" : "var(--hxm-line-2)",
      }}
    >
      {muted ? <VolumeX size={11} /> : <Volume2 size={11} />}
      {muted ? "SOUND OFF" : "SOUND ON"}
    </button>
  );
}

