function Toast({ kind, msg, onClose }) {
  const palette = {
    ok:   { bg: "linear-gradient(180deg, #0e3018, #061a0c)", border: "rgba(62,200,112,0.5)", text: "#a0f0bc" },
    warn: { bg: "linear-gradient(180deg, #2c1c08, #1a0e02)", border: "rgba(255,180,80,0.6)", text: "var(--hxm-gold-bright)" },
    err:  { bg: "linear-gradient(180deg, #2c0a0a, #160404)", border: "rgba(229,75,75,0.6)", text: "#f0a0a0" },
  };
  const p = palette[kind] || palette.ok;
  return (
    <div className="toast-pop" style={{
      position: "fixed", left: "50%", bottom: 70, transform: "translateX(-50%)",
      zIndex: 100, padding: "10px 18px", borderRadius: 8,
      background: p.bg, border: `1px solid ${p.border}`, color: p.text,
      boxShadow: "0 16px 40px rgba(0,0,0,0.7)",
      fontFamily: "'JetBrains Mono', monospace", fontSize: 12,
      display: "flex", alignItems: "center", gap: 10,
    }}>
      <span>{msg}</span>
      <button onClick={onClose} style={{ background: "none", border: "none", color: p.text, cursor: "pointer", opacity: 0.7 }}>
        <X size={13} />
      </button>
    </div>
  );
}

