// =============================================================================
// TOKEN INDEX — on-chain registry of all deployed tokens
// =============================================================================

/**
 * Derive the displayable "holders" count for a token, consistently across
 * every UI surface that reads it. Pure function of the token entry.
 * Why a derive helper instead of a stored field:
 * - Old DeployScreen entries were created with `holders: 1` hardcoded
 * (the deployer was assumed to auto-hold), but the LUCKYPROTOCOL protocol
 * doesn't auto-mint to the deployer — holders should be 0 until the
 * first BET WIN credit. That's the user's "CASINO shows 1 but minted
 * is 0/21M" bug. Recomputing here makes the display self-consistent
 * with `minted` regardless of what's stored.
 * - The local app only knows ITS OWN address's balance. The exact
 * global holder count requires the LUCKYPROTOCOL indexer's per-address
 * ledger; without that we can only say "0" (definitely none yet) /
 * "≥ 1" (mints exist somewhere) / "—" (unknown).
 * Returns { n, display } — n is the sort key, display is the JSX text.
 * - { n: 0, display: "0" } → minted==0, no holders possible
 * - { n: N, display: "N" } → indexer-supplied count (rare today)
 * - { n: 1, display: "≥ 1" } → minted>0, no exact count, but
 * SOMEONE holds (we may or may not)
 * - { n: -1, display: "—" } → minted unknown, can't say
 * Declared as a function (hoisted) so callers earlier in the file —
 * e.g. TokenDeployPanel's right-rail card — can use it without the
 * "Cannot access 'holdersFor' before initialization" TDZ error that
 * `const holdersFor = (...) =>` would produce.
 */
function holdersFor(t) {
  const stored = t?.holders;
 // Local floor: if THIS WALLET holds any of this ticker, the holders
 // count is at least 1. Used only when the indexer's authoritative
 // count is unavailable.
  let localFloor = 0;
  try {
    const balances = getIndexedBalances();
    if (t?.ticker && Number(balances[t.ticker] || 0) > 0) localFloor = 1;
  } catch {}
 // Authoritative path: indexer returned a holders count via /tokens.
 // Show the exact number — this is what the user actually wants
 // ("holders1").
  if (typeof stored === "number") {
 // Defensive max(stored, localFloor) — the local-balance floor
 // catches a freshly-restarted indexer that hasn't yet rebuilt the
 // addresses map, but normally stored ≥ localFloor.
    const n = Math.max(stored, localFloor);
    return { n, display: n.toLocaleString() };
  }
 // No indexer count yet. Best we can do is local floor: 1 if WE hold,
 // 0 (rendered as "—") otherwise.
  if (localFloor > 0) return { n: 1, display: "1" };
  return { n: -1, display: "—" };
}

/** Effective minted = max(indexer-reported minted, this wallet's own balance).
 * The local balance is a hard lower bound on global mint — you can't
 * hold tokens that don't exist. Used so the index doesn't show
 * "0 / 21M" when the user is clearly holding a positive amount.
 */
function mintedFor(t) {
  const reported = Number(t?.minted ?? 0);
  let localOwned = 0;
  try {
    const balances = getIndexedBalances();
    if (t?.ticker) localOwned = Number(balances[t.ticker] || 0);
  } catch {}
  return Math.max(reported, localOwned);
}

function TokenIndex({ state, selectToken, goDashboard, onScan }) {
  const [query, setQuery] = useState("");
  const [sortKey, setSortKey] = useState("holders");
  const [sortDir, setSortDir] = useState("desc");
 // When set, the INDEX screen swaps its table for an inline token
 // detail view (holder list + stats) — no modal popup. Click a row →
 // detail view; click the back button → return to the table. Stays
 // in the same `.btx-screen` panel so the visual style matches the
 // rest of INDEX exactly.
  const [holdersToken, setHoldersToken] = useState(null);
 // Pagination — page size matches TokenPickerModal (10) so the
 // "client-side token list" feels consistent across the two
 // surfaces that surface the token registry. Page resets to 0
 // whenever the result set changes (search / sort) below.
  const PAGE_SIZE = 10;
  const [page, setPage] = useState(0);
  useEffect(() => { setPage(0); }, [query, sortKey, sortDir]);

 // Split into confirmed vs pending. The registry below ONLY shows
 // confirmed tokens — a deploy with `status: "pending"` is on its way
 // but isn't a real on-chain registry entry yet (the indexer would
 // reject any bet against it via strict mode). Pending deploys get
 // their own banner above the table so the user has visible feedback
 // that their broadcast is in-flight without polluting the registry.
 // `status: "rejected"` covers DEPLOYs confirmed BELOW the protocol
 // activation height (LCKPROTOCOL_START_HEIGHT) — they are invisible to
 // the protocol, so we hide them from the registry too. They stay in
 // state.deployedTokens (in case the user wants to see them via a
 // future "show rejected" toggle) but the registry table treats them
 // as if they didn't exist.
  const tokens = useMemo(() => {
    const q = query.trim().toLowerCase();
 // INDEX shows tokens by on-chain provenance under the current
 // protocol cohort:
 // - status active + deployedBlock >= LCKPROTOCOL_START_HEIGHT → "confirmed"
 // bucket, fully sortable + clickable rows.
 // - status pending (user's own broadcast, not yet confirmed) →
 // "pending" bucket, rendered at the BOTTOM of the table as
 // non-clickable rows so the user can see "this DEPLOY is in
 // flight" without us pretending it's real registry data.
 // - status rejected (pre-activation / bad) → hide
 // - deployedBlock missing (locally-discovered placeholder from a
 // bet payload referencing a never-deployed ticker) → hide
 // - deployedBlock < LCKPROTOCOL_START_HEIGHT (pre-activation) → hide
 // Without these filters the user sees ghost tokens like "CASINO"
 // that they never deployed but accumulated balance against via
 // pre-activation bet wins (now invalid under new activation height).
    let list = state.deployedTokens.filter((t) => {
      if (t.status === "pending") return false; // appended below
      if (t.status === "rejected") return false;
      if (t.deployedBlock == null) return false;
      if (t.deployedBlock < LCKPROTOCOL_START_HEIGHT) return false;
      return true;
    });
    if (q) {
      list = list.filter((t) => t.ticker.toLowerCase().includes(q) || t.name.toLowerCase().includes(q));
    }
    const dir = sortDir === "asc" ? 1 : -1;
    list.sort((a, b) => {
      let av, bv;
      if (sortKey === "ticker" || sortKey === "name") { av = a[sortKey]; bv = b[sortKey]; return av < bv ? -1 * dir : av > bv ? 1 * dir : 0; }
      if (sortKey === "mint") { av = a.minted / a.supply; bv = b.minted / b.supply; }
      else if (sortKey === "holders") { av = holdersFor(a).n; bv = holdersFor(b).n; }
      else { av = a[sortKey]; bv = b[sortKey]; }
      return (av - bv) * dir;
    });
 // Append pending deploys at the END of the list — they share the
 // same row chrome but render as non-interactive (no click, no
 // hover) so the user reads them as "in flight" without us
 // pretending they're real registry rows. Filtered/searched
 // separately so a user-typed query doesn't make the pending
 // chips disappear mid-broadcast.
    const pending = state.deployedTokens.filter((t) => t.status === "pending");
    const pendingFiltered = q
      ? pending.filter((t) => t.ticker.toLowerCase().includes(q))
      : pending;
    return [...list, ...pendingFiltered];
  }, [state.deployedTokens, query, sortKey, sortDir]);

  const toggleSort = (key) => {
    if (sortKey === key) setSortDir(sortDir === "asc" ? "desc" : "asc");
    else { setSortKey(key); setSortDir("desc"); }
  };

  const SortHeader = ({ k, label, align = "left", paddingLeft }) => {
    const active = sortKey === k;
    const flexAlign =
      align === "right" ? "flex-end"
      : align === "center" ? "center"
      : "flex-start";
    return (
      <button
        onClick={() => toggleSort(k)}
        className="hxm-bebas"
        style={{
          background: "transparent", border: "none", padding: 0, cursor: "pointer",
          paddingLeft: paddingLeft || undefined,
          fontSize: 10, letterSpacing: "0.18em",
          color: active ? "var(--hxm-gold-bright)" : "var(--hxm-text-dim)",
          textAlign: align, width: "100%",
          display: "flex", alignItems: "center", gap: 4,
          justifyContent: flexAlign,
          fontFamily: "inherit",
        }}
      >
        {label}
        {active && (sortDir === "asc" ? <ChevronUp size={10} /> : <ChevronDown size={10} />)}
      </button>
    );
  };

 // When a token row is clicked, swap the index table for an inline
 // detail view INSIDE the same screen — same chrome (.btx-screen +
 // hero header pattern +.hxm-bordered table) so it visually reads
 // as a different INDEX page, not a popup.
  if (holdersToken) {
    return (
      <TokenHoldersDetail
        token={holdersToken}
        ownAddress={state.wallet.address}
        onBack={() => setHoldersToken(null)}
      />
    );
  }

  return (
    <div className="btx-screen">
      {/* Hero header */}
      <div style={{
        padding: "20px 24px",
        background: "linear-gradient(135deg, rgba(212,162,58,0.06), rgba(212,162,58,0.02))",
        border: "1px solid var(--hxm-line-2)",
        borderRadius: 6,
        marginBottom: 16,
        position: "relative",
        overflow: "hidden",
      }}>
        {/* Header — TOKENS / HOLDERS counters were removed per user
            request (those numbers conflicted with the still-backfilling
            global indexer's view). The SCAN button on the right
            replaces them and gives the user explicit control: press to
            force a chain-tip re-poll + a /tokens registry re-fetch.
            Auto-resolves to "SCAN" once the indexer catches up. */}
        <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 16 }}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <Database size={22} color="var(--hxm-gold-bright)" style={{ filter: "drop-shadow(0 0 8px rgba(212,162,58,0.45))" }} />
              <div className="hxm-cinzel metal-gold" style={{
                fontSize: 28, fontWeight: 900, letterSpacing: "0.10em", lineHeight: 1.1,
              }}>
                ON-CHAIN TOKEN INDEX
              </div>
            </div>
            <div className="hxm-cormorant" style={{
              fontSize: 13, color: "var(--hxm-gold)",
              fontStyle: "italic", marginTop: 6, letterSpacing: "0.08em",
              display: "flex", alignItems: "center", gap: 12,
            }}>
              <span className="gold-rule" style={{ width: 32 }} />
              <span>All tokens deployed via the LUCKYPROTOCOL protocol</span>
              <span className="gold-rule" style={{ flex: 1 }} />
            </div>
          </div>
          {onScan && (
            <div style={{ flexShrink: 0, marginTop: 4 }}>
              <ScanButton onClick={onScan} />
            </div>
          )}
        </div>

        {/* Search */}
        <div style={{ marginTop: 14, display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{
            display: "flex", alignItems: "center", gap: 8,
            flex: 1, padding: "8px 12px",
            background: "rgba(0,0,0,0.5)",
            border: "1px solid var(--hxm-line-2)",
            borderRadius: 5,
          }}>
            <Search size={14} color="var(--hxm-text-dim)" />
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search ticker or name..."
              className="hxm-mono"
              style={{
                flex: 1, background: "transparent", border: "none", outline: "none",
                color: "var(--hxm-text)", fontSize: 12,
              }}
            />
            {query && (
              <button onClick={() => setQuery("")} style={{ background: "transparent", border: "none", color: "var(--hxm-text-dim)", cursor: "pointer", padding: 0, display: "flex" }}>
                <X size={12} />
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="hxm-bordered" style={{ padding: 0, overflow: "hidden", marginTop: 14 }}>
        {/* Header row */}
        <div style={{
          display: "grid",
 // NAME column removed — the registry's
 // ticker IS the user-facing identifier (all 1-8 uppercase
 // alphanumeric; no separate display name to disambiguate).
 // Columns: # | TICKER | DEPLOYED | SUPPLY | HOLDERS | MINT | STATUS
          gridTemplateColumns: "28px 100px 95px 100px 100px 1fr 65px",
          gap: 10, alignItems: "center",
          padding: "10px 14px",
          borderBottom: "1px solid var(--hxm-line-2)",
          background: "rgba(0,0,0,0.35)",
        }}>
          <span className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.18em" }}>#</span>
          <SortHeader k="ticker" label="TICKER" />
          <SortHeader k="deployedBlock" label="DEPLOYED" align="right" />
          <SortHeader k="supply" label="SUPPLY" align="right" />
          <SortHeader k="holders" label="HOLDERS" align="center" />
          <SortHeader k="mint" label="MINT PROGRESS" paddingLeft={22} />
          <span className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.18em", textAlign: "right" }}>STATUS</span>
        </div>

        {tokens.length === 0 && (
          <div style={{ padding: 32, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 12 }}>
            {query
              ? `No tokens match "${query}"`
              : <>No protocol tokens indexed yet · place a BET in any IRON / BRONZE / SILVER / GOLD room to mint your first tokens</>
            }
          </div>
        )}

        {/* Body rows — client-side paged. `pageItems` is the sliced
            view; `totalPages` + the footer pager below let the user
            walk through the registry without flooding the DOM with
            hundreds of rows at once. Page size matches the
            TokenPickerModal (10) so the two surfaces feel consistent. */}
        {(() => {
          const totalPages = Math.max(1, Math.ceil(tokens.length / PAGE_SIZE));
          const safePage = Math.min(page, totalPages - 1);
          const pageStart = safePage * PAGE_SIZE;
          const pageItems = tokens.slice(pageStart, pageStart + PAGE_SIZE);
          return pageItems.map((t, idxInPage) => {
          const idx = pageStart + idxInPage;
          const pct = t.supply > 0 ? (t.minted / t.supply) * 100 : 0;
          const fullyMinted = pct >= 99.99;
 // Pending rows (status === "pending") = user's own DEPLOY
 // broadcast still in mempool. Render as non-interactive,
 // amber-tinted, no hover/click. They share the same grid
 // chrome as confirmed rows so the table reads as one
 // unified list, just with the PENDING badge in STATUS to
 // signal in-flight. Clicking a pending row to "view
 // holders" makes no sense (no holders exist yet), and the
 // detail page would crash on missing block/holders data —
 // so we strip the onClick + hover entirely.
          const isPending = t.status === "pending";
          return (
            <div
              key={t.ticker}
              onClick={isPending ? undefined : () => setHoldersToken(t)}
              style={{
                display: "grid",
 // Columns match the header above — NAME removed:
 // # | TICKER | DEPLOYED | SUPPLY | HOLDERS | MINT | STATUS
                gridTemplateColumns: "28px 100px 95px 100px 100px 1fr 65px",
                gap: 10, alignItems: "center",
 // Vertical padding 12 → 16 so the PENDING badge (which is
 // ~22px tall with its border + padding) doesn't graze the
 // row's bottom divider line. Reported as "pending
 //. The extra 4px each side gives the badge breathing
 // room above + below.
                padding: "16px 14px",
                borderBottom: idx === tokens.length - 1 ? "none" : "1px solid var(--hxm-line)",
                background: isPending ? "rgba(255,184,77,0.04)" : "transparent",
                cursor: isPending ? "default" : "pointer",
                opacity: isPending ? 0.85 : 1,
                transition: "background 0.15s",
              }}
              onMouseEnter={isPending ? undefined : (e) => { e.currentTarget.style.background = "rgba(212,162,58,0.04)"; }}
              onMouseLeave={isPending ? undefined : (e) => { e.currentTarget.style.background = "transparent"; }}
            >
              <span className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-text-mute)" }}>{idx + 1}</span>

              <span className="hxm-cinzel" style={{
                fontSize: 14, fontWeight: 700,
                color: isPending ? "var(--hxm-amber)" : "var(--hxm-gold)",
                letterSpacing: "0.1em",
              }}>
                {t.ticker}
              </span>

              <span className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-text-dim)", textAlign: "right" }}>
                {t.deployedBlock != null ? `#${fmt(t.deployedBlock)}` : <span style={{ color: "var(--hxm-text-mute)" }}>—</span>}
              </span>

              <span className="hxm-mono" style={{ fontSize: 12, color: "var(--hxm-text)", textAlign: "right" }}>
                {t.supply != null ? fmtCompact(t.supply) : <span style={{ color: "var(--hxm-text-mute)" }}>—</span>}
              </span>

              <span className="hxm-mono" style={{
                fontSize: 12, color: "var(--hxm-text)",
 // Centered to match the HOLDERS column header (which is
 // also now `align="center"`). Right-alignment looked
 // visually disconnected: the header sat near the column
 // edge while the small icon+digit cluster floated by
 // itself further right — reported as "holders.
                textAlign: "center",
                display: "flex", alignItems: "center", justifyContent: "center", gap: 4,
              }}>
                <Users size={11} color="var(--hxm-text-dim)" />
                {holdersFor(t).display}
              </span>

              {/* Left padding pushes MINT PROGRESS away from the
                  HOLDERS column — the original 10px grid gap felt
                  too tight given HOLDERS is right-aligned + MINT
                  starts immediately with text. 22px gives a clear
                  break between the two semantic groups (right-aligned
                  count vs. left-aligned progress bar). */}
              <div style={{ display: "flex", flexDirection: "column", gap: 4, paddingLeft: 22 }}>
                {t.supply != null && t.minted != null ? (
                  (() => {
 // Effective minted = max(indexer-reported, our own
 // wallet balance). Defends against the indexer
 // being behind / fresh-state / disagreeing — the
 // user can't be holding tokens that haven't been
 // minted, so the display floor is local balance.
                    const effMinted = mintedFor(t);
                    const effPct = t.supply > 0 ? (effMinted / t.supply) * 100 : 0;
                    const effFull = t.supply > 0 && effMinted >= t.supply;
                    return (
                      <>
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10 }}>
                          <span className="hxm-mono" style={{ color: "var(--hxm-text-dim)" }}>{fmtCompact(effMinted)} / {fmtCompact(t.supply)}</span>
                          <span className="hxm-mono" style={{ color: effFull ? "var(--hxm-green)" : "var(--hxm-gold-bright)" }}>{effPct.toFixed(2)}%</span>
                        </div>
                        <MintBar pct={effPct} />
                      </>
                    );
                  })()
                ) : (
                  <span className="hxm-mono" style={{ fontSize: 10, color: "var(--hxm-text-mute)" }}>indexed · open mint</span>
                )}
              </div>

              <div style={{ textAlign: "right" }}>
                {/* STATUS is now purely a chain-state badge — three values,
                    no overlap with wallet-side concepts:
                      PENDING  — user's own DEPLOY broadcast, no confirming
                                 block yet (only ever populated by the
                                 deploy-confirmation poller in App).
                      MINTED   — supply fully drained (pct ≥ 99.99).
                      OPEN     — confirmed on chain, supply remaining — any
                                 user can mine on it.
                    Previously a 4th value "ACTIVE" leaked the wallet's
                    `tokenTicker` (UI focus for the MINE button) into this
                    column, which conflated two unrelated dimensions —
                    "what state is this token in on chain" vs "which
                    ticker does my MINE button currently target". The
                    overlap made the user's own non-focused deploys
                    visually indistinguishable from anyone else's, and
                    forced a "SET AS ACTIVE" ceremony on every deploy.
                    Removed. The wallet's mining-target ticker is still
                    tracked internally for the MINE form, but no longer
                    surfaces as a status badge here. */}
                {t.status === "pending" ? (
                  <span className="hxm-bebas" style={{
                    fontSize: 9, letterSpacing: "0.18em",
                    color: "var(--hxm-amber)",
                    display: "inline-flex", alignItems: "center", gap: 4,
                    padding: "3px 7px",
                    background: "rgba(255,184,77,0.12)",
                    border: "1px solid rgba(255,184,77,0.5)",
                    borderRadius: 3,
                  }}>
                    <RefreshCw size={9} className="btx-spin" /> PENDING
                  </span>
                ) : fullyMinted ? (
                  <span className="hxm-bebas" style={{ fontSize: 9, letterSpacing: "0.18em", color: "var(--hxm-green)" }}>MINTED</span>
                ) : (
                  <span className="hxm-bebas" style={{ fontSize: 9, letterSpacing: "0.18em", color: "var(--hxm-text-mute)" }}>OPEN</span>
                )}
              </div>
            </div>
          );
          });
        })()}

        {/* Pager — matches TokenPickerModal's pagination chrome
            (PREV / page N of M · showing A–B of T / NEXT). Hidden
            when the registry fits on one page. */}
        {(() => {
          const totalPages = Math.max(1, Math.ceil(tokens.length / PAGE_SIZE));
          if (tokens.length === 0 || totalPages <= 1) return null;
          const safePage = Math.min(page, totalPages - 1);
          const pageStart = safePage * PAGE_SIZE;
          return (
            <div style={{
              display: "flex", alignItems: "center", justifyContent: "space-between",
              padding: "8px 18px",
              borderTop: "1px solid var(--hxm-line)",
              background: "rgba(0,0,0,0.4)",
              fontSize: 11, color: "var(--hxm-text-dim)",
            }}>
              <button
                onClick={() => setPage((p) => Math.max(0, p - 1))}
                disabled={safePage === 0}
                className="btx-btn-ghost"
                style={{
                  padding: "4px 10px", fontSize: 10,
                  opacity: safePage === 0 ? 0.4 : 1,
                  cursor: safePage === 0 ? "not-allowed" : "pointer",
                  display: "inline-flex", alignItems: "center", gap: 4,
                }}
              >
                <ChevronLeft size={11} /> PREV
              </button>
              <div className="hxm-mono" style={{ textAlign: "center", lineHeight: 1.4 }}>
                <div>page {safePage + 1} / {totalPages}</div>
                <div style={{ fontSize: 9, color: "var(--hxm-text-mute)" }}>
                  showing {pageStart + 1}–{Math.min(pageStart + PAGE_SIZE, tokens.length)} of {tokens.length}
                </div>
              </div>
              <button
                onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                disabled={safePage >= totalPages - 1}
                className="btx-btn-ghost"
                style={{
                  padding: "4px 10px", fontSize: 10,
                  opacity: safePage >= totalPages - 1 ? 0.4 : 1,
                  cursor: safePage >= totalPages - 1 ? "not-allowed" : "pointer",
                  display: "inline-flex", alignItems: "center", gap: 4,
                }}
              >
                NEXT <ChevronRight size={11} />
              </button>
            </div>
          );
        })()}
      </div>

      <div style={{ marginTop: 12, fontSize: 10, color: "var(--hxm-text-mute)", textAlign: "center" }}>
        Click any row to view holders · Switch the mine target from the side-rail panel · Any OPEN token is mintable
      </div>
      {/* The external "PENDING DEPLOYMENTS" amber banner used to live
          here. Removed — pending deploys are now appended as inline
          rows in the main token table (filtered out of the clickable
          / sortable confirmed group, rendered at the bottom with
          status="pending" → PENDING badge in the STATUS column, no
          onClick / no hover). One unified list, no separate side
          panel for in-flight broadcasts. */}
    </div>
  );
}

// =============================================================================
// TOKEN HOLDERS — INLINE DETAIL VIEW
// =============================================================================
// Rendered INSIDE TokenIndex's `.btx-screen` slot when the user clicks a
// token row. Same chrome as the index list (gold hero header, hxm-bordered
// table, gold-rule subtitle line) so it reads as just-another-INDEX-page
// rather than a modal popup. A "← INDEX" back button at the top-left
// returns to the token list.
// =============================================================================
function TokenHoldersDetail({ token, ownAddress, onBack }) {
  const [holders, setHolders] = useState([]);
  const [total, setTotal] = useState(0);
 // Pagination — `/tokens/:ticker/holders?limit=...&offset=...`. With
 // a single popular ticker holders can easily run into the
 // thousands; rendering them all at once on one page is both slow
 // (DOM + virtual scroll) and unreadable. Page size 25 keeps each
 // page short enough that the user can scan it without scrolling
 // inside the table, and the fetch payload stays tiny (~3KB per
 // page). Page state resets to 0 when the ticker changes.
  const PAGE_SIZE = 25;
  const [page, setPage] = useState(0);
 // `indexed` flag from the server — false means the indexer hasn't seen
 // this ticker's deploy yet (still backfilling, or genuinely missing).
 // `indexedHeight` / `tipHeight` give the user a sense of how far behind
 // the indexer is. Re-poll every 4s while !indexed so a recently-
 // broadcast deploy auto-resolves once the indexer catches up.
  const [indexed, setIndexed] = useState(true);
  const [indexedHeight, setIndexedHeight] = useState(0);
  const [tipHeight, setTipHeight] = useState(0);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState(null);

 // Reset to page 0 when the user clicks a different ticker — otherwise
 // an empty page (because the new ticker has fewer holders than the
 // previous one's last page offset) would render confusing nothing.
  useEffect(() => { setPage(0); }, [token.ticker]);

  useEffect(() => {
    let cancelled = false;
    let timer = null;
    const ctrl = new AbortController();

    const tick = async () => {
      try {
        const data = await fetchTokenHolders(token.ticker, getGlobalIndexerUrl(), {
          limit: PAGE_SIZE,
          offset: page * PAGE_SIZE,
          signal: ctrl.signal,
        });
        if (cancelled) return;
        setHolders(Array.isArray(data?.holders) ? data.holders : []);
        setTotal(typeof data?.total === "number" ? data.total : 0);
        setIndexed(!!data?.indexed);
        setIndexedHeight(Number(data?.indexed_height) || 0);
        setTipHeight(Number(data?.tip_height) || 0);
        setErr(null);
        setLoading(false);
 // Polling cadence:
 // !indexed → 4s (fast — waiting for backfill to discover
 // the deploy)
 // indexed → 8s (background — holders change on bet wins
 // and SEND landings; previously stopped entirely,
 // which made the page silently go stale when a
 // new WIN credited a new holder. 8s is faster
 // than INDEX's 15s `/tokens` cadence so this
 // drill-in stays at least as fresh as the
 // parent list).
        if (!cancelled) {
          timer = setTimeout(tick, data?.indexed ? 8_000 : 4_000);
        }
      } catch (e) {
        if (cancelled) return;
        if (e?.name === "AbortError") return;
        setErr(String(e?.message || e));
        setLoading(false);
      }
    };
    setLoading(true);
    setErr(null);
    tick();

    return () => {
      cancelled = true;
      if (timer) clearTimeout(timer);
      ctrl.abort();
    };
  }, [token.ticker, page]);

 // ESC returns to the index list — same convention as the modal had,
 // but without the modal-blocker overlay.
  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") onBack(); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onBack]);

  const supply = token.supply || 0;
  const minted = token.minted || 0;
  const fmtAddr = (addr) => {
    if (!addr) return "—";
    if (addr.length <= 18) return addr;
    return `${addr.slice(0, 10)}…${addr.slice(-6)}`;
  };

  return (
    <div className="btx-screen">
      {/* Hero — same shape as the INDEX list's hero, with a back link
          replacing the search box and the ticker name in place of
          "ON-CHAIN TOKEN INDEX". */}
      <div style={{
        padding: "20px 24px",
        background: "linear-gradient(135deg, rgba(212,162,58,0.06), rgba(212,162,58,0.02))",
        border: "1px solid var(--hxm-line-2)",
        borderRadius: 6,
        marginBottom: 16,
        position: "relative",
        overflow: "hidden",
      }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16 }}>
          <div style={{ minWidth: 0 }}>
            <button
              onClick={onBack}
              className="hxm-bebas"
              style={{
                background: "transparent", border: "none", cursor: "pointer",
                color: "var(--hxm-text-dim)", letterSpacing: "0.22em",
                fontSize: 10.5, padding: 0, marginBottom: 6,
                display: "inline-flex", alignItems: "center", gap: 6,
              }}
            >
              <ArrowLeft size={12} /> INDEX
            </button>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <Database size={22} color="var(--hxm-gold-bright)" style={{ filter: "drop-shadow(0 0 8px rgba(212,162,58,0.45))" }} />
              <div className="hxm-cinzel metal-gold" style={{
                fontSize: 28, fontWeight: 900, letterSpacing: "0.10em", lineHeight: 1.1,
              }}>
                {token.ticker}
              </div>
            </div>
            {/* Italic "N holders · X.XX% minted" subtitle removed --
                same info already lives in the SUPPLY / MINTED /
                HOLDERS cards directly below the hero. Repeating it
                here was filler text the user asked to drop. */}
            <div className="hxm-cormorant" style={{
              fontSize: 13, color: "var(--hxm-gold)",
              fontStyle: "italic", marginTop: 6, letterSpacing: "0.08em",
              display: "flex", alignItems: "center", gap: 12,
            }}>
              <span className="gold-rule" style={{ flex: 1 }} />
            </div>
          </div>
          {/* The "✓ ACTIVE" badge and "SET AS ACTIVE" button used to live
              here — both removed when the wallet-focus / chain-state
              dimensions in STATUS were untangled. Any OPEN token can be
              mined from the MINE form's ticker selector directly; no
              pre-flight ceremony needed. */}
        </div>
      </div>

      {/* Stats strip — same dark-card pattern as elsewhere */}
      <div style={{
        display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1.5fr",
        gap: 10, marginBottom: 14,
        fontFamily: "'JetBrains Mono', monospace",
      }}>
        {[
          { label: "SUPPLY",   value: fmt(supply), color: "var(--hxm-text)" },
          { label: "MINTED",   value: fmt(minted), color: "var(--hxm-gold-bright)" },
          { label: "HOLDERS",  value: total.toLocaleString(), color: "var(--hxm-gold-bright)" },
 // DEPLOYER shows the full bc1q... address. The cell sits in
 // the wider 1.5fr grid column; we render in monospace at a
 // smaller size with word-break so the 42-char string lays
 // out cleanly across 2 lines if needed instead of being
 // truncated to `bc1q48tx...avsx`.
          { label: "DEPLOYER", value: token.deployer || "—", color: "var(--hxm-text-dim)", title: token.deployer || "", mono: true },
        ].map((cell, i) => (
          <div key={i} style={{
            padding: "10px 12px",
            background: "rgba(0,0,0,0.45)",
            border: "1px solid var(--hxm-line)",
            borderRadius: 4,
          }}>
            <div className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-mute)", letterSpacing: "0.22em", marginBottom: 4 }}>
              {cell.label}
            </div>
            <div
              className={cell.mono ? "hxm-mono" : undefined}
              style={{
                fontSize: cell.mono ? 10.5 : 13,
                color: cell.color,
                wordBreak: cell.mono ? "break-all" : undefined,
                lineHeight: cell.mono ? 1.45 : undefined,
              }}
              title={cell.title}
            >
              {cell.value}
            </div>
          </div>
        ))}
      </div>

      {/* Holders table — same .hxm-bordered chrome as the INDEX list */}
      <div className="hxm-bordered" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{
          display: "grid",
          gridTemplateColumns: "60px 1fr 160px 90px",
          gap: 10, alignItems: "center",
          padding: "12px 14px",
          borderBottom: "1px solid var(--hxm-line-2)",
          background: "rgba(0,0,0,0.35)",
          fontFamily: "'Bebas Neue', sans-serif",
          fontSize: 11, color: "var(--hxm-text-dim)", letterSpacing: "0.20em",
        }}>
          <span>RANK</span>
          <span>ADDRESS</span>
          <span style={{ textAlign: "right" }}>BALANCE</span>
          <span style={{ textAlign: "right" }}>% SUPPLY</span>
        </div>

        {loading && (
          <div style={{ padding: 32, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 12 }}>
            <RefreshCw size={12} className="btx-spin" style={{ verticalAlign: "-2px", marginRight: 6 }} />
            fetching holders from indexer…
          </div>
        )}
        {err && !loading && (
          <div style={{ padding: 24, textAlign: "center", color: "var(--hxm-red)", fontSize: 11.5, lineHeight: 1.55 }}>
            indexer fetch failed: {err}
            <div style={{ marginTop: 6, fontSize: 10, color: "var(--hxm-text-mute)" }}>
              The indexer sidecar auto-starts at boot — restart the app to retry,
              or check that port 8765 isn't already in use.
            </div>
          </div>
        )}
        {!loading && !err && holders.length === 0 && (
          <div style={{ padding: 32, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 12, lineHeight: 1.6 }}>
            {(() => {
 // Three distinct empty-state cases the user can land in:
 // 1. Indexer is genuinely behind (indexed < tip) → show
 // catch-up status + auto-retry hint.
 // 2. Indexer is FULLY synced (indexed >= tip) but the
 // token isn't in its registry. Either:
 // a. The deploy block is below LCKPROTOCOL_START_HEIGHT
 // — protocol rejects it permanently. Most likely
 // cause: token was minted under the old 948,650
 // activation height (cohort v2) and is now
 // invalid under v3 (949,375).
 // b. The deploy is in mempool / not yet confirmed.
 // In that case the user JUST broadcast it; the
 // local state has it but no indexer sees it yet.
 // 3. Token IS indexed but no holders → genuine zero-state.
              const indexerCaughtUp = tipHeight > 0 && indexedHeight >= tipHeight;
              const deployBlock = token.deployedBlock;
              const preActivation = deployBlock != null && deployBlock < 948_785;

              if (indexed) {
                return <>No holders yet — token is deployed but no MINE has settled with a positive balance.</>;
              }
              if (preActivation) {
                return (
                  <>
                    <AlertCircle size={12} style={{ verticalAlign: "-2px", marginRight: 6, color: "var(--hxm-red)" }} />
                    <span style={{ color: "var(--hxm-red)" }}>
                      Pre-activation token — deployed at block #{deployBlock.toLocaleString()},
                      below the protocol activation height #949,375.
                    </span>
                    <div style={{ marginTop: 6, fontSize: 10.5, color: "var(--hxm-text-mute)", maxWidth: 420, margin: "6px auto 0" }}>
                      The LUCKYPROTOCOL protocol no longer recognizes this token. Your local
                      balance is stale — DEPLOY a new token after the activation height
                      to mint fresh tokens that the global indexer will track.
                    </div>
                  </>
                );
              }
              if (indexerCaughtUp) {
                return (
                  <>
                    <AlertCircle size={12} style={{ verticalAlign: "-2px", marginRight: 6, color: "var(--hxm-amber)" }} />
                    <span style={{ color: "var(--hxm-amber)" }}>
                      Token not found in the global registry — indexer is fully synced.
                    </span>
                    <div style={{ marginTop: 6, fontSize: 10.5, color: "var(--hxm-text-mute)", maxWidth: 420, margin: "6px auto 0" }}>
                      Most likely the DEPLOY tx is still in mempool (not yet confirmed).
                      It will appear here automatically once it lands in a block.
                      indexed {indexedHeight.toLocaleString()} / {tipHeight.toLocaleString()}
                    </div>
                  </>
                );
              }
 // Case 1: indexer still behind tip
              return (
                <>
                  <RefreshCw size={12} className="btx-spin" style={{ verticalAlign: "-2px", marginRight: 6, color: "var(--hxm-amber)" }} />
                  <span style={{ color: "var(--hxm-amber)" }}>
                    Indexer is still backfilling — this token's deploy hasn't been scanned yet.
                  </span>
                  {tipHeight > 0 && (
                    <div style={{ marginTop: 6, fontSize: 10, color: "var(--hxm-text-mute)" }}>
                      indexed {indexedHeight.toLocaleString()} / {tipHeight.toLocaleString()}
                      · {(tipHeight - indexedHeight).toLocaleString()} blocks behind · auto-retry every 4s
                    </div>
                  )}
                </>
              );
            })()}
          </div>
        )}
        {!loading && !err && holders.map((h, i) => {
          const isMine = ownAddress && h.address === ownAddress;
          const pct = supply > 0 ? (h.balance / supply) * 100 : 0;
          return (
            <div key={h.address} style={{
              display: "grid",
              gridTemplateColumns: "60px 1fr 160px 90px",
              gap: 10, alignItems: "center",
              padding: "10px 14px",
              borderTop: "1px solid var(--hxm-line)",
              background: isMine ? "rgba(212,162,58,0.06)" : "transparent",
            }}>
              <span className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-text-mute)" }}>
 #{page * PAGE_SIZE + i + 1}
              </span>
              <span
                className="hxm-mono"
                style={{
                  fontSize: 11.5,
                  color: isMine ? "var(--hxm-gold-bright)" : "var(--hxm-text)",
                  wordBreak: "break-all",
                  lineHeight: 1.4,
                }}
                title={h.address}
              >
                {h.address}
                {isMine && (
                  <span className="hxm-bebas" style={{
                    fontSize: 9, color: "var(--hxm-gold-bright)",
                    letterSpacing: "0.2em", marginLeft: 8,
                    padding: "1px 5px",
                    border: "1px solid rgba(212,162,58,0.55)",
                    borderRadius: 2,
                  }}>
                    YOU
                  </span>
                )}
              </span>
              <span className="hxm-mono" style={{
                fontSize: 12.5, fontWeight: 600,
                color: "var(--hxm-gold-bright)",
                textAlign: "right",
              }}>
                {fmt(h.balance)}
              </span>
              <span className="hxm-mono" style={{
                fontSize: 11,
                color: pct >= 1 ? "var(--hxm-amber)" : "var(--hxm-text-dim)",
                textAlign: "right",
              }}>
                {pct < 0.01 ? "<0.01" : pct.toFixed(2)}%
              </span>
            </div>
          );
        })}

        {/* Pagination strip — only shown when there's more than one
            page's worth of holders. Prev / Next around a centered
            "Page A of B · N holders" indicator. Disabled state keys
            off page bounds + loading so the user can't fire a
            request that's already in flight. */}
        {!loading && !err && total > PAGE_SIZE && (() => {
          const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
          const atFirst = page <= 0;
          const atLast = page >= totalPages - 1;
          const rangeStart = page * PAGE_SIZE + 1;
          const rangeEnd = Math.min(total, rangeStart + holders.length - 1);
          return (
            <div style={{
              padding: "10px 14px",
              borderTop: "1px solid var(--hxm-line)",
              display: "flex", alignItems: "center", justifyContent: "space-between",
              gap: 12,
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: 10.5, color: "var(--hxm-text-dim)",
            }}>
              <button
                onClick={() => setPage((p) => Math.max(0, p - 1))}
                disabled={atFirst || loading}
                className="btx-btn-ghost"
                style={{
                  padding: "4px 10px", fontSize: 10,
                  opacity: atFirst || loading ? 0.4 : 1,
                  cursor: atFirst || loading ? "not-allowed" : "pointer",
                  display: "inline-flex", alignItems: "center", gap: 4,
                }}
              >
                <ChevronLeft size={11} /> PREV
              </button>
              <div style={{ textAlign: "center", lineHeight: 1.5 }}>
                <div>page {page + 1} / {totalPages}</div>
                <div style={{ fontSize: 9, color: "var(--hxm-text-mute)" }}>
                  showing #{rangeStart.toLocaleString()}–#{rangeEnd.toLocaleString()} of {total.toLocaleString()}
                </div>
              </div>
              <button
                onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                disabled={atLast || loading}
                className="btx-btn-ghost"
                style={{
                  padding: "4px 10px", fontSize: 10,
                  opacity: atLast || loading ? 0.4 : 1,
                  cursor: atLast || loading ? "not-allowed" : "pointer",
                  display: "inline-flex", alignItems: "center", gap: 4,
                }}
              >
                NEXT <ChevronRight size={11} />
              </button>
            </div>
          );
        })()}
      </div>
    </div>
  );
}

function DashboardHero() {
  return (
    <div style={{
      position: "relative",
      borderRadius: 14,
      overflow: "hidden",
      border: "1px solid var(--hxm-line-2)",
      boxShadow: "0 8px 30px -8px rgba(0,0,0,0.6), inset 0 0 0 1px rgba(212,162,58,0.18)",
      lineHeight: 0,
      // Flex-grow inside the Dashboard column: GameCards sit at their
      // natural compact height (~400px); Hero soaks up the rest of the
      // viewport. minHeight floors it at 200.
      flex: 1,
      minHeight: 200,
    }}>
      <img
        src={BRAND_BANNER_SRC}
        alt="LuckyProtocol — Proof of Luck"
        style={{
          width: "100%",
          height: "100%",
          display: "block",
          // cover = fill the whole frame edge-to-edge, cropping
          // whichever dimension is in excess. The banner is 1983×793
          // (≈ 2.5:1). At wider Dashboard windows the frame is more
          // square than the image, so cover scales to fit width and
          // crops VERTICALLY. We anchor the image's TOP at the frame's
          // top — that preserves the curtain + sparkles strip above
          // the LUCKY MINER wordmark, giving it visible breathing
          // room instead of butting straight against the frame edge.
          // (The cost is the bottom-most feature-callout strip
          // gets trimmed at very wide frame aspects — acceptable
          // trade since the slot machine + chips remain the visual
          // anchor of the banner.)
          objectFit: "cover",
          objectPosition: "center top",
        }}
        draggable={false}
      />
      {/* faint inner gold rim for integration with the casino UI */}
      <div style={{
        position: "absolute", inset: 0, pointerEvents: "none",
        boxShadow: "inset 0 0 40px rgba(0,0,0,0.35)",
        borderRadius: 14,
      }} />
    </div>
  );
}

function GameCard({ tier, state, onPlay }) {
 // Use the centralized predicate so this count is guaranteed to
 // match the room's chip strip and ALMANAC's tier dropdown.
  const eligibleList = eligibleChipUtxos(state.wallet.utxos, tier);
  const eligible = eligibleList.length;
  const totalConfirmedBtc = confirmedBtcUtxos(state.wallet.utxos).length;
  const metalClass = tier.key === "iron" ? "metal-iron"
    : tier.key === "bronze" ? "metal-bronze"
    : tier.key === "silver" ? "metal-silver"
    : "metal-gold";
  const Preview = tier.key === "iron" ? CardPreview : tier.key === "bronze" ? RoulettePreview : tier.key === "silver" ? DoubleDrawPreview : SlotPreview;
  return (
    <div className="hxm-bordered" style={{
      padding: "18px 16px 16px",
      borderColor: "var(--hxm-line-2)",
      borderRadius: 10,
      display: "flex", flexDirection: "column",
      height: "100%",
    }}>
      {/* Title block — ONLY the tier name uses its metal gradient (luxury accent) */}
      <div style={{ textAlign: "center", marginBottom: 12 }}>
        <div className={`hxm-cinzel ${metalClass}`} style={{
          fontSize: 30, fontWeight: 900, letterSpacing: "0.16em", lineHeight: 1,
        }}>
          {tier.label}
        </div>
        <div className="hxm-bebas" style={{
          fontSize: 11, color: "var(--hxm-text-dim)", letterSpacing: "0.28em", marginTop: 6,
          height: 14, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
        }}>
          {tier.game}
        </div>
      </div>

      {/* Image preview — fixed 170px so all cards align and the roulette /
          slot / dice cup / poker-table previews stay at their tuned
          sprite-perfect size. Hero takes care of filling the rest of
          the viewport, so we don't need to grow the preview slot here. */}
      <div style={{
        height: 170, position: "relative",
        background: "radial-gradient(ellipse 80% 80% at 50% 60%, rgba(0,0,0,0.5), transparent 70%)",
        display: "flex", alignItems: "center", justifyContent: "center",
        marginBottom: 10,
      }}>
        <Preview tier={tier} />
      </div>

      {/* Stats — single-line values, identical gold treatment */}
      <div style={{
        display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8,
        padding: "12px 0", borderTop: "1px solid var(--hxm-line)", borderBottom: "1px solid var(--hxm-line)",
      }}>
        <div style={{ textAlign: "center" }}>
          <div className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.18em" }}>ODDS</div>
          <div className="hxm-mono" style={{ fontSize: 14, color: "var(--hxm-gold-bright)", fontWeight: 500, whiteSpace: "nowrap", marginTop: 3 }}>
            {tier.probability}
          </div>
        </div>
        <div style={{ textAlign: "center", borderLeft: "1px solid var(--hxm-line)" }}>
          <div className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.18em" }}>REWARD</div>
          <div className="hxm-mono" style={{ fontSize: 14, color: "var(--hxm-gold-bright)", fontWeight: 500, whiteSpace: "nowrap", marginTop: 3 }}>
            {fmt(tier.reward)} {state.wallet.tokenTicker || <span style={{ color: "var(--hxm-text-mute)" }}>?</span>}
          </div>
        </div>
      </div>

      {/* CTA — uniform gold treatment across all tiers */}
      <div style={{ marginTop: "auto" }}>
        <button className="hxm-btn-cta" onClick={onPlay} style={{
          width: "100%", marginTop: 14,
          padding: "12px 16px",
          borderColor: "var(--hxm-line-2)",
          color: "var(--hxm-gold-bright)",
          whiteSpace: "nowrap",
        }}>
          MINE {tier.label}
        </button>
        {/* "X / Y eligible" makes the relationship explicit when the
            user has dust UTXOs below the chip threshold (Y > X). */}
        <div style={{ textAlign: "center", marginTop: 8, fontSize: 10, color: eligible > 0 ? "var(--hxm-green-dim)" : "var(--hxm-red-dim)" }}>
          {eligible > 0
            ? (totalConfirmedBtc > eligible
                ? `${eligible} / ${totalConfirmedBtc} eligible UTXOs`
                : `${eligible} eligible UTXO${eligible > 1 ? "s" : ""}`)
            : "no eligible UTXO — fund wallet"}
        </div>
      </div>
    </div>
  );
}

// game card mini-previews
// Real game previews — each shows the actual asset used in the room itself,
// so the dashboard card matches what the player will see when they click in.

function CardPreview() {
 // Iron room = SicBo dice cup (overhead view of the gilded ruby cup).
 // Fixed 160×160 to match the GameCard preview slot (170px).
  return (
    <div style={{ position: "relative", width: 160, height: 160 }}>
      <img
        src={ASSETS.dice_cup}
        alt="dice cup"
        style={{
          width: "100%", height: "100%",
          objectFit: "contain",
          filter: "drop-shadow(0 10px 20px rgba(0,0,0,0.75))",
        }}
      />
    </div>
  );
}

function RoulettePreview() {
 // Bronze room = roulette wheel. PNG has a square black background + a
 // few px of black padding around the gold frame — clip to a tight
 // circle (matches BronzeRoom's.roulette-frame clip-path).
  return (
    <div style={{ position: "relative", width: 160, height: 160 }}>
      <img
        src={rouletteV2}
        alt="roulette"
        style={{
          width: "100%", height: "100%",
          objectFit: "contain",
          clipPath: "circle(48% at 50% 50%)",
          filter: "drop-shadow(0 10px 20px rgba(0,0,0,0.75))",
        }}
      />
    </div>
  );
}

function DoubleDrawPreview() {
 // Silver room = poker table with face-down cards fanned across it.
 // Wider than tall (poker table is landscape); 230×155 fits the 170px
 // GameCard preview slot proportionally.
  return (
    <div style={{ position: "relative", width: 230, height: 155 }}>
      <img
        src={ASSETS.silver_table}
        alt="poker table"
        style={{
          width: "100%", height: "100%",
          objectFit: "contain",
          filter: "drop-shadow(0 8px 16px rgba(0,0,0,0.65))",
        }}
      />
      {/* fanned face-down cards on the felt */}
      {[-12, -4, 4, 12].map((rot, i) => (
        <img key={i}
          src={cardBackV2}
          alt=""
          style={{
            position: "absolute",
            left: `calc(50% + ${(i - 1.5) * 15}px)`,
            top: "42%",
            width: 28, height: 42,
            transform: `translate(-50%, -50%) rotate(${rot}deg)`,
            borderRadius: 3,
            boxShadow: "0 4px 8px rgba(0,0,0,0.6)",
          }}
        />
      ))}
    </div>
  );
}

function SlotPreview() {
 // Gold room = slot machine cabinet. Fixed 160×160 matches the 170px
 // GameCard preview slot.
  return (
    <div style={{ position: "relative", width: 160, height: 160 }}>
      <img
        src={ASSETS.slot_body}
        alt="slot machine"
        style={{
          width: "100%", height: "100%",
          objectFit: "contain",
          filter: "drop-shadow(0 10px 20px rgba(0,0,0,0.75))",
        }}
      />
    </div>
  );
}

// =============================================================================
// BOTTOM TRIPLE — Recent Rounds + Settlement Feed + Performance chart
// =============================================================================
// =============================================================================
// BOTTOM PAIR — Recent Rounds + Settlement Feed
// =============================================================================
function BottomTriple({ state, screenFilter }) {
  const filtered = screenFilter ? state.recentMines.filter((m) => m.tier === screenFilter) : state.recentMines;
  return (
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginTop: 18, marginBottom: 18 }}>
      <RecentRoundsPanel state={state} mines={filtered} screenFilter={screenFilter} />
      <SettlementFeedPanel state={state} mines={filtered} />
    </div>
  );
}

function RecentRoundsPanel({ state, mines, screenFilter }) {
  const showCols = screenFilter === "iron"
    ? ["round", "pick", "next", "result", "payout"]
    : screenFilter === "silver"
    ? ["round", "left", "right", "result", "payout"]
    : screenFilter === "bronze"
    ? ["round", "picked", "winning", "result", "payout"]
    : screenFilter === "gold"
    ? ["round", "pick", "result", "payout", "earned"]
    : ["round", "game", "result", "payout", "earned"];
  return (
    <div className="hxm-panel">
      <div className="hxm-panel-head">
        <Activity size={13} color="var(--hxm-gold)" />
        <span>RECENT ROUNDS</span>
        <button className="hxm-btn" style={{ marginLeft: "auto", fontSize: 9, padding: "4px 8px" }}>VIEW ALL</button>
      </div>
      <div className="hxm-panel-body" style={{ padding: 0 }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ borderBottom: "1px solid var(--hxm-line)" }}>
              {showCols.map((c) => (
                <th key={c} className="hxm-bebas" style={{
                  padding: "8px 10px", textAlign: "left", fontSize: 10,
                  color: "var(--hxm-text-dim)", letterSpacing: "0.18em", fontWeight: 400,
                }}>{c.toUpperCase()}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {mines.length === 0 && (
              <tr><td colSpan={showCols.length} style={{ padding: 18, textAlign: "center", color: "var(--hxm-text-mute)", fontStyle: "italic", fontSize: 11 }}>
                no rounds yet
              </td></tr>
            )}
            {mines.slice(0, 5).map((m, i) => {
              const T = TIERS[m.tier];
 // iron now shows the single die value derived from last hex
              const tail = m.target_hash ? m.target_hash.slice(
                - (m.tier === "silver" ? 2 : m.tier === "gold" ? 3 : 1)
              ) : "";
              const win = m.status === "win";
              const payoutMult = m.tier === "iron" ? 2
                : m.tier === "bronze" ? 16 : m.tier === "silver" ? 256 : 4096;
              const ironPickGlyph = { odd: "ODD", even: "EVEN" }[m.pick] || "?";
              const ironPickColor = m.pick === "even" ? "var(--hxm-red)" : "var(--hxm-green)";
              const ironDieVal = m.target_hash ? diceFromHash(m.target_hash) : "—";
              return (
                <tr key={i} style={{ borderBottom: "1px solid rgba(212,162,58,0.08)" }}>
                  <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 11, color: "var(--hxm-text-mute)" }}>#{m.confirmed_block || ""}</td>
                  {screenFilter === null && (
                    <td style={{ padding: "7px 10px", fontSize: 11 }}>
                      <span style={{ display: "inline-flex", alignItems: "center", gap: 5 }}>
                        <span style={{
                          width: 6, height: 6, borderRadius: "50%", background: T.accent,
                        }} /> {T.label.charAt(0) + T.label.slice(1).toLowerCase()} {T.game.split(" ")[0].toLowerCase().replace(/^./, c => c.toUpperCase())}
                      </span>
                    </td>
                  )}
                  {screenFilter === "iron" && (
                    <>
                      <td style={{ padding: "7px 10px", fontSize: 11 }}>
                        <span style={{ color: ironPickColor, fontWeight: 500 }}>
                          {ironPickGlyph} {(m.pick || "").toUpperCase()}
                        </span>
                      </td>
                      <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 11, color: "var(--hxm-text)" }}>
                        {ironDieVal}
                      </td>
                    </>
                  )}
                  {screenFilter === "silver" && (
                    <>
                      <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 12, color: win ? "var(--hxm-green)" : "var(--hxm-text)", textAlign: "center" }}>{m.pick[0].toUpperCase()}</td>
                      <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 12, color: win ? "var(--hxm-green)" : "var(--hxm-text)", textAlign: "center" }}>{m.pick[1].toUpperCase()}</td>
                    </>
                  )}
                  {screenFilter === "bronze" && (
                    <>
                      <td style={{ padding: "7px 10px", fontSize: 11 }}>
                        <HexCellMini char={m.pick} highlight={false} />
                      </td>
                      <td style={{ padding: "7px 10px", fontSize: 11 }}>
                        <HexCellMini char={tail} highlight={win} />
                      </td>
                    </>
                  )}
                  {screenFilter === "gold" && (
                    <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 12, color: win ? "var(--hxm-green)" : "var(--hxm-text)" }}>
                      {m.pick.toUpperCase()} {win && <Award size={10} color="var(--hxm-gold-bright)" style={{ display: "inline", verticalAlign: "-1px" }} />}
                    </td>
                  )}
                  <td style={{ padding: "7px 10px", fontSize: 11 }}>
                    <span style={{
                      color: win ? "var(--hxm-green)" : "var(--hxm-red)",
                      fontFamily: "'Bebas Neue', sans-serif", letterSpacing: "0.15em",
                    }}>
                      {win ? "✓ WIN" : "✗ LOSS"}
                    </span>
                  </td>
                  <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 11, textAlign: "right",
                    color: win ? "var(--hxm-green)" : "var(--hxm-text-mute)" }}>
                    {win ? `${payoutMult}.00x` : "0.00x"}
                  </td>
                  {(screenFilter === null || screenFilter === "gold") && (
                    <td className="hxm-mono" style={{ padding: "7px 10px", fontSize: 11, textAlign: "right",
                      color: win ? "var(--hxm-green)" : "var(--hxm-text-mute)" }}>
                      {win ? `+${(m.reward / 100000).toFixed(8)}` : "0.0000"}
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function HexCellMini({ char, highlight }) {
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", justifyContent: "center",
      width: 24, height: 24,
      clipPath: "polygon(30% 0%, 70% 0%, 100% 30%, 100% 70%, 70% 100%, 30% 100%, 0% 70%, 0% 30%)",
      background: highlight ? "linear-gradient(180deg, #f9e082, #d4af37)" : "linear-gradient(180deg, #2a0c0c, #150506)",
      color: highlight ? "#1a0a00" : "var(--hxm-gold-bright)",
      fontFamily: "'Cinzel', serif", fontWeight: 700, fontSize: 11,
      border: highlight ? "none" : `1px solid var(--hxm-line-2)`,
    }}>
      {char.toUpperCase()}
    </span>
  );
}

function SettlementFeedPanel({ state, mines }) {
  return (
    <div className="hxm-panel">
      <div className="hxm-panel-head">
        <Layers size={13} color="var(--hxm-gold)" />
        <span>SETTLEMENT FEED</span>
        <span className="live">LIVE</span>
      </div>
      <div className="hxm-panel-body" style={{ padding: "8px 10px" }}>
        {mines.length === 0 ? (
          <div style={{ padding: 18, textAlign: "center", color: "var(--hxm-text-mute)", fontStyle: "italic", fontSize: 11 }}>
            waiting for next settlement…
          </div>
        ) : (
          mines.slice(0, 5).map((m, i) => {
            const T = TIERS[m.tier];
            const win = m.status === "win";
            return (
              <div key={i} style={{
                display: "flex", alignItems: "center", gap: 10,
                padding: "5px 4px",
                borderBottom: "1px solid rgba(212,162,58,0.06)",
                fontSize: 11,
              }}>
                <span className="hxm-mono" style={{ color: "var(--hxm-text-mute)", minWidth: 60, fontSize: 10 }}>
                  23:5{8 - i}:{(60 - i * 7).toString().padStart(2, "0")}
                </span>
                <span className="hxm-mono" style={{ color: "var(--hxm-text)", minWidth: 80, fontSize: 11 }}>#{m.confirmed_block || ""}</span>
                <span style={{ display: "inline-flex", alignItems: "center", gap: 5, color: T.accent, minWidth: 100, fontSize: 11 }}>
                  <span style={{ width: 5, height: 5, borderRadius: "50%", background: T.accent }} />
                  {T.label.charAt(0) + T.label.slice(1).toLowerCase()}
                </span>
                <span style={{
                  fontFamily: "'Bebas Neue', sans-serif", letterSpacing: "0.15em",
                  color: win ? "var(--hxm-green)" : "var(--hxm-red)", fontSize: 10,
                }}>{win ? "WIN" : "LOSS"}</span>
                <span className="hxm-mono" style={{
                  marginLeft: "auto", fontSize: 11,
                  color: win ? "var(--hxm-green)" : "var(--hxm-text-mute)",
                }}>
                  {win ? `+${(m.reward / 100000).toFixed(5)}` : "+0.00000"} BTC
                </span>
              </div>
            );
          })
        )}
        <div style={{ marginTop: 8, textAlign: "center" }}>
          <button className="hxm-btn" style={{ width: "100%", justifyContent: "center", fontSize: 11 }}>
            VIEW FULL FEED
          </button>
        </div>
      </div>
    </div>
  );
}

// =============================================================================
// ROOM SHELL (header + nav between rooms)
// =============================================================================
function RoomShell({ tier, children, goRoom, goDashboard }) {
  return (
    <div className="btx-screen">
      {/* Room nav strip — DASHBOARD on the left, 4 tier buttons centered.
          marginBottom tightened from 8→0 to pull the table up further
          (per user repeated "[redacted] / [redacted]"). The
          tier buttons sit immediately above the room-scene with no
          extra gap. */}
      <div style={{
        display: "grid",
        gridTemplateColumns: "auto 1fr auto",
        alignItems: "center",
        gap: 12,
        marginBottom: 0,
 // Force the tier-switch row above the room-scene's z-index
 // stack. Without this, the spinning roulette / dice / cards
 // / slot art can render with elements that intercept clicks
 // intended for the IRON / BRONZE / SILVER / GOLD buttons —
 //. `position: relative`
 // is required for `z-index` to take effect on a non-positioned
 // grid container.
        position: "relative",
        zIndex: 10,
      }}>
        <button className="hxm-btn" onClick={goDashboard}>
          <ChevronRight size={11} style={{ transform: "rotate(180deg)" }} />
          DASHBOARD
        </button>
        <div style={{ display: "flex", justifyContent: "center", gap: 10, flexWrap: "wrap" }}>
          {Object.values(TIERS).map((T) => {
            const isActive = T.key === tier.key;
            return (
              <button
                key={T.key}
                onClick={() => goRoom(T.key)}
                className={`hxm-tier-btn hxm-cinzel ${isActive ? "is-active" : ""}`}
                style={{
 /* Solid metal color (the brightest highlight from the
                     tier's palette) so the text reads cleanly on dark
                     velvet. The metal-{tier} foil-clip-text trick we
                     tried earlier rendered the gradient ONLY where text
                     pixels are — invisible at 14px on dark bg. */
                  color: T.metalA,
                  textShadow: `0 1px 0 rgba(0,0,0,0.85), 0 0 10px ${T.accent}55`,
                  borderColor: isActive ? T.accent : "var(--hxm-line-2)",
                  boxShadow: isActive
                    ? `0 0 20px ${T.accent}66, inset 0 0 0 1px ${T.accent}88`
                    : `inset 0 1px 0 rgba(255,255,255,0.08)`,
                }}
                title={T.game}
              >
                {T.label}
              </button>
            );
          })}
        </div>
        <span aria-hidden="true" style={{ width: 110 }} />
      </div>

      {/* Game scene — bet history moved out to the right sidebar
          (SidebarRight in App.tsx) so the room reverts to its original
          centered layout per the user's "old layout" feedback. */}
      {children}
    </div>
  );
}

function RoomHeroTitle({ tier }) {
  const cls = tier.key === "iron" ? "metal-iron" : tier.key === "bronze" ? "metal-bronze" : tier.key === "silver" ? "metal-silver" : "metal-gold";
  return (
    <div style={{ textAlign: "center", padding: "8px 0 18px" }}>
      <div className={`hxm-cinzel ${cls}`} style={{
        fontSize: 64, fontWeight: 900, letterSpacing: "0.14em", lineHeight: 1,
      }}>
        {tier.label}
      </div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 14, marginTop: 6 }}>
        <span className="gold-rule" style={{ width: 80 }} />
        <div className="hxm-bebas" style={{ fontSize: 15, color: "var(--hxm-gold-bright)", letterSpacing: "0.32em" }}>
          ◆ {tier.game} ◆
        </div>
        <span className="gold-rule" style={{ width: 80 }} />
      </div>
    </div>
  );
}

