function CurrentPickPanel({ value, label = "CURRENT PICK", subtitle, locked }) {
  return (
    <div className="hxm-bordered" style={{ padding: "16px 14px", minWidth: 180, textAlign: "center" }}>
      <div className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.32em" }}>{label}</div>
      {value ? (
        <div className="hxm-cinzel" style={{
          fontSize: 36, fontWeight: 900, color: "var(--hxm-gold-bright)", marginTop: 6, letterSpacing: "0.05em",
          textShadow: "0 2px 0 #1a0a00, 0 0 18px rgba(245,220,137,0.5)",
        }}>{String(value).toUpperCase()}</div>
      ) : (
        <div className="hxm-cinzel" style={{ fontSize: 30, color: "var(--hxm-text-mute)", marginTop: 6 }}>--</div>
      )}
      <div style={{ marginTop: 6, fontSize: 11, color: locked ? "var(--hxm-green)" : "var(--hxm-text-dim)" }}>
        {locked ? <><Lock size={11} style={{ display: "inline", verticalAlign: "-2px", marginRight: 4 }}/>Locked</> : (subtitle || "Not Locked")}
      </div>
    </div>
  );
}

function UTXOSelectStrip({ state, tier, value, onChange, exitingUtxoKeys }) {
 // Game tables only accept plain BTC UTXOs that are confirmed. Token-bearing
 // UTXOs would burn the token if used as a buy-in; pending UTXOs would be
 // rejected by the protocol's confs >= 1 guard at settle time.
 // Sorted ascending so the default chip selection (eligible[0]) is the
 // smallest above the tier threshold —
 //. Users can still pick a bigger chip from the strip, but the
 // initial visual cue is "spend the smallest available unit".
  const eligible = eligibleChipUtxos(state.wallet.utxos, tier);

 // VISUAL ORDER STABILITY — append-only ordering.
 // Without this, `eligible` re-sorts by sats on every render. A new
 // smaller UTXO arriving mid-game (e.g. change UTXO from a previous
 // settle, fresh chain refresh, dust drop) would sort to position 0,
 // shoving the user's currently-selected chip one slot to the right.
 // `recv` (== `value` here) stays correctly pinned to the SAME UTXO,
 // so the gold "is-selected" glow physically follows that chip — but
 // from the user's POV the chip at position-0 just stopped glowing
 // and the glow "jumped" to position-1. Reported as
 // Fix: maintain a stable visual order in a ref. Existing chips keep
 // their original slot; brand-new chips append to the tail (sorted
 // sats-asc internally so a batch arrival reads small→large within
 // the tail). Spent / no-longer-eligible chips drop out of the order,
 // and everything to their right collapses left to fill the gap (this
 // last bit IS expected — the gap left by a consumed chip should
 // close, that's normal layout behavior the user reads as "chip got
 // played").
 // The `eligible[0]`-based default-selection logic in each room's
 // useEffect (e.g. IronRoom line 10177) still references the sats-
 // sorted array, so the auto-pick-smallest behavior on first mount /
 // post-spend snap-back is unchanged. Stability is purely a render
 // concern.
  const orderRef = useRef([]);
  const eligibleByKey = new Map(eligible.map((u) => [utxoKey(u), u]));
  const eligibleKeySet = new Set(eligibleByKey.keys());
  const kept = orderRef.current.filter((k) => eligibleKeySet.has(k));
  const known = new Set(kept);
  const additions = eligible
    .filter((u) => !known.has(utxoKey(u)))
    .sort((a, b) => a.sats - b.sats)
    .map(utxoKey);
  orderRef.current = additions.length > 0 || kept.length !== orderRef.current.length
    ? [...kept, ...additions]
    : orderRef.current;
  const ordered = orderRef.current
    .map((k) => eligibleByKey.get(k))
    .filter(Boolean);
 // Map sats amount → chip art tier. Higher amount = fancier chip.
 // Chip tier by sats — logarithmic luxury progression. Each tier is ~20×
 // the next, so moving up a tier feels like a real step in stakes.
 // blue < 5,000 sat (< 0.00005 BTC) — entry
 // green < 100,000 sat (< 0.001 BTC) — standard
 // black < 1,000,000 sat (< 0.01 BTC) — mid
 // purple < 10,000,000 sat (< 0.1 BTC) — high roller
 // vip ≥ 10,000,000 sat (≥ 0.1 BTC) — whale
  const chipFor = (sats) => {
    if (sats >= 10000000) return ASSETS.chip_vip;     // ≥ 0.1 BTC — VIP red/green/black mix
    if (sats >= 1000000)  return ASSETS.chip_purple;  // ≥ 0.01 BTC — purple amethyst
    if (sats >= 100000)   return ASSETS.chip_black;   // ≥ 0.001 BTC — black obsidian
    if (sats >= 5000)     return ASSETS.chip_green;   // ≥ 5K sat — emerald green
    return ASSETS.chip_blue;                           // < 5K sat — blue sapphire
  };
 // Show full sats up to 9 digits (≤ 999,999,999); switch to BTC at 10+ digits.
 // 999,999,999 sat ≈ 10 BTC — bigger than that gets compressed to BTC unit.
  const formatChip = (sats) => {
    if (sats <= 999999999) {
      return { value: sats.toLocaleString('en-US'), unit: 'SATOSHI' };
    }
    const btc = sats / 1e8;
    let str;
    if (btc >= 100)      str = btc.toFixed(2);
    else if (btc >= 10)  str = btc.toFixed(3);
    else                 str = btc.toFixed(4);
    if (str.indexOf('.') !== -1) {
      str = str.replace(/0+$/, '').replace(/\.$/, '');
    }
    return { value: str, unit: 'BTC' };
  };
 // ₿ chip watermark moved out of the React tree — it's now baked
 // into `.utxo-chip` as a background-image data URI (see
 // BTC_CHIP_WATERMARK_SVG above CasinoCss). That folds it into the
 // same paint surface as the chip art so chip transforms (hover /
 // selected scale, MINE throw-out) move the glyph in lockstep with
 // the art, with no per-element subpixel jitter.
  return (
    <div>
      <div className="hxm-bebas" style={{ fontSize: 10, color: "var(--hxm-text-dim)", letterSpacing: "0.22em", marginBottom: 6 }}>
        BUY-IN UTXO
      </div>
      {ordered.length === 0 ? (
        <div style={{ padding: "10px 12px", color: "var(--hxm-red)", fontSize: 11, border: "1px dashed rgba(229,75,75,0.4)", borderRadius: 6 }}>
          <AlertCircle size={11} style={{ display: "inline", verticalAlign: "-1px", marginRight: 5 }}/>
          No UTXO meets the {fmt(tier.threshold)} sat threshold for {tier.label}
        </div>
      ) : (
 // Scrollable chip rack. Selected chips scale to 1.05 (no
 // translate) plus a tight 4px drop-shadow halo — total
 // overflow is ~5% × half-radius ≈ 2-3px each side, plus 4px
 // halo = 6-8px max in any direction. 8px padding all around
 // is enough breathing room; nothing clips at the cell edges.
 // PERFORMANCE CAP. When the wallet has hundreds
 // of UTXOs, rendering them all as <button> nodes — each with
 // a background-image, container-query, click handler — would
 // tank the room's frame rate. Cap visible chips at 80; user
 // can SPLIT / consolidate in the UTXO screen. The smallest-
 // first sort means the cap mostly cuts large idle UTXOs the
 // user wouldn't bet anyway.
        <div className="hxm-scroll" style={{
          maxHeight: 240,
          overflowY: "auto",
          padding: "8px 8px",
        }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(72px, 1fr))", gap: 10, justifyItems: "center" }}>
            {(() => {
              const CHIP_RENDER_CAP = 80;
              const visible = ordered.length > CHIP_RENDER_CAP
                ? ordered.slice(0, CHIP_RENDER_CAP)
                : ordered;
              return visible;
            })().map((u) => {
              const k = utxoKey(u);
              const sel = k === value;
              const exiting = !!(exitingUtxoKeys && exitingUtxoKeys.has && exitingUtxoKeys.has(k));
              const f = formatChip(u.sats);
              return (
                <div key={k} className="utxo-chip-wrap" style={{ width: "100%", maxWidth: 92 }}>
                  <button
                    className={`utxo-chip ${sel ? "is-selected" : ""} ${exiting ? "is-exiting" : ""}`}
                    onClick={() => exiting ? null : onChange(k)}
                    style={{ "--chip-bg": `url(${chipFor(u.sats)})` }}
                    title={`${k}\n${fmt(u.sats)} sat`}
                  >
                    <div
                      className="utxo-chip-amount"
                      style={{
 // Tiered scale: shorter = larger, longer = smaller.
 // Calibrated so even 11 chars stays inside the chip's gold center plate.
                        "--amount-scale":
                          f.value.length <= 3  ? "1.00" :
                          f.value.length <= 5  ? "0.80" :
                          f.value.length <= 7  ? "0.62" :
                          f.value.length <= 9  ? "0.48" :
                                                 "0.38",
                      }}
                    >{f.value}</div>
                    <div className="utxo-chip-unit">{f.unit}</div>
                  </button>
                </div>
              );
            })}
          </div>
          {ordered.length > 80 && (
            <div className="hxm-mono" style={{
              padding: "6px 10px", marginTop: 6,
              fontSize: 10, color: "var(--hxm-text-mute)", textAlign: "center",
              borderTop: "1px solid var(--hxm-line)",
            }}>
              Showing 80 of {ordered.length} eligible UTXOs · consolidate via the UTXO screen for the rest
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// pending bet readout
function BetActions({ pending, recv, onPlace, onSettle, settling, label }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      {!pending ? (
        <button className="hxm-btn-cta" onClick={onPlace} disabled={!recv}
          style={{ padding: "13px 18px", fontSize: 14 }}>
          PLACE BET
        </button>
      ) : (
        <button className="hxm-btn-cta glow" onClick={onSettle} disabled={settling}
          style={{ padding: "13px 18px", fontSize: 14 }}>
          <Zap size={13}/> {label}
        </button>
      )}
    </div>
  );
}

// =============================================================================
// ROOM BOTTOM ACTIONS — two equal-width buttons below the per-phase
// ROLL DIE / SPIN / etc. button stack. Identical UI in every room
// (Iron / Bronze / Silver / Gold) so the user sees the same controls
// regardless of tier:
// 1. MINE — broadcasts a real LUCKYPROTOCOL bet for THIS room's tier (pick is
// randomized at click time — same RNG semantics as the room's
// visual game). Disabled while a previous bet for the active token
// is still unsettled — that's thegate.
// 2. FEE — opens a small dropdown of fee-rate presets (1/5/10/20)
// plus a FETCH LIVE option that pulls the current recommended
// rate from mempool.space. The chosen rate is persisted via
// setFeeRateMock so every other screen sees the same value.
// =============================================================================
function RoomBottomActions({
  tier, state, submitMine, sessionPassword, setToast, onChainBets, walletMeta,
 // The room's currently-selected chip (utxoKey "txid:vout"). Threaded
 // through so the always-on MINE button at the bottom of the rail
 // honors the user's chip selection from the strip — without this
 // prop, MINE would pass `null` to submitMine and bdk_wallet's default
 // Branch-and-Bound coin-selector would pick the largest available
 // UTXO instead of the chip the user clicked. Optional: when the
 // caller doesn't provide it (or no chips are eligible), MINE is
 // disabled with a "select a chip" toast.
  recv,
 // Hide the always-on MINE row when the per-phase action button stack
 // already has its own MINE (i.e., the visual game's "rolled" state
 // where the user is locking in their pick). Keeps the right column
 // at three rows max — RE-ROLL / per-phase MINE / FEE — instead of
 // showing two MINE buttons stacked.
  hideMine,
}) {
 // Fee rate is kept as a string in state so the user can mid-type a
 // partial value like "1." without React jumping to NaN. Numeric reads
 // parseFloat at use sites with a "≥1" floor.
  const [feeRate, setFeeRate] = useState(() => String(getFeeRateMock() ?? "1"));
  const [busy, setBusy] = useState(false);

  const activeTicker = state?.wallet?.tokenTicker;
 //: the
 // MINE button no longer blocks on prior unsettled bets. Each bet
 // consumes its own UTXO and the indexer settles them independently;
 // chaining bets with different chips is fully safe at the protocol
 // layer. We keep `onChainBets` in scope for any future surfacing of
 // "N pending" status text but do not gate clicks on it.
  void onChainBets;

 // Pick a random valid pick for the current tier — protocol shape is
 // iron = odd|even, bronze = 1 hex, silver = 2 hex, gold = 3 hex.
  const randomPickFor = (key) => {
    if (key === "iron") return Math.random() < 0.5 ? "odd" : "even";
    const len = key === "bronze" ? 1 : key === "silver" ? 2 : 3;
    return Array.from({ length: len },
      () => HEX[Math.floor(Math.random() * 16)]).join("");
  };

 // MINE gate. the prior "wait for previous bet to
 // settle" lock is gone — each bet uses a distinct UTXO and the indexer
 // settles them independently. We still gate on:
 // - wallet unlocked (need sessionPassword to sign)
 // - active token selected (BET payload requires a ticker)
 // - chip selected (Rust pins it via add_utxo + manually_selected_only;
 // without recv, bdk's BnB would silently pick a larger UTXO)
 // - not currently busy (debounce against double-clicks)
  const mineDisabled = !sessionPassword || !activeTicker || !recv || busy;
  const mineReason = !sessionPassword
    ? "wallet locked"
    : !activeTicker
      ? "no mine target"
      : !recv
        ? "select a chip first"
        : null;

  const onMine = async () => {
    if (mineDisabled) {
      if (mineReason) setToast?.({ kind: "warn", msg: mineReason });
      return;
    }
    try { await setFeeRateMock(parseFloat(feeRate || "1") || 1); } catch {}
    setBusy(true);
    try {
      const pick = randomPickFor(tier.key);
 // Pass the user's selected chip (recv) so cmd_publish_bet in Rust
 // can pin it as the bet's input via add_utxo + manually_selected_only.
 // bdk's default coin-selector would otherwise prefer larger UTXOs.
      submitMine(tier.key, pick, recv);
    } finally {
      setTimeout(() => setBusy(false), 1500);
    }
  };

 // Persist whatever's in the input. Called from onChange + the +/- steppers
 // + FETCH LIVE so all three paths flow through the same persistence point.
 // Floor is 0.1 sat/vB — fractional rates are valid on mainnet during
 // empty-mempool windows where any-rate-relays accept sub-1 sat/vB fees.
  const writeFee = (next) => {
    const s = String(next);
    setFeeRate(s);
    const n = parseFloat(s);
    if (Number.isFinite(n) && n >= 0.1) {
      setFeeRateMock(n);
    }
  };
 // Stepper bumps by 0.1 sat/vB so the user can sweep through the
 // sub-1 range cleanly (0.1 → 0.2 →... → 1.0 → 1.1 →...).
  const bumpFee = (delta) => {
    const cur = parseFloat(feeRate || "1");
    const safe = Number.isFinite(cur) ? cur : 1;
 // Round to 1 decimal so +/- doesn't drift into floating-point noise.
    const next = Math.max(0.1, Math.round((safe + delta) * 10) / 10);
    writeFee(next);
  };

  const fetchLive = async () => {
    try {
      const fees = await chainFetchFees(walletMeta?.network || "bitcoin");
      const r = fees?.halfHourFee ?? fees?.fastestFee ?? 1;
      writeFee(r);
      setToast?.({ kind: "ok", msg: `fee rate updated to ${r} sat/vB` });
    } catch (e) {
      setToast?.({ kind: "err", msg: `fee fetch failed: ${String(e?.message ?? e).slice(0, 80)}` });
    }
  };

 // Stepper button — small square, used three times (−, +, ⚡).
  const stepBtn = (label, onClick, title) => (
    <button
      onClick={onClick}
      title={title}
      className="hxm-bebas"
      style={{
        width: 28, height: 28,
        flexShrink: 0,
        display: "flex", alignItems: "center", justifyContent: "center",
        background: "rgba(212,162,58,0.08)",
        border: "1px solid var(--hxm-line-2)",
        color: "var(--hxm-gold-bright)",
        fontSize: 16, lineHeight: 1,
        borderRadius: 3,
        cursor: "pointer",
        userSelect: "none",
      }}
    >
      {label}
    </button>
  );

 // Render MINE + FEE as a Fragment so they become direct siblings of
 // the per-phase ROLL DIE / SPIN / etc. button inside the room's right
 // flex column. The parent column has `gap: 8` so all three rows
 // (ROLL DIE → MINE → FEE) share identical vertical spacing, identical
 // full-column width, and consistent UI across iron/bronze/silver/gold.
  return (
    <>
      {/* MINE — full-width button matching ROLL DIE's dimensions
          (padding 13/18, fontSize 14). The button shows a small lock
          glyph as a prefix when disabled (wallet locked / no ticker /
          previous bet still settling); otherwise renders just the
          plain "MINE" label. No state-specific wording change — the
          icon alone communicates the lock.

          Hidden while the visual game is in its "rolled" phase — the
          per-phase action stack already shows a contextual MINE
          (using the rolled pick), so showing this one too produces
          two stacked MINE buttons. Other phases keep this MINE
          visible so the user always has access to a quick on-chain
          bet path. */}
      {!hideMine && (
        <button
          onClick={onMine}
          disabled={mineDisabled}
          className="hxm-btn-cta"
          style={{
            padding: "13px 18px",
            fontSize: 14,
            width: "100%",
            opacity: mineDisabled ? 0.45 : 1,
            cursor: mineDisabled ? "not-allowed" : "pointer",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
          }}
          title={mineReason || `Broadcast a ${tier.label} bet on ${activeTicker || "—"}`}
        >
          {mineDisabled && !busy && <Lock size={14} />}
          {busy ? "BROADCASTING..." : "MINE"}
        </button>
      )}

      {/* FEE — full-width frame using the SAME visual shell as
          .hxm-btn-cta (the class ROLL DIE / MINE use), so the right
          column reads as three uniform rows. Inline-stylewise we mirror
          the class' background gradient, border, radius, and shadow
          rather than applying the class itself — `:hover` on a passive
          frame would mislead the user into thinking the whole row is
          clickable, when really only the inner −/+/⚡ steppers are. */}
      <div style={{
        width: "100%",
        padding: "8px 14px",
        background: "linear-gradient(180deg, #2c0e0e 0%, #1a0506 100%)",
        border: "1px solid var(--hxm-line-2)",
        borderRadius: 8,
        boxShadow: "inset 0 1px 0 rgba(255,220,140,0.1), 0 4px 14px rgba(0,0,0,0.5)",
        display: "flex", alignItems: "center", gap: 8,
        boxSizing: "border-box",
      }}>
        <span className="hxm-bebas" style={{
          fontSize: 11, letterSpacing: "0.18em", color: "var(--hxm-text-dim)", flexShrink: 0,
        }}>
          FEE
        </span>
        {stepBtn("−", () => bumpFee(-0.1), "decrease 0.1 sat/vB")}
        <input
          type="number"
          min="0.1"
          step="0.1"
          value={feeRate}
          onChange={(e) => writeFee(e.target.value)}
          onBlur={() => {
 // Clamp on blur — empty / NaN / <0.1 → snap to 0.1 (the
 // protocol floor for accepted fee rates).
            const n = parseFloat(feeRate);
            if (!Number.isFinite(n) || n < 0.1) writeFee(0.1);
          }}
          className="hxm-mono no-spin"
          style={{
            flex: 1, minWidth: 0,
            background: "transparent",
            border: "none",
            outline: "none",
            color: "var(--hxm-gold-bright)",
            fontSize: 14,
            fontWeight: 600,
            textAlign: "center",
            padding: 0,
 // Hide native number-input spinners — we have our own −/+.
            MozAppearance: "textfield",
          }}
          title="Type a fee rate or use the −/+ buttons"
        />
        <span className="hxm-mono" style={{
          fontSize: 10, color: "var(--hxm-text-mute)", whiteSpace: "nowrap", flexShrink: 0,
        }}>
          sat/vB
        </span>
        {stepBtn("+", () => bumpFee(0.1), "increase 0.1 sat/vB")}
        {stepBtn("⚡", fetchLive, "fetch live recommended rate from mempool.space")}
      </div>
    </>
  );
}

// =============================================================================
// ALMANAC — last-N-blocks analyzer + direct on-chain bet entry
// =============================================================================
// Shows the most recent 20 confirmed blocks' tail-hex outcomes for each tier
// (IRON / BRONZE / SILVER / GOLD), plus a 4-tier direct-bet panel where the
// user types a pick and broadcasts immediately — bypassing the visual game
// rooms. Power-user surface for analyzing patterns and acting on hunches.
// Block hashes are fetched once per height via cmd_get_block_hash_at and
// cached at module scope for the session (immutable past 6 confirmations).
// =============================================================================

// =============================================================================
// HxmSelect — custom dropdown that matches the casino theme
// =============================================================================
// The native HTML <select> dropdown is unstylable across browsers (Chromium
// paints a white system menu regardless of CSS) and clashes hard with the
// black/gold UI everywhere else in the app. This is a tiny replacement: a
// styled trigger button + an absolute-positioned panel of options. Closes
// on Escape, click-outside, or selection.
// Props:
// value — currently selected option's `value` field
// options — [{ value: string, label: ReactNode },...]
// onChange — (newValue) => void
// disabled — bool, greys the trigger and blocks open
// fontSize — override option/trigger font-size (default 12)
// emptyText — fallback rendered when options is empty
// =============================================================================
function HxmSelect({ value, options, onChange, disabled, fontSize = 12, emptyText = "—" }) {
  const [open, setOpen] = useState(false);
  const triggerRef = useRef(null);
  const panelRef = useRef(null);

 // Close on click outside, Escape — both are conventional dropdown UX
 // and avoid trapping the user inside an open panel.
  useEffect(() => {
    if (!open) return undefined;
    const onDocClick = (e) => {
      if (triggerRef.current?.contains(e.target)) return;
      if (panelRef.current?.contains(e.target)) return;
      setOpen(false);
    };
    const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("mousedown", onDocClick);
    window.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("mousedown", onDocClick);
      window.removeEventListener("keydown", onKey);
    };
  }, [open]);

 // Bulletproof scroll containment. `overscroll-behavior: contain` on
 // the panel SHOULD prevent the wheel event from chaining to the
 // outer.hxm-center scroller, but in practice some Chromium /
 // Tauri webview combos still let the parent scroll when the user
 // wheels over a child that's already mid-scroll. Attach a non-
 // passive native wheel listener that:
 // 1. lets the panel do its native scroll (we don't preventDefault
 // mid-range)
 // 2. preventDefault when at the top/bottom boundary so the wheel
 // event can't bubble up
 // 3. stopPropagation always — kills both bubble paths
 // Native listener (not React's synthetic) because React events are
 // passive by default and can't preventDefault on wheel.
  useEffect(() => {
    if (!open) return undefined;
    const el = panelRef.current;
    if (!el) return undefined;
    const onWheel = (e) => {
      const { scrollTop, scrollHeight, clientHeight } = el;
      const delta = e.deltaY;
      const atTop = scrollTop <= 0;
      const atBottom = scrollTop + clientHeight >= scrollHeight - 1;
      if ((atTop && delta < 0) || (atBottom && delta > 0)) {
        e.preventDefault();
      }
      e.stopPropagation();
    };
    el.addEventListener("wheel", onWheel, { passive: false });
    return () => el.removeEventListener("wheel", onWheel);
  }, [open]);

  const current = options.find((o) => o.value === value);
  const triggerLabel = current ? current.label : emptyText;
  const isEmpty = options.length === 0;

  return (
    <div ref={triggerRef} style={{ position: "relative", width: "100%" }}>
      <button
        type="button"
        className="btx-input"
        onClick={() => { if (!disabled && !isEmpty) setOpen((o) => !o); }}
        disabled={disabled}
        style={{
          width: "100%", height: 30,
          fontFamily: "'JetBrains Mono', monospace",
          fontSize, letterSpacing: "0.1em",
          padding: "5px 26px 5px 10px",
          textAlign: "left",
          cursor: disabled || isEmpty ? "not-allowed" : "pointer",
          position: "relative",
          opacity: disabled ? 0.55 : 1,
          color: current ? "var(--hxm-text)" : "var(--hxm-text-mute)",
          boxSizing: "border-box",
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
        }}
      >
        {triggerLabel}
        <ChevronDown
          size={12}
          style={{
            position: "absolute", right: 8, top: "50%",
            transform: open ? "translateY(-50%) rotate(180deg)" : "translateY(-50%)",
            color: "var(--hxm-gold)",
            transition: "transform 0.15s ease",
            pointerEvents: "none",
          }}
        />
      </button>
      {open && !isEmpty && (
        <div
          ref={panelRef}
 // `hxm-scroll` styles the WebKit scrollbar to match the
 // casino chrome (6px-wide gold thumb on dark track) instead
 // of the OS-default gray bar that visually clashes with the
 // dark/gold theme.
 // overscrollBehavior: contain — wheel events at the top/
 // bottom edge don't propagate to the parent. Without it,
 // scrolling the chip list also scrolls the whole ALMANAC
 // view, making it impossible to reach lower chips.
          className="hxm-scroll"
          style={{
            position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0,
            zIndex: 200,
            maxHeight: 220, overflowY: "auto",
            overscrollBehavior: "contain",
            background: "linear-gradient(180deg, #1a0e0a 0%, #0a0506 100%)",
            border: "1px solid var(--hxm-gold)",
            borderRadius: 4,
            boxShadow: "0 6px 24px rgba(0,0,0,0.7), 0 0 0 1px rgba(212,162,58,0.2), 0 0 24px rgba(212,162,58,0.18)",
            padding: 4,
          }}
        >
          {options.map((opt) => {
            const isSel = opt.value === value;
            return (
              <button
                key={String(opt.value)}
                type="button"
                onClick={() => { onChange(opt.value); setOpen(false); }}
                onMouseEnter={(e) => {
                  if (!isSel) {
                    e.currentTarget.style.background = "rgba(212,162,58,0.10)";
                    e.currentTarget.style.color = "var(--hxm-gold-bright)";
                  }
                }}
                onMouseLeave={(e) => {
                  if (!isSel) {
                    e.currentTarget.style.background = "transparent";
                    e.currentTarget.style.color = "var(--hxm-text)";
                  }
                }}
                style={{
                  display: "block", width: "100%",
                  padding: "6px 10px",
                  textAlign: "left",
                  background: isSel
                    ? "linear-gradient(90deg, rgba(212,162,58,0.22) 0%, rgba(212,162,58,0.05) 100%)"
                    : "transparent",
                  border: "none",
                  borderLeft: isSel ? "2px solid var(--hxm-gold-bright)" : "2px solid transparent",
                  borderRadius: 2,
                  fontFamily: "'JetBrains Mono', monospace",
                  fontSize, letterSpacing: "0.06em",
                  color: isSel ? "var(--hxm-gold-bright)" : "var(--hxm-text)",
                  cursor: "pointer",
                  transition: "background 0.12s, color 0.12s",
                  fontWeight: isSel ? 600 : 400,
                }}
              >
                {opt.label}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

// Module-level cache keyed by height. Stores `{ hash, time }` pairs (or
// just `{ hash }` if the older single-call path was used). Survives
// screen switches but clears on full app reload. Bounded by the natural
// use case (~20 blocks at a time) so no eviction needed. Block hashes
// and timestamps are stable past 1 confirmation, so the cache never
// needs to invalidate within a session.
const __almanacHashCache = new Map();

async function fetchBlockInfo(height, network) {
  const cached = __almanacHashCache.get(height);
  if (cached && cached.time != null) return cached;
  try {
    const info = await protocolGetBlockInfoAt(height, network || "bitcoin");
    if (info && typeof info.hash === "string" && info.hash.length === 64) {
      const entry = { hash: info.hash.toLowerCase(), time: Number(info.time) || 0 };
      __almanacHashCache.set(height, entry);
      return entry;
    }
  } catch (e) {
    console.warn("[almanac] block-info fetch failed", height, e);
  }
  return null;
}

async function fetchBlockHash(height, network) {
  if (__almanacHashCache.has(height)) return __almanacHashCache.get(height).hash;
  try {
    const h = await protocolGetBlockHashAt(height, network || "bitcoin");
    if (typeof h === "string" && h.length === 64) {
      __almanacHashCache.set(height, { hash: h.toLowerCase() });
      return h.toLowerCase();
    }
  } catch (e) { /* swallow — caller renders "—" */ }
  return null;
}

// Pure helpers — same settlement rule as protocolComputeBetOutcome but
// applied directly to a hash for display ("if you'd bet ODD on this block,
// would it have hit?"). Just produces the ENGRAVED winning value per tier
// so the table can render four columns of "what would have won here".
function ironOutcomeForHash(hash) {
  if (!hash || hash.length < 1) return null;
  const tail = hash.slice(-1);
  const v = parseInt(tail, 16);
  if (Number.isNaN(v)) return null;
  const die = (v % 6) + 1;
  return { die, parity: die % 2 === 1 ? "ODD" : "EVEN", tail };
}
function tailFor(hash, k) {
  if (!hash || hash.length < k) return null;
  return hash.slice(-k).toUpperCase();
}

// Format a UNIX timestamp (seconds) as the WALL-CLOCK time the block
// was mined, in the user's local timezone. The user explicitly wanted
//— i.e. show 14:23:45 ·
// 05-10, not "12m ago". Two-line layout (date on top, time below) keeps
// the column narrow while still surfacing both pieces of info.
function formatBlockMinedAt(timeSec) {
  if (!timeSec) return null;
  const d = new Date(timeSec * 1000);
  if (Number.isNaN(d.getTime())) return null;
  const pad = (n) => String(n).padStart(2, "0");
  return {
    date: `${pad(d.getMonth() + 1)}-${pad(d.getDate())}`,
    time: `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`,
  };
}

function ChainAlmanac({ state, walletMeta, chainState, sessionPassword, setToast, broadcastCasinoBet, setSettleModal }) {
  const network = walletMeta?.network || "bitcoin";
  const tipHeight = chainState?.tip_height ?? null;
 // Show the last 10 blocks. Sized so the entire CHAIN ALMANAC screen
 // (hero header + table + DIRECT BET panel) fits in one viewport
 // without scrolling on a typical 1080p / 1440p window. 10 blocks =
 // ~100 minutes of recent chain at the 10-min target — enough recent
 // history for at-a-glance pattern reads before placing a direct bet.
  const HISTORY = 10;

 // Map height → { hash, time }. Hydrated synchronously from the
 // module-level __almanacHashCache so a remount (user navigates away
 // then returns to ALMANAC) renders the cached rows on the FIRST
 // paint — no "fetching…" flash. The useEffect below still runs to
 // pick up new blocks since the last visit, but if everything is
 // already cached the network skip is a no-op.
  const [blockInfos, setBlockInfos] = useState(() => {
    const m = new Map();
    for (const [h, info] of __almanacHashCache.entries()) {
      if (info && info.time != null) m.set(h, info);
    }
    return m;
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (tipHeight == null) return undefined;
    let cancelled = false;
 // Compute which heights we still need. If the module cache already
 // has every height in the window (user just remounted from another
 // screen), skip the loading flicker entirely and the useEffect
 // does no work. Only set `loading` when an actual network fetch
 // is going to happen.
    const heights = [];
    const missing = [];
    for (let i = 0; i < HISTORY; i++) {
      const h = tipHeight - i;
      if (h <= 0) break;
      heights.push(h);
      const cached = __almanacHashCache.get(h);
      if (!cached || cached.time == null) missing.push(h);
    }
    if (missing.length > 0) setLoading(true);
    (async () => {
 // Concurrent fetch — `fetchBlockInfo` returns synchronously
 // (well, microtask) for cached heights, so Promise.all only
 // actually hits the network for `missing`.
      const results = await Promise.all(heights.map((h) => fetchBlockInfo(h, network)));
      if (cancelled) return;
      setBlockInfos((prev) => {
        const next = new Map(prev);
        for (let i = 0; i < heights.length; i++) {
          if (results[i]) next.set(heights[i], results[i]);
        }
        return next;
      });
      setLoading(false);
    })();
    return () => { cancelled = true; };
  }, [tipHeight, network]);

 // Eligible chips for direct-bet — same predicate as the rooms (the
 // shared `confirmedBtcUtxos` helper at module scope). Sorted asc so
 // the smallest chip is the default selection.
  const allEligible = useMemo(() => (
    confirmedBtcUtxos(state.wallet.utxos).slice().sort((a, b) => a.sats - b.sats)
  ), [state.wallet.utxos]);

 // ===== DIRECT BET state — one pick + chip choice per tier ===========
 // All four tiers start with NO pre-selected pick — the user must
 // consciously choose ODD/EVEN (iron) or type the hex tail (the other
 // three). Pre-selecting iron to "odd" used to make the IRON row look
 // ready-to-fire on mount even though the user hadn't actually made a
 // decision; one accidental click on MINE would broadcast a bet the user
 // didn't actually configure. Empty defaults force the click to be
 // intentional. The HxmSelect renders `placeholder` ("ODD or EVEN") via
 // `emptyText` when iron's value is "".
  const [picks, setPicks] = useState({ iron: "", bronze: "", silver: "", gold: "" });
 // Per-tier chip selection. Initialized to the smallest chip that
 // meets the tier's threshold; re-snaps when state.wallet.utxos
 // changes so a spent chip doesn't leave the dropdown stuck.
  const [chipKeys, setChipKeys] = useState({ iron: null, bronze: null, silver: null, gold: null });
  useEffect(() => {
    setChipKeys((prev) => {
      const next = { ...prev };
      for (const key of ["iron", "bronze", "silver", "gold"]) {
        const tier = TIERS[key];
        const eligible = allEligible.filter((u) => u.sats >= tier.threshold);
        const stillThere = prev[key] && eligible.some((u) => utxoKey(u) === prev[key]);
        if (!stillThere) next[key] = eligible[0] ? utxoKey(eligible[0]) : null;
      }
      return next;
    });
  }, [allEligible]);

  const [busyTier, setBusyTier] = useState(null);

 // Transient "invalid char typed" flash — when the user attempts a
 // non-hex character, we set this to the offending tier key for 1.5s
 // so the row can show a red border + inline hint, then auto-clear.
 // The actual character is silently dropped from the input value
 // (replace below) — this is purely UX feedback so the user knows
 // why their keystroke didn't land.
  const [invalidTier, setInvalidTier] = useState(null);
  const invalidTimerRef = useRef(null);
  const flashInvalid = (tierKey) => {
    setInvalidTier(tierKey);
    if (invalidTimerRef.current) clearTimeout(invalidTimerRef.current);
    invalidTimerRef.current = setTimeout(() => {
      setInvalidTier(null);
      invalidTimerRef.current = null;
    }, 1500);
  };
  useEffect(() => () => {
    if (invalidTimerRef.current) clearTimeout(invalidTimerRef.current);
  }, []);

 // Per-panel FEE RATE override (sat/vB) — defaults to whatever the
 // user last set in SETTINGS (getFeeRateMock). Editing it here only
 // affects bets fired from this panel; the global setting is left
 // untouched. parseFloat in submitDirect coerces to a number; empty
 // string falls through to the global default inside broadcastCasinoBet.
  const [feeRate, setFeeRate] = useState(() => {
    const stored = parseFloat(getFeeRateMock() || "");
    return Number.isFinite(stored) && stored > 0 ? String(stored) : "1";
  });

  const validatePick = (tier, raw) => {
    const p = (raw || "").toLowerCase().trim();
    if (tier === "iron") {
      if (p === "odd" || p === "even") return p;
      return null;
    }
    const len = tier === "bronze" ? 1 : tier === "silver" ? 2 : 3;
    return /^[0-9a-f]+$/.test(p) && p.length === len ? p : null;
  };

  const submitDirect = async (tierKey) => {
    const tier = TIERS[tierKey];
    const pick = validatePick(tierKey, picks[tierKey]);
    if (!pick) {
      const need = tierKey === "iron" ? "ODD or EVEN"
        : tierKey === "bronze" ? "1 hex char (0-9, a-f)"
        : tierKey === "silver" ? "2 hex chars"
        : "3 hex chars";
      setToast({ kind: "warn", msg: `${tier.label} needs ${need}` });
      return;
    }
    const recvKey = chipKeys[tierKey];
    if (!recvKey) {
      setToast({ kind: "warn", msg: `${tier.label}: no eligible chip (need ≥ ${fmt(tier.threshold)} sat)` });
      return;
    }
    if (!sessionPassword) {
      setToast({ kind: "warn", msg: "wallet locked — open SETTINGS → Wallet password" });
      return;
    }
    if (!state.wallet.tokenTicker) {
      setToast({ kind: "warn", msg: "no mine target — pick one from the side-rail panel" });
      return;
    }
 // Initial-sync gate — same rule as game-room MINE.
    if (!_syncState.initialSyncComplete) {
      setToast({ kind: "warn", msg: "initial chain scan in progress — direct bet unlocks when complete" });
      return;
    }
 // Indexer-behind-tip gate — direct bet broadcasts a real LUCKYPROTOCOL
 // bet whose win predicate hashes against the confirming block. If
 // the global indexer hasn't yet seen the most recent block(s), the
 // local view of "what counts as the canonical tip" is stale and
 // we refuse the broadcast until catch-up. Mirrors the game-room
 // MINE guard plus the InitialSyncOverlay's game-resync gate.
    if (_syncState.chainTip > _syncState.scanHeight) {
      setToast({ kind: "warn", msg: "indexer catching up to chain tip — direct bet locked until resync completes" });
      return;
    }
 // Cap-exhaustion gate — same rule as game-room MINE (PROTOCOL.md §5):
 // BET on a fully-minted ticker burns fees for zero reward. Refuse.
    const _activeTok = state.deployedTokens.find((t) => t.ticker === state.wallet.tokenTicker);
    if (_activeTok && Number(_activeTok.supply || 0) > 0
        && Number(_activeTok.minted || 0) >= Number(_activeTok.supply)) {
      setToast({
        kind: "warn",
        msg: `${state.wallet.tokenTicker} fully minted (${Number(_activeTok.minted).toLocaleString()} / ${Number(_activeTok.supply).toLocaleString()}) — no more mining possible`,
      });
      return;
    }
    setBusyTier(tierKey);
 // Open the floating SettleModal IMMEDIATELY (mine_txid: null →
 // shows the "BROADCAST · awaiting confirmation" banner). Mirrors
 // the game-room MINE flow at line ~3499. broadcastCasinoBet's
 // async hydrate path will stamp the real txid onto this modal
 // once Esplora returns — same setSettleModal((prev) =>...) at
 // line ~2972 keys on `prev.tier === tier`, so the modal we open
 // here gets matched and updated.mine
 //— DIRECT BET should produce the same
 // visual confirmation as the in-game MINE.
    setSettleModal?.({
      tier: tierKey,
      tier_label: tier.label,
      pick,
      ticker: state.wallet.tokenTicker,
      reward: tier.reward,
      mine_txid: null,
    });
    try {
      const fr = parseFloat(feeRate);
      const feeOverride = Number.isFinite(fr) && fr > 0 ? fr : null;
      await broadcastCasinoBet(tierKey, pick, recvKey, feeOverride);
    } finally {
      setTimeout(() => setBusyTier(null), 800);
    }
  };

  const formatChip = (k) => {
    if (!k) return "—";
    const u = (state.wallet.utxos ?? []).find((x) => utxoKey(x) === k);
    return u ? `${fmt(u.sats)} sat` : "—";
  };

 // Build the rendered rows: tip downward, one entry per height in the
 // window, pulling each row's hash + computed tier outcomes from the
 // module cache.
  const rows = useMemo(() => {
    if (tipHeight == null) return [];
    const out = [];
    for (let i = 0; i < HISTORY; i++) {
      const h = tipHeight - i;
      if (h <= 0) break;
      const info = blockInfos.get(h) || null;
      const hash = info ? info.hash : null;
      const time = info ? info.time : null;
      out.push({
        height: h,
        hash,
        time,
        iron: hash ? ironOutcomeForHash(hash) : null,
        bronze: hash ? tailFor(hash, 1) : null,
        silver: hash ? tailFor(hash, 2) : null,
        gold: hash ? tailFor(hash, 3) : null,
      });
    }
    return out;
  }, [tipHeight, blockInfos]);

  return (
    <div className="btx-screen">
      {/* Hero header — sized so header + 10-row table + DIRECT BET
          panel together fill (without overflowing) a typical 1080p
          viewport. The bordered .btx-screen wrapper already uses a
          flex column layout, so growing the table's row padding +
          giving the hero / DIRECT BET reasonable room is what closes
          the dead space at the bottom. */}
      <div style={{
        padding: "14px 20px 13px",
        background: "linear-gradient(135deg, rgba(212,162,58,0.06), rgba(212,162,58,0.02))",
        border: "1px solid var(--hxm-line-2)",
        borderRadius: 6, marginBottom: 14,
        position: "relative", overflow: "hidden",
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 11 }}>
          <ScanSearch size={20} color="var(--hxm-gold-bright)" style={{ filter: "drop-shadow(0 0 6px rgba(212,162,58,0.4))" }} />
          <div className="hxm-cinzel metal-gold" style={{
            fontSize: 24, fontWeight: 900, letterSpacing: "0.10em", lineHeight: 1.05,
          }}>
            CHAIN ALMANAC
          </div>
        </div>
        <div className="hxm-cormorant" style={{
          fontSize: 12.5, color: "var(--hxm-gold)",
          fontStyle: "italic", marginTop: 5, letterSpacing: "0.06em",
          display: "flex", alignItems: "center", gap: 10,
        }}>
          <span className="gold-rule" style={{ width: 28 }} />
          <span style={{ whiteSpace: "nowrap" }}>
            Last {HISTORY} blocks · winning hex per tier · direct on-chain bet
          </span>
          <span className="gold-rule" style={{ flex: 1 }} />
        </div>
      </div>

      {/* === HISTORY TABLE ===
          Seven columns: BLOCK · HASH · AGE · IRON · BRONZE · SILVER · GOLD.
          HASH is uniform "matrix green" mono and centered. AGE renders
          the relative time since the block was mined (refreshes every
          30s via a tick). Outcome cells use Bebas Neue (casino
          scoreboard typeface) so the row reads as: ledger entry → mined
          how long ago → tier scoreboard. */}
      <div className="hxm-bordered" style={{ padding: 0, overflow: "hidden", marginBottom: 14 }}>
        <div style={{
          display: "grid",
          gridTemplateColumns: "82px 1fr 96px 92px 60px 64px 72px",
          gap: 12, alignItems: "center",
          padding: "11px 14px",
          borderBottom: "1px solid var(--hxm-line-2)",
          background: "rgba(0,0,0,0.35)",
          fontFamily: "'Bebas Neue', sans-serif",
          // fontWeight bumped from default (400) to 700 so every column
          // header (BLOCK / HASH / BLOCK TIME / IRON / BRONZE / SILVER
          // / GOLD) reads as a bold marquee label, matching the cell
          // typography weight (900) below without overpowering it.
          fontSize: 11, fontWeight: 700,
          color: "var(--hxm-text-dim)", letterSpacing: "0.20em",
        }}>
          <span>BLOCK</span>
          <span style={{ textAlign: "center" }}>HASH</span>
          <span style={{ textAlign: "center" }}>BLOCK TIME</span>
          {/* Headers re-themed to match the casino-floor cell styling
              below. IRON keeps a steel-blue tint (matches the existing
              IronRoom dice-cup aesthetic — and the cells below use
              roulette red/green for the actual outcomes, so the header
              shouldn't pre-claim either color). BRONZE/SILVER/GOLD
              echo their respective metal gradients via background-clip
              so the header literally LOOKS like the metal it names. */}
          <span style={{ color: "#a8c8e8", textAlign: "center", textShadow: "0 0 6px rgba(110,168,232,0.55)" }}>IRON</span>
          <span style={{
            textAlign: "center",
            color: "#e0a060",
            textShadow: "0 0 6px rgba(205,127,50,0.7), 0 0 12px rgba(205,127,50,0.3)",
          }}>BRONZE</span>
          <span style={{
            textAlign: "center",
            background: "linear-gradient(180deg, #ffffff 0%, #c8d0d8 50%, #707880 100%)",
            WebkitBackgroundClip: "text", backgroundClip: "text",
            WebkitTextFillColor: "transparent",
            filter: "drop-shadow(0 0 5px rgba(220,230,255,0.6))",
          }}>SILVER</span>
          <span style={{
            textAlign: "center",
            background: "linear-gradient(180deg, #fff5b8 0%, #ffd700 50%, #b8860b 100%)",
            WebkitBackgroundClip: "text", backgroundClip: "text",
            WebkitTextFillColor: "transparent",
            filter: "drop-shadow(0 0 6px rgba(255,215,0,0.75))",
          }}>GOLD</span>
        </div>
        {tipHeight == null ? (
          <div style={{ padding: 24, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 11 }}>
            waiting for chain sync…
          </div>
        ) : rows.length === 0 ? (
          <div style={{ padding: 24, textAlign: "center", color: "var(--hxm-text-mute)", fontSize: 11 }}>
            {loading ? "fetching block hashes…" : "no blocks fetched yet"}
          </div>
        ) : (
          rows.map((r) => {
            const hash = r.hash;
            return (
              <div key={r.height} style={{
                display: "grid",
                gridTemplateColumns: "82px 1fr 96px 92px 60px 64px 72px",
                gap: 12, alignItems: "center",
                padding: "7px 14px",
                borderTop: "1px solid var(--hxm-line)",
                minHeight: 32,
              }}>
                {/* BLOCK # — gold link, mono so the digits align column-wise */}
                <a
                  href={hash ? blockExplorerUrl(network, hash) : "#"}
                  target="_blank"
                  rel="noopener noreferrer"
                  onClick={hash ? undefined : (e) => e.preventDefault()}
                  style={{
                    color: "var(--hxm-gold-bright)",
                    textDecoration: hash ? "underline" : "none",
                    cursor: hash ? "pointer" : "default",
                    fontFamily: "'JetBrains Mono', monospace",
                    fontSize: 11,
                    letterSpacing: "0.02em",
                  }}
                  title={hash ? `view block #${r.height} on mempool.space` : "fetching..."}
                >
 #{r.height.toLocaleString()}
                </a>

                {/* Full hash — deep electric blue, centered, mono.
                    Casino-neon palette swap from the old matrix green —
                    blue reads as "data / chain / cryptographic" rather
                    than "active outcome" (which is what the green-glow
                    used to suggest, conflicting with IRON's EVEN cells
                    which now own the green slot). text-shadow keeps a
                    soft CRT halo. word-break lets the 64-char string
                    wrap on narrow windows so the full hash is always
                    visible. */}
                {hash ? (
                  <a
                    href={blockExplorerUrl(network, hash)}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={{
                      color: "#3b82f6",
                      textDecoration: "none",
                      fontFamily: "'JetBrains Mono', monospace",
                      fontSize: 12,
                      lineHeight: 1.4,
                      fontWeight: 500,
                      letterSpacing: "0.02em",
                      textShadow: "0 0 6px rgba(59,130,246,0.40)",
                      textAlign: "center",
                      display: "block",
                      wordBreak: "break-all",
                    }}
                    title={`view block on mempool.space\n${hash}`}
                  >
                    {hash}
                  </a>
                ) : (
                  <span style={{ color: "var(--hxm-text-mute)", textAlign: "center", fontSize: 11 }}>fetching…</span>
                )}

                {/* BLOCK TIME — the block header's nTime field, rendered
                    in the user's local timezone. Two lines (MM-DD on
                    top, HH:MM:SS below) so the column reads cleanly
                    even when narrow. Tooltip carries the absolute UTC
                    timestamp for cross-checking against mempool.space. */}
                {(() => {
                  const stamp = formatBlockMinedAt(r.time);
                  if (!stamp) {
                    return (
                      <span style={{
                        color: "var(--hxm-text-mute)", textAlign: "center",
                        fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5,
                      }}>—</span>
                    );
                  }
                  return (
                    <span
                      style={{
                        color: "var(--hxm-text-dim)", textAlign: "center",
                        fontFamily: "'JetBrains Mono', monospace",
                        fontSize: 10.5, letterSpacing: "0.02em",
                        lineHeight: 1.25,
                        display: "flex", flexDirection: "column", alignItems: "center",
                      }}
                      title={r.time ? `${new Date(r.time * 1000).toUTCString()}\n(local time shown)` : "—"}
                    >
                      <span style={{ color: "var(--hxm-text-mute)", fontSize: 9.5 }}>{stamp.date}</span>
                      <span>{stamp.time}</span>
                    </span>
                  );
                })()}

                {/* Per-tier outcome cells — casino-floor typography.
                    IRON adopts roulette colors (ODD = red, EVEN = felt
                    green) with a small chip-dot indicator so a glance
                    parses the parity even before reading the word.
                    BRONZE / SILVER / GOLD use polished-metal gradients
                    via `background-clip: text`, with a `drop-shadow`
                    filter providing the neon glow that text-shadow
                    can't deliver on gradient-clipped text (transparent
                    text → text-shadow shows nothing). Each row reads
                    like a glowing casino scoreboard rather than flat
                    log output. Empty cells fall back to a muted dash. */}
                {(() => {
                  const parity = r.iron?.parity;
                  if (!parity) {
                    return <span style={{ color: "var(--hxm-text-mute)", textAlign: "center", fontFamily: "'Bebas Neue', sans-serif", fontSize: 13 }}>—</span>;
                  }
                  const isOdd = parity === "ODD";
                  return (
                    <span style={{
                      textAlign: "center",
                      display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 5,
                      fontFamily: "'Bebas Neue', sans-serif",
                      fontSize: 14, fontWeight: 800, letterSpacing: "0.14em",
                      color: isOdd ? "#ff4757" : "#2ed573",
                      textShadow: isOdd
                        ? "0 0 10px rgba(255,71,87,0.85), 0 0 18px rgba(255,71,87,0.4)"
                        : "0 0 10px rgba(46,213,115,0.75), 0 0 18px rgba(46,213,115,0.35)",
                    }}>
                      <span style={{
                        fontSize: 9, lineHeight: 1,
                        color: isOdd ? "#ff4757" : "#2ed573",
                        textShadow: isOdd
                          ? "0 0 4px rgba(255,71,87,0.9)"
                          : "0 0 4px rgba(46,213,115,0.85)",
                      }}>●</span>
                      {parity}
                    </span>
                  );
                })()}

                {r.bronze ? (
                  <span style={{
                    textAlign: "center",
                    fontFamily: "'Bebas Neue', sans-serif",
                    // BRONZE / SILVER / GOLD use weight 900 / size 15 — one
                    // step bolder than the previous 800/14 so the
                    // characters read as "the answer" of each row, with
                    // a TWO-layer glow (close inner halo + soft mid-
                    // distance halo) that's bright enough to register
                    // on a dark background without dominating the row.
                    // An earlier 4-layer halo was too intense — user
                    // called it "刺眼"; the layer count + outer alpha
                    // were both cut to bring it back to "marquee letters,
                    // not eyestrain".
                    fontSize: 15, fontWeight: 900, letterSpacing: "0.14em",
                    color: "#e6a06a",
                    textShadow:
                      "0 0 6px rgba(205,127,50,0.55), " +
                      "0 0 12px rgba(205,127,50,0.22)",
                  }}>
                    {r.bronze.toUpperCase()}
                  </span>
                ) : (
                  <span style={{ color: "var(--hxm-text-mute)", textAlign: "center", fontFamily: "'Bebas Neue', sans-serif", fontSize: 15 }}>—</span>
                )}

                {r.silver ? (
                  <span style={{
                    textAlign: "center",
                    fontFamily: "'Bebas Neue', sans-serif",
                    fontSize: 15, fontWeight: 900, letterSpacing: "0.14em",
                    background: "linear-gradient(180deg, #ffffff 0%, #dde4ec 30%, #aab3bc 65%, #5e6770 100%)",
                    WebkitBackgroundClip: "text",
                    backgroundClip: "text",
                    WebkitTextFillColor: "transparent",
                    filter:
                      "drop-shadow(0 0 5px rgba(220, 230, 255, 0.55)) " +
                      "drop-shadow(0 0 12px rgba(220, 230, 255, 0.20)) " +
                      "drop-shadow(0 1px 0 rgba(0, 0, 0, 0.45))",
                  }}>
                    {r.silver.toUpperCase()}
                  </span>
                ) : (
                  <span style={{ color: "var(--hxm-text-mute)", textAlign: "center", fontFamily: "'Bebas Neue', sans-serif", fontSize: 15 }}>—</span>
                )}

                {r.gold ? (
                  <span style={{
                    textAlign: "center",
                    fontFamily: "'Bebas Neue', sans-serif",
                    fontSize: 15, fontWeight: 900, letterSpacing: "0.14em",
                    background: "linear-gradient(180deg, #fff5b8 0%, #ffd700 30%, #d49a17 65%, #7a5a00 100%)",
                    WebkitBackgroundClip: "text",
                    backgroundClip: "text",
                    WebkitTextFillColor: "transparent",
                    filter:
                      "drop-shadow(0 0 6px rgba(255, 215, 0, 0.65)) " +
                      "drop-shadow(0 0 14px rgba(255, 200, 0, 0.25)) " +
                      "drop-shadow(0 1px 0 rgba(0, 0, 0, 0.45))",
                  }}>
                    {r.gold.toUpperCase()}
                  </span>
                ) : (
                  <span style={{ color: "var(--hxm-text-mute)", textAlign: "center", fontFamily: "'Bebas Neue', sans-serif", fontSize: 15 }}>—</span>
                )}
              </div>
            );
          })
        )}
      </div>

      {/* === DIRECT BET PANEL ===
          Top row: section title (Bebas, gold) on the left, FEE RATE
          stepper on the right. The fee rate is per-panel (initialized
          from the global getFeeRateMock value but stored in local state
          so editing here doesn't bleed into SETTINGS).
          Then four tier rows (IRON/BRONZE/SILVER/GOLD), each a 4-column
          grid: tier label · pick input · chip selector · MINE button. */}
      <div className="hxm-bordered" style={{ padding: "10px 14px" }}>
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          gap: 14, marginBottom: 6,
        }}>
          <div className="hxm-bebas" style={{
            fontSize: 11, letterSpacing: "0.22em",
            color: "var(--hxm-gold-bright)",
          }}>
 // DIRECT BET — TYPE PICK · CLICK MINE · BROADCAST
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span className="hxm-bebas" style={{
              fontSize: 10, letterSpacing: "0.20em", color: "var(--hxm-text-dim)",
            }}>
              FEE RATE
            </span>
            <input
              className="btx-input"
              type="number"
              min="0.1"
              step="0.1"
              value={feeRate}
              onChange={(e) => setFeeRate(e.target.value)}
              style={{
                width: 64, textAlign: "right",
                fontFamily: "'JetBrains Mono', monospace", fontSize: 12,
                padding: "4px 8px",
                height: 28, boxSizing: "border-box",
              }}
              title="sat/vB applied to direct-bet broadcasts"
            />
            <span className="hxm-mono" style={{ fontSize: 10, color: "var(--hxm-text-mute)" }}>
              sat/vB
            </span>
          </div>
        </div>
        {/* Hex-input legend — clarifies the alphabet for the three hex
            tiers. Bebas Neue all-caps so it visually echoes the
            section title above it (same casino-marquee typography),
            lives in its own dim-amber band so users notice the
            constraint before typing. */}
        <div className="hxm-bebas" style={{
          fontSize: 11, color: "var(--hxm-amber)",
          letterSpacing: "0.18em", lineHeight: 1.5,
          paddingBottom: 8, marginBottom: 4,
          borderBottom: "1px solid var(--hxm-line)",
          textTransform: "uppercase",
        }}>
          HEX PICK USES <span style={{ color: "var(--hxm-gold-bright)" }}>0–9</span> AND{" "}
          <span style={{ color: "var(--hxm-gold-bright)" }}>A–F</span> ONLY ·
          {" "}<span style={{ color: TIERS.bronze.metalA, textShadow: `0 0 5px ${TIERS.bronze.glow}` }}>BRONZE</span> 1 CHAR ·
          {" "}<span style={{ color: TIERS.silver.metalA, textShadow: `0 0 5px ${TIERS.silver.glow}` }}>SILVER</span> 2 CHARS ·
          {" "}<span style={{ color: TIERS.gold.metalA,   textShadow: `0 0 5px ${TIERS.gold.glow}` }}>GOLD</span> 3 CHARS ·
          {" "}OTHER CHARS REJECTED
        </div>

        {[
          { key: "iron",   placeholder: "ODD or EVEN",        inputType: "select" },
          { key: "bronze", placeholder: "1 hex · e.g. 9",     inputType: "text", maxLen: 1 },
          { key: "silver", placeholder: "2 hex · e.g. 2c",    inputType: "text", maxLen: 2 },
          { key: "gold",   placeholder: "3 hex · e.g. 4d9",   inputType: "text", maxLen: 3 },
        ].map(({ key, placeholder, inputType, maxLen }, idx) => {
          const tier = TIERS[key];
          const tierEligible = allEligible.filter((u) => u.sats >= tier.threshold);
          const chipKey = chipKeys[key];
          const noChip = !chipKey;
          const busy = busyTier === key;
          return (
            <div key={key} style={{
              borderTop: idx === 0 ? "none" : "1px solid var(--hxm-line)",
              padding: "6px 0",
            }}>
            <div style={{
              display: "grid",
              gridTemplateColumns: "62px 1fr 1fr 96px",
              gap: 10, alignItems: "center",
            }}>
              {/* Tier label */}
              <div className="hxm-cinzel" style={{
                fontSize: 12.5, fontWeight: 700,
                color: tier.metalA,
                textShadow: `0 0 8px ${tier.accent}55`,
                letterSpacing: "0.06em",
              }}>
                {tier.label}
              </div>

              {/* Pick input — IRON uses HxmSelect (custom themed
                  dropdown matching the casino chrome); the three hex
                  tiers use a free-text input with hex-only filter. */}
              {inputType === "select" ? (
                <HxmSelect
                  value={picks[key]}
                  options={[
                    { value: "odd",  label: "ODD" },
                    { value: "even", label: "EVEN" },
                  ]}
                  onChange={(v) => setPicks((p) => ({ ...p, [key]: v }))}
                  disabled={busy}
                  fontSize={12}
 // When picks[key] is "" (the initial state), HxmSelect renders
 // this string instead of "—". Mirrors the hex-tier inputs which
 // show `placeholder` in the same slot. The user sees "ODD or
 // EVEN" and knows the trigger is awaiting a choice.
                  emptyText={placeholder}
                />
              ) : (
 /* Hex-only input: BRONZE 1 char, SILVER 2, GOLD 3.
                   The onChange runs a two-step normalize:
                     1. lowercase                — uniform display
                     2. strip [^0-9a-f]          — silently reject letters
                                                   beyond a-f (g, x, ż, …)
                   then truncates to the tier's maxLen. If anything was
                   stripped at step 2 we flash a red border + inline
                   hint via flashInvalid(key) for 1.5s so the user sees
                   why their keystroke didn't land. The native
                   maxLength attr is kept as a belt-and-suspenders cap
                   in case the controlled value ever drifts. */
                <input
                  className="btx-input"
                  type="text"
                  value={picks[key]}
                  onChange={(e) => {
                    const lowered = e.target.value.toLowerCase();
                    const cleaned = lowered.replace(/[^0-9a-f]/g, "");
                    if (cleaned.length < lowered.length) {
                      flashInvalid(key);
                    }
                    setPicks((p) => ({ ...p, [key]: cleaned.slice(0, maxLen) }));
                  }}
                  placeholder={placeholder}
                  spellCheck={false}
                  maxLength={maxLen}
                  disabled={busy}
                  style={{
                    fontFamily: "'JetBrains Mono', monospace",
                    fontSize: 12,
                    letterSpacing: "0.1em",
                    padding: "5px 10px",
                    height: 30,
                    boxSizing: "border-box",
                    borderColor: invalidTier === key ? "var(--hxm-red)" : undefined,
                    boxShadow: invalidTier === key
                      ? "0 0 0 1px var(--hxm-red), 0 0 8px rgba(220,60,60,0.35)"
                      : undefined,
                    transition: "border-color 0.15s, box-shadow 0.15s",
                  }}
                  title="hex chars only · 0-9, a-f"
                />
              )}

              {/* Chip selector — themed dropdown showing eligible
                  UTXOs (≥ tier threshold). Empty list shows the
                  threshold hint inline as the trigger label. */}
              <HxmSelect
                value={chipKey || ""}
                options={tierEligible.length === 0
                  ? []
                  : tierEligible.map((u) => ({
                      value: utxoKey(u),
                      label: `${fmt(u.sats)} sat`,
                    }))
                }
                onChange={(v) => setChipKeys((c) => ({ ...c, [key]: v || null }))}
                disabled={busy || tierEligible.length === 0}
                fontSize={11}
                emptyText={`no chip ≥ ${fmt(tier.threshold)} sat`}
              />

              {/* MINE button — fixed height matches the inputs above.
                  Gated on: not busy, has eligible chip, wallet unlocked,
                  AND pick is structurally valid (ODD/EVEN for iron, hex
                  tail of the right length for the others). Without the
                  pick check, an accidental click on the empty IRON row
                  would fire submitDirect, which would just toast the
                  user "select ODD or EVEN" — burning a UI round-trip.
                  Disabling the button up-front makes the awaiting-input
                  state visible at a glance. */}
              {(() => {
                const pickValid = !!validatePick(key, picks[key]);
                const disabled = busy || noChip || !sessionPassword || !pickValid;
                const title = !sessionPassword ? "wallet locked"
                  : noChip ? "no eligible chip"
                  : !pickValid ? (key === "iron"
                      ? "select ODD or EVEN"
                      : `enter ${maxLen} hex char${maxLen > 1 ? "s" : ""} (0-9, a-f)`)
                  : "broadcast on-chain bet";
                return (
                  <button
                    className="hxm-btn-cta"
                    onClick={() => submitDirect(key)}
                    disabled={disabled}
                    style={{
                      padding: "0 12px", fontSize: 11.5, letterSpacing: "0.12em",
                      height: 30, boxSizing: "border-box",
                      display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 6,
                    }}
                    title={title}
                  >
                    {busy ? <RefreshCw size={11} className="btx-spin" /> : <Lock size={11} />}
                    {busy ? "SENDING" : "MINE"}
                  </button>
                );
              })()}
            </div>
            {/* Inline rejection hint — appears for 1.5s after the user
                types a non-hex character. Sits below the input grid,
                indented to align under the pick column so the user's
                eye lands on the right input. The arrow ▲ points at the
                input that just rejected the keystroke. */}
            {invalidTier === key && inputType !== "select" && (
              <div className="hxm-mono" style={{
                marginTop: 4, paddingLeft: 72,
                fontSize: 10, color: "var(--hxm-red)",
                letterSpacing: "0.04em",
              }}>
                ▲ only hex chars allowed · 0-9, a-f
              </div>
            )}
            </div>
          );
        })}

      </div>
    </div>
  );
}


// =============================================================================
// IRON ROOM — SICBO DICE
// =============================================================================
function IronRoom({ state, submitMine, settle, settling, lastResult, goRoom, goDashboard, exitingUtxoKeys, aiMode, onChainBets, sessionPassword, walletMeta, setToast }) {
  const tier = TIERS.iron;
 // Game tables only accept plain BTC UTXOs that are confirmed. Token-bearing
 // UTXOs would burn the token if used as a buy-in; pending UTXOs would be
 // rejected by the protocol's confs >= 1 guard at settle time.
 // Sorted ascending so the default chip selection (eligible[0]) is the
 // smallest above the tier threshold —
 //. Users can still pick a bigger chip from the strip, but the
 // initial visual cue is "spend the smallest available unit".
  const eligible = eligibleChipUtxos(state.wallet.utxos, tier);
  const [recv, setRecv] = useState(eligible[0] ? utxoKey(eligible[0]) : null);
 // When the previously-selected chip gets spent (e.g. after MINE → block
 // settle drops it from state.wallet.utxos and a smaller change UTXO
 // takes its place), our `recv` key still points at the dead one. Snap
 // back to the new smallest eligible chip so the user always sees an
 // active chip ready to bet without having to manually re-select.
  useEffect(() => {
    if (!recv) {
      if (eligible[0]) setRecv(utxoKey(eligible[0]));
      return;
    }
    const stillThere = eligible.some((u) => utxoKey(u) === recv);
    if (!stillThere) setRecv(eligible[0] ? utxoKey(eligible[0]) : null);
  }, [state.wallet.utxos]); // eslint-disable-line react-hooks/exhaustive-deps
 // Phase machine for the new two-step protocol flow:
 // idle → user selects UTXO & taps ROLL
 // rolling → cup shakes, dice tumbles, lands on a random 1..6
 // rolled → pick is generated locally; user can RE-ROLL or MINE
 // revealing → block hash is being mined; brief "consensus" pause
 // revealed → block hash arrived; banner shows WIN/MISS, NEW ROUND ready
  const [phase, setPhase] = useState("idle");
  const [displayDie, setDisplayDie] = useState(1);
 // rolledDie is the SOLE source of truth for "what we landed on".
 // Both the dot+ODD/EVEN label and the pick string sent to OP_RETURN
 // derive from this single value, so a parity mismatch between the
 // visible label and the committed pick is impossible by construction.
 // (Earlier IRON kept `rolledPick` as an independent useState set
 // alongside `rolledDie`; if a race ever made one commit but not the
 // other, the label and OP_RETURN would diverge — same class of bug
 // GOLD just got refactored for.)
  const [rolledDie, setRolledDie] = useState(null);
  const rolledPick = rolledDie == null
    ? null
    : (rolledDie % 2 === 1 ? "odd" : "even");

 // (lastResult.iron was the mock outcome from the deleted 8s settle —
 // gone. Real outcome shows in SettleModal + MY BETS sidebar via
 // onChainBets.)
  const pendingMine = state.pendingMines.find((m) => m.tier === "iron");

 // Tumble face values during the rolling phase, then settle on a random
 // outcome and drop into the ROLLED phase. The user can re-roll from here
 // until they're happy, then commit to the mine pool by clicking MINE.
  const tumbleRef = useRef(null);
  useEffect(() => {
    if (phase !== "rolling") return;
    // Single setRolledDie clears both (since rolledPick derives from it).
    setRolledDie(null);
    sfxLever();
    tumbleRef.current = setInterval(() => {
      setDisplayDie(1 + Math.floor(Math.random() * 6));
    }, 90);
    const tEnd = setTimeout(() => {
      // rollPickFor returns { pick, die } where pick = (die%2===1 ?
      // "odd" : "even"). We only need to commit `die` — `rolledPick`
      // recomputes the parity label on the next render. This collapses
      // the previous three-setState batch (displayDie + rolledDie +
      // rolledPick) into two and removes the GOLD-class drift risk.
      const { die } = rollPickFor("iron");
      setDisplayDie(die);
      setRolledDie(die);
      sfxReelStop();
      setPhase("rolled");
    }, 2400);
    return () => {
      clearInterval(tumbleRef.current); tumbleRef.current = null;
      clearTimeout(tEnd);
    };
  }, [phase]);

 // (mock 8s tip_hash watcher removed — phases no longer transition
 // through revealing/revealed. Real outcome arrives via SettleModal +
 // MY BETS panel reading onChainBets.)

  const startRoll = () => {
 // pendingMine gate dropped — under the old mock 8s tick, settle()
 // cleared pendingMines so the user could roll again on the next
 // block; with the mock removed, pendingMines never clears and
 // would permanently lock the dice. Each MINE consumes its own UTXO
 // (gone from state.wallet.utxos after CHIP_EXIT_MS) so chained
 // rolls are safe.
    if (!recv) return;
    if (phase !== "idle" && phase !== "rolled") return;
    setPhase("rolling");
  };
 // Per-round submission lock. The "hasPending" guard alone is racy: when
 // settle clears pendingMines, hasPending flips back to false in the same
 // commit the watcher schedules setPhase("revealing"). The AI loop, firing
 // in that commit, sees phase still == "rolled" (the watcher's setPhase
 // is queued, not yet applied) AND !hasPending, so it schedules a SECOND
 // lockAndSettle for the same rolledPick. Cleanup usually clears that
 // timer in the next commit, but if it doesn't win the race, submitMine
 // gets called again and a second chip flies for the same pick.
 // This ref is the synchronous backstop — set the moment a mine is
 // submitted, cleared only when a brand-new round starts (phase →
 // idle/rolling). Nothing in the inter-render race can flip it.
  const submittedThisRoundRef = useRef(false);
  useEffect(() => {
    if (phase === "idle" || phase === "rolling") {
      submittedThisRoundRef.current = false;
    }
  }, [phase]);
  const lockAndSettle = () => {
    if (phase !== "rolled" || !rolledPick) return;
 // hasPending check removed
 //. Each bet uses a distinct UTXO (recv); the
 // submittedThisRoundRef + per-UTXO inflight ref in App's submitMine
 // are sufficient backstops against double-firing the same chip.
    if (submittedThisRoundRef.current) return;  // race backstop
    submittedThisRoundRef.current = true;
    submitMine("iron", rolledPick, recv);
 // After submit, immediately reset the room to idle so the user can
 // roll the next dice without waiting for the on-chain confirm. The
 // real outcome (~10 min later) is surfaced via SettleModal + the
 // MY BETS sidebar — both read directly from onChainBets. No
 // visual "revealing/revealed" stage anymore (those were driven by
 // the now-deleted mock 8s block tick).
    setTimeout(() => {
      setPhase("idle");
      setDisplayDie(1);
      // rolledPick is now derived from rolledDie — clearing rolledDie
      // alone resets the parity label too. Removed the redundant
      // setRolledPick(null) that the multi-state version needed.
      setRolledDie(null);
    }, 600);
  };

 // ==========================================================================
 // AI Copilot auto-play — single consolidated effect.
 // semiAuto — phase=idle → auto setPhase("rolling") (user clicks MINE)
 // fullAuto — semiAuto + phase=rolled → auto MINE, phase=revealed → auto NEW ROUND
 // Was 3 separate effects with `pendingMine` (an OBJECT reference) in the
 // deps array — that reference changes on every render, causing the
 // setTimeout to be cleared+re-scheduled every paint and never fire. Fixed
 // by using a primitive `hasPending` derived from pendingMine.id.
 // ==========================================================================
  const hasPending = !!pendingMine;
 // AI auto-loop. Now only two phases matter (idle / rolled) since the
 // revealing/revealed mock stages are gone — lockAndSettle resets
 // straight to idle 600ms after MINE, so the idle branch fires the
 // next ROLL automatically. The `!hasPending` guard was dropped here
 // for the same reason as the startRoll/startSpin gates above:
 // pendingMines never clears now that the mock 8s tick is gone, so
 // gating on it permanently freezes auto-mode after the first MINE.
 // submittedThisRoundRef + per-UTXO inflight ref still prevent
 // double-firing the same chip in the same phase.
  useEffect(() => {
    if (aiMode === "manual") return undefined;
    let t = null;
    if (phase === "idle" && recv) {
      t = setTimeout(() => setPhase("rolling"), 700);
    } else if (phase === "rolled" && rolledPick && aiMode === "fullAuto") {
      t = setTimeout(() => lockAndSettle(), 900);
    }
    return () => { if (t) clearTimeout(t); };
  }, [aiMode, phase, recv, rolledPick]); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <RoomShell tier={tier} goRoom={goRoom} goDashboard={goDashboard} state={state}>

      <div className="room-scene">
        <div className={`sicbo-table ${phase === "rolling" ? "shaking" : ""}`}
             style={{ backgroundImage: `url(${ASSETS.dice_cup})` }}>
          {/* under-cup red glow during shake */}
          <div className={`sicbo-cup-glow ${phase === "rolling" ? "active" : ""}`} />

          {/* dice arena */}
          <div className="sicbo-arena">
            <div className={`sicbo-orbit ${phase === "rolling" ? "rolling" : ""}`}>
              <Die
                value={displayDie}
                rolling={phase === "rolling"}
                settled={phase !== "idle" && phase !== "rolling"}
                idle={phase === "idle"}
              />
            </div>
          </div>

        </div>

        {/* result strip removed per user request — the BetHistoryPanel
            on the right rail and the SettleModal already surface the
            outcome with mempool tx + reward; an extra italic line below
            the cup just duplicated info. */}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 16, marginTop: 8 }}>
        <UTXOSelectStrip state={state} tier={tier} value={recv} onChange={setRecv} exitingUtxoKeys={exitingUtxoKeys} />
        <div style={{ display: "flex", flexDirection: "column", gap: 6, justifyContent: "flex-start", paddingTop: 18 }}>
          {phase === "idle" && (
            <button className={`hxm-btn-cta ${recv ? "glow" : ""}`} onClick={startRoll} disabled={!recv}
                    style={{ padding: "13px 18px", fontSize: 14 }}>
              <Zap size={13}/> ROLL DIE
            </button>
          )}
          {phase === "rolling" && (
            <div style={{
              textAlign: "center", color: "var(--hxm-gold-bright)",
              fontSize: 12, fontStyle: "italic", padding: "13px 18px",
              border: "1px dashed var(--hxm-line-2)", borderRadius: 6,
            }}>
              <Activity size={11} style={{ display: "inline", verticalAlign: "-1px", marginRight: 5 }}/>
              Rolling…
            </div>
          )}
          {phase === "rolled" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              <button className="hxm-btn-cta" onClick={startRoll}
                      style={{ padding: "11px 18px", fontSize: 13 }}>
                <RefreshCw size={12}/> RE-ROLL
              </button>
              <button className="hxm-btn-cta glow" onClick={lockAndSettle}
                      style={{ padding: "11px 18px", fontSize: 13 }}>
                <Lock size={12}/> MINE
              </button>
            </div>
          )}
          {/* revealing / revealed / NEW ROUND buttons removed — phase
              auto-resets to idle 600ms after MINE click (see lockAndSettle). */}
          {/* Two equal-width buttons below the per-phase action button —
              MINE (instant on-chain bet, disabled while a previous bet
              for the active token is still settling) + FEE (fee-rate
              picker dropdown). */}
          <RoomBottomActions
            tier={tier}
            state={state}
            submitMine={submitMine}
            sessionPassword={sessionPassword}
            setToast={setToast}
            onChainBets={onChainBets}
            walletMeta={walletMeta}
            recv={recv}
            hideMine={phase === "rolled"}
          />
        </div>
      </div>

    </RoomShell>
  );
}


// Real 3D die — Three.js BoxGeometry with face textures painted on canvas at runtime.
// No external image loading, no async texture failures. WebGL renders a true cube.
function Die({ value, rolling, settled, idle = false }) {
  const mountRef = useRef(null);
  const stateRef = useRef({ rolling: false, value: 1 });

 // Always update the latest props for the animation loop to read
  useEffect(() => {
    stateRef.current = { rolling: !!rolling, value: value || 1 };
  }, [rolling, value]);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;
    if (typeof window === "undefined") return;

    const w = mount.clientWidth || 200;
    const h = mount.clientHeight || 200;

 // Detect WebGL availability — bail out cleanly if missing so we still see SOMETHING
    let renderer;
    try {
      renderer = new WebGLRenderer({ antialias: true, alpha: true });
    } catch (e) {
 // fallback: just show a placeholder
      mount.innerHTML = '<div style="width:100%;height:100%;background:#fff;border-radius:12%;border:2px solid #2a2218;"></div>';
      return;
    }
    renderer.setPixelRatio(window.devicePixelRatio || 1);
    renderer.setSize(w, h);
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    const scene = new Scene();
    const camera = new PerspectiveCamera(35, w / h, 0.1, 100);
 /* Camera pulled in slightly from z=6.4 → z=5.7 so the die appears
       ~12% larger ("[redacted]" feedback). Going closer than ~5.5 risks
       clipping the corners of the rounded cube against the perspective
       frustum's near plane. */
    camera.position.set(0, 0, 5.7);

 // Crank ambient + directional + add a warm fill light so the dice glows
 // off the red velvet instead of looking dim/gray. Boosted +20-25% per
 //. Previously ambient 1.35 / top 0.85 /
 // warm 0.45 still read a touch dim against the casino's dark velvet.
    scene.add(new AmbientLight(0xffffff, 1.65));
    const topLight = new DirectionalLight(0xffffff, 1.05);
    topLight.position.set(1, 2, 2);
    scene.add(topLight);
 // Warm rim light from below-front pulls a subtle gold tint into the
 // shadow side, tying the dice into the casino color story without
 // washing out the white face.
    const warmFill = new DirectionalLight(0xffe6b3, 0.6);
    warmFill.position.set(-1.2, -0.8, 1.5);
    scene.add(warmFill);

 // Paint a face on a canvas, return a CanvasTexture
    function makeFace(val) {
      const C = 256;
      const cv = document.createElement("canvas");
      cv.width = C; cv.height = C;
      const ctx = cv.getContext("2d");

 // Bright pure-white face — reads as a luminous casino die against
 // the red velvet instead of a dim gray block. Slight subtle inset
 // shadow on the rim adds depth without dimming the center.
      ctx.fillStyle = "#ffffff";
      ctx.fillRect(0, 0, C, C);
 // Rim shadow — very subtle, only kicks in at the outer 6% so the
 // face still reads as full-bright from any angle.
      const rim = ctx.createRadialGradient(C/2, C/2, C*0.46, C/2, C/2, C*0.52);
      rim.addColorStop(0, "rgba(255,255,255,0)");
      rim.addColorStop(1, "rgba(0,0,0,0.10)");
      ctx.fillStyle = rim;
      ctx.fillRect(0, 0, C, C);

 // Pip layout
      const PIP_LAYOUT = {
        1: [[0.5, 0.5]],
        2: [[0.27, 0.27], [0.73, 0.73]],
        3: [[0.27, 0.27], [0.5, 0.5], [0.73, 0.73]],
        4: [[0.27, 0.27], [0.73, 0.27], [0.27, 0.73], [0.73, 0.73]],
        5: [[0.27, 0.27], [0.73, 0.27], [0.5, 0.5], [0.27, 0.73], [0.73, 0.73]],
        6: [[0.27, 0.27], [0.73, 0.27], [0.27, 0.5], [0.73, 0.5], [0.27, 0.73], [0.73, 0.73]],
      };
      const r = C * 0.085;
      ctx.fillStyle = "#1a1a1a";
      for (const [u, v] of (PIP_LAYOUT[val] || [])) {
        const cx = u * C, cy = v * C;
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.fill();
      }

      const tex = new CanvasTexture(cv);
      tex.colorSpace = SRGBColorSpace || tex.colorSpace;
      tex.anisotropy = renderer.capabilities.getMaxAnisotropy();
      return tex;
    }

 // BoxGeometry material order: [+X, -X, +Y, -Y, +Z, -Z]
 // Standard die: opposite faces sum to 7
 // We assign: +X=3, -X=4, +Y=1 (top), -Y=6, +Z=2 (front), -Z=5
    const materials = [
      new MeshLambertMaterial({ map: makeFace(3) }),
      new MeshLambertMaterial({ map: makeFace(4) }),
      new MeshLambertMaterial({ map: makeFace(1) }),
      new MeshLambertMaterial({ map: makeFace(6) }),
      new MeshLambertMaterial({ map: makeFace(2) }),
      new MeshLambertMaterial({ map: makeFace(5) }),
    ];

 // Rounded cube geometry: build a high-segment BoxGeometry and pull every
 // vertex toward a blended sphere/cube shape so corners become smooth.
 // r=0 gives a sharp cube, r=0.5 a sphere; we want ~0.18 for a nicely
 // chamfered die.
    function makeRoundedCube(size, segments, radius) {
      const geo = new BoxGeometry(size, size, size, segments, segments, segments);
      const pos = geo.attributes.position;
      const half = size / 2;
      const inner = half - radius;   // half-edge of the "core" cube
      for (let i = 0; i < pos.count; i++) {
        let x = pos.getX(i), y = pos.getY(i), z = pos.getZ(i);
 // Vector from the closest point on the inner cube to this vertex
        const cx = Math.max(-inner, Math.min(inner, x));
        const cy = Math.max(-inner, Math.min(inner, y));
        const cz = Math.max(-inner, Math.min(inner, z));
        let dx = x - cx, dy = y - cy, dz = z - cz;
        const d = Math.hypot(dx, dy, dz);
        if (d > 1e-6) {
 // Normalize and scale to `radius` from the core
          const k = radius / d;
          x = cx + dx * k;
          y = cy + dy * k;
          z = cz + dz * k;
          pos.setXYZ(i, x, y, z);
        }
      }
      geo.computeVertexNormals();
      return geo;
    }

    const geom = makeRoundedCube(1.6, 8, 0.32);
    const cube = new Mesh(geom, materials);
 // Initial pose — face value 1 toward camera (default Three.js scene orientation)
    cube.rotation.x = Math.PI / 2;
    scene.add(cube);

 // Camera looks down +Z axis. The face on +Z is what's visible head-on.
 // Material order: +X=3, -X=4, +Y=1, -Y=6, +Z=2, -Z=5
 // Default (no rotation): +Z = 2 is facing camera.
 // Map value → rotation that brings that value's face to +Z (camera-facing).
    const VALUE_REST = {
      1: { x:  Math.PI/2, y: 0, z: 0 },     // +Y(=1) → +Z: rotate +90° around X
      6: { x: -Math.PI/2, y: 0, z: 0 },     // -Y(=6) → +Z: rotate -90° around X
      2: { x: 0,          y: 0, z: 0 },     // +Z(=2) already facing camera
      5: { x: 0,          y: Math.PI, z: 0 }, // -Z(=5) → +Z: rotate 180° around Y
      3: { x: 0,          y: -Math.PI/2, z: 0 }, // +X(=3) → +Z: rotate -90° around Y
      4: { x: 0,          y:  Math.PI/2, z: 0 }, // -X(=4) → +Z: rotate +90° around Y
    };
    const TILT_X = 0;
    const TILT_Y = 0;

    let raf = 0;
    const clock = new ThreeClock();
    let velX = 0, velY = 0, velZ = 0;
    let phase = "rest";
    let settleT0 = 0;
    let from = { x: 0, y: 0, z: 0 };
    let to   = { x: 0, y: 0, z: 0 };

    const tick = () => {
      const dt = Math.min(clock.getDelta(), 1/30);
      const s = stateRef.current;

      if (s.rolling) {
        if (phase !== "rolling") {
          phase = "rolling";
          velX = 8 + Math.random() * 5;     // faster spin
          velY = 9 + Math.random() * 5;
          velZ = 5 + Math.random() * 4;
        }
        cube.rotation.x += velX * dt;
        cube.rotation.y += velY * dt;
        cube.rotation.z += velZ * dt;
 // Position jitter — simulate dice bouncing inside the cup.
 // Use noisy oscillation: sum of two sine waves at different frequencies.
        const t = clock.elapsedTime;
        cube.position.x = Math.sin(t * 28) * 0.18 + Math.sin(t * 41 + 1.3) * 0.10;
        cube.position.y = Math.cos(t * 33) * 0.18 + Math.sin(t * 47 + 0.7) * 0.10;
        cube.position.z = Math.sin(t * 22 + 0.5) * 0.08;
      } else {
 // ease position back to center while settling
        cube.position.x *= 0.85;
        cube.position.y *= 0.85;
        cube.position.z *= 0.85;
        const r = VALUE_REST[s.value] || VALUE_REST[1];
        const tx = (r.x || 0) + TILT_X;
        const ty = (r.y || 0) + TILT_Y;
        const tz = (r.z || 0);

        if (phase === "rolling") {
          phase = "settling";
          settleT0 = clock.elapsedTime;
          from = { x: cube.rotation.x, y: cube.rotation.y, z: cube.rotation.z };
 // Snap target to the equivalent rotation closest to current angle
          const TWO_PI = Math.PI * 2;
          const nearest = (a, b) => a + (((b - a) % TWO_PI + TWO_PI + Math.PI) % TWO_PI - Math.PI);
          to = { x: nearest(from.x, tx), y: nearest(from.y, ty), z: nearest(from.z, tz) };
        }
        if (phase === "settling") {
          const k = Math.min(1, (clock.elapsedTime - settleT0) / 0.6);
          const e = 1 - Math.pow(1 - k, 3);
          cube.rotation.x = from.x + (to.x - from.x) * e;
          cube.rotation.y = from.y + (to.y - from.y) * e;
          cube.rotation.z = from.z + (to.z - from.z) * e;
          if (k >= 1) phase = "rest";
        }
 // phase === "rest": do nothing. Cube stays exactly at the settled angle.
 // (No drift toward tx — that would unwind the multi-revolution offset
 // applied by `nearest()` and cause an unwanted extra rotation.)
      }

      renderer.render(scene, camera);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);

    const ro = new ResizeObserver(() => {
      const W = mount.clientWidth, H = mount.clientHeight;
      if (W > 0 && H > 0) {
        renderer.setSize(W, H);
        camera.aspect = W / H;
        camera.updateProjectionMatrix();
      }
    });
    ro.observe(mount);

    return () => {
      cancelAnimationFrame(raf);
      ro.disconnect();
      materials.forEach(m => { if (m.map) m.map.dispose(); m.dispose(); });
      geom.dispose();
      renderer.dispose();
      if (renderer.domElement.parentNode) renderer.domElement.parentNode.removeChild(renderer.domElement);
    };
  }, []);

  return <div ref={mountRef} className="sicbo-die" />;
}

