// =============================================================================
// UTXO SCREEN — full UTXO manager ported from bitai-miner UtxoTab.
// Per-UTXO actions: SPLIT (BTC only) and SEND (BTC only). Token-bearing
// UTXOs are flagged red and locked from this tab — direct spend would burn
// the token. Pending (0-conf) UTXOs are also locked. Batch select multiple
// BTC UTXOs to drain them in one tx, or pick exactly one BTC UTXO and
// SPLIT it into N pieces. Sync banner gates everything (matches the
// bitminer assert_scan_synced contract).
// =============================================================================
function UtxoScreen({ state, setState, walletMeta, setToast, goDashboard, chainState, chainBusy, onChainSync, sessionPassword, setScreen, setActiveNav }) {
  const sync = useSyncStatus();

 // UTXOs are now sourced entirely from the chain — state.wallet.utxos is
 // hydrated by hydrateWalletFromChain after every successful sync. The
 // BTC UTXOs in this list are real on-chain UTXOs at the wallet's BIP84
 // address; token UTXOs (with a `.token` field) remain from the legacy
 // mock seed and will go away once the on-chain DEPLOY opcode lands.
  const utxos = state.wallet.utxos ?? [];
  const utxoKeyOf = (u) => `${u.txid}:${u.vout}`;
  const isLocked = (u) => !!u.token || (u.confirmations ?? 1) < 1;

 // STABLE SORT — the source `state.wallet.utxos` is rebuilt from chain.rs
 // after every sync, and the order it returns in is not guaranteed
 // between calls. Without a deterministic re-sort here the rows visibly
 // shuffle around on every ~5s wallet poll, making it impossible to
 // click a checkbox that's adjacent to one currently being repositioned.
 // Sort: confirmed UTXOs first (matches the "AVAILABLE → PENDING"
 // grouping shown in the panel), then by txid lexicographic, then by
 // vout numeric. Same chain state → same list order, every time.
  const _utxoSort = (a, b) => {
    const aConf = (a.confirmations ?? 1) > 0 ? 1 : 0;
    const bConf = (b.confirmations ?? 1) > 0 ? 1 : 0;
    if (aConf !== bConf) return bConf - aConf;
    if (a.txid !== b.txid) return a.txid < b.txid ? -1 : 1;
    return (a.vout ?? 0) - (b.vout ?? 0);
  };
  const btcUtxos   = utxos.filter((u) => !u.token).slice().sort(_utxoSort);
  const tokenUtxos = utxos.filter((u) =>  u.token).slice().sort(_utxoSort);
  const pendingCount = utxos.filter((u) => (u.confirmations ?? 1) < 1 && !u.token).length;

 // Per-UTXO action state
  const [activeUtxo, setActiveUtxo] = useState(null);
  const [actionMode, setActionMode] = useState(null); // "split" | "send" | null
  const [splitCount, setSplitCount] = useState("10");
  const [splitAmount, setSplitAmount] = useState("0.00010000");
  const [sendAddr, setSendAddr] = useState("");
  const [sendConfirm, setSendConfirm] = useState(false);
  const [feeRate, setFeeRateLocal] = useState(() => getFeeRateMock());
  const [msg, setMsg] = useState("");
  const [txid, setTxid] = useState(null);
  const [splitBusy, setSplitBusy] = useState(false);
 // Cooldown timestamp (ms since epoch) — after a successful split
 // broadcast, suppress the next doSplit() call until cooldown
 // expires. Stops the user from inadvertently broadcasting a CHAIN
 // of dependent splits (tx2 spending tx1's outputs) by re-clicking
 // SPLIT during the brief window between broadcast-complete and
 // chain-resync. Set in executeSplit's success path. 0 = no cooldown.
  const [splitCooldownUntil, setSplitCooldownUntil] = useState(0);
  const SPLIT_COOLDOWN_MS = 3000;
 // Pending-broadcast tracking — every split tx we broadcast appends
 // its txid here on success. Items are removed once the chain sync
 // confirms the tx OR when it's been pending for >1 hour (giveup).
 // The UTXO MANAGER header surfaces "N pending" so the user knows
 // there are in-flight broadcasts and can decide whether to wait
 // before launching another op. Pure UI state — bdk's wallet already
 // has authoritative pending-spend tracking via apply_unconfirmed_txs.
  const [pendingSplitTxs, setPendingSplitTxs] = useState([]);  // [{ txid, broadcast_at, count, amountSats }]
 // Post-broadcast success popup state — mirrors the DEPLOY / SEND
 // family's `success` state. When non-null, `SplitSuccessModal` is
 // mounted floating-center over the screen showing
 // "BROADCAST · awaiting confirmation" + txid + VIEW ON MEMPOOL.
 // Set in the executeSplit success path, cleared by the modal's X /
 // ESC. Previously the success feedback was a fleeting toast; users
 // asked for the persistent card matching DEPLOY's UX so they have
 // time to click through to mempool.space.
  const [splitSuccess, setSplitSuccess] = useState(null);

 // Auto-prune pendingSplitTxs entries that have either confirmed
 // on chain (we see any output spending FROM this txid in our
 // UTXO set, which can only happen post-confirmation) OR aged out
 // (>1 hour without confirming — drop and let the user manually
 // check the explorer). Runs whenever state.wallet.utxos changes
 // (i.e., after every chain sync). Cheap O(pending × utxos).
  useEffect(() => {
    if (pendingSplitTxs.length === 0) return undefined;
    const now = Date.now();
    const STALE_MS = 60 * 60 * 1000; // 1 hour
    const utxos = state?.wallet?.utxos || [];
 // A pending split is "confirmed" when at least one of its
 // outputs appears in our UTXO set with confirmed=true. (Bdk's
 // apply_unconfirmed_txs adds pending outputs as confirmed=false
 // first; chain sync flips them to confirmed=true once mined.)
    const confirmedTxids = new Set(
      utxos.filter((u) => u.confirmed === true).map((u) => u.txid)
    );
    const keep = pendingSplitTxs.filter((p) => {
      if (confirmedTxids.has(p.txid)) return false;       // mined → drop
      if (now - p.broadcast_at > STALE_MS) return false;  // aged out → drop
      return true;
    });
    if (keep.length !== pendingSplitTxs.length) {
      setPendingSplitTxs(keep);
    }
    return undefined;
  }, [state?.wallet?.utxos, pendingSplitTxs]);

 // Pending-confirmation dialog. When set, a modal blocks the screen and
 // asks the user to explicitly confirm before we sign + broadcast. Shape:
 // { kind: "split", count, amountSats, feeRateSatVb, sourceUtxo,
 // result?: { txid, fee_sats, vsize, network }, ← set on success
 // error?: string } ← set on failure
 // Replaces the per-op password input — the wallet password is held
 // session-wide in App's `sessionPassword` and reused for every on-chain
 // signing call. Confirmation here is the user's "yes, do it" gate.
  const [confirmAction, setConfirmAction] = useState(null);

 // Auto-dismiss the DONE state after 3 seconds. The txid is already
 // captured in state.logs + recent transfers, and the toast carries a
 // shorter version, so the user doesn't need the modal to stay open
 // forever. They can still click DONE / backdrop / X earlier — the
 // setTimeout is cleared on unmount/state change.
  const AUTO_DISMISS_MS = 3000;
  const [autoDismissProgress, setAutoDismissProgress] = useState(100);
  useEffect(() => {
    if (!confirmAction || confirmAction.kind !== "split" || !confirmAction.result) {
      setAutoDismissProgress(100);
      return undefined;
    }
    setAutoDismissProgress(100);
    const start = Date.now();
 // Tick the progress bar 30× per second so it feels smooth.
    const tickId = setInterval(() => {
      const elapsed = Date.now() - start;
      const pct = Math.max(0, 100 - (elapsed / AUTO_DISMISS_MS) * 100);
      setAutoDismissProgress(pct);
    }, 33);
    const closeId = setTimeout(() => setConfirmAction(null), AUTO_DISMISS_MS);
    return () => {
      clearInterval(tickId);
      clearTimeout(closeId);
    };
  }, [confirmAction?.kind, confirmAction?.result]);

 // Batch state
  const [batchSelected, setBatchSelected] = useState(new Set());
  const [batchAddr, setBatchAddr] = useState("");
  const [batchMode, setBatchMode] = useState(null); // "split" | "send" | null
  const [batchConfirm, setBatchConfirm] = useState(false);
  const [batchSending, setBatchSending] = useState(false);

  const addrPrefix = "bc1q";

  const triggerScan = async () => {
    if (!onChainSync) {
 // Fallback for non-Tauri / no chain wiring — keep the legacy mock
 // visual so the screen doesn't appear broken in browser preview.
      triggerScanMock();
      return;
    }
    try {
      await onChainSync();
    } catch (e) {
      setToast?.({ kind: "err", msg: `chain sync failed: ${String(e?.message ?? e).slice(0, 80)}` });
    }
  };

  const toggleUtxo = (key) => {
    if (activeUtxo === key) {
      setActiveUtxo(null); setActionMode(null);
    } else {
      setActiveUtxo(key); setActionMode(null);
    }
    setSendConfirm(false);
  };

  const toggleBatch = (key) => {
    setBatchSelected((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key); else next.add(key);
 // INLINE EXPANSION SHORTCUT — when the toggle results in EXACTLY
 // one selected UTXO, also engage the same per-row "active" view
 // that a direct row-click would (showing inline SPLIT / SEND
 // controls directly under the row). Without this, checking a
 // single checkbox only surfaced the floating bottom "1 SELECTED"
 // bar, forcing the user to scroll down to find SPLIT — and the
 // bar's distance from the actual UTXO row was disorienting on
 // long lists. When the user adds a SECOND checkbox we drop back
 // to "batch mode" (no inline expansion — the bottom bar is the
 // right place for multi-UTXO ops). Unchecking the only one
 // collapses the row too, so the UI is symmetric.
      if (next.size === 1) {
        const onlyKey = next.values().next().value;
        setActiveUtxo(onlyKey);
        setActionMode(null);
        setSendConfirm(false);
      } else {
 // 0 or 2+ selected — leave activeUtxo alone if the user got
 // there via direct row-click; otherwise close.
        if (prev.has(activeUtxo) || (next.size === 0 && activeUtxo === key)) {
          setActiveUtxo(null);
          setActionMode(null);
        }
      }
      return next;
    });
    setBatchConfirm(false);
    setBatchMode(null);
  };

  const selectedUtxos = utxos.filter((u) => batchSelected.has(utxoKeyOf(u)));
  const batchBtcCount = selectedUtxos.filter((u) => !u.token).length;
  const batchBtcTotal = selectedUtxos.filter((u) => !u.token).reduce((s, u) => s + u.sats, 0);
  const batchTokenCount = selectedUtxos.length - batchBtcCount;
  const isBtcBatch = batchBtcCount > 0 && batchTokenCount === 0;
  const canSplit   = isBtcBatch && batchBtcCount === 1;

 // `spendUtxos` was a mock helper that mutated state.wallet.utxos in
 // place after fake doSplit/doSend/doBatchSend. Removed — those flows
 // now broadcast real on-chain txs and rely on the next chain re-sync
 // to update state.wallet.utxos with the canonical post-broadcast view.

 // Two-stage split flow:
 // 1. doSplit(u) validates + opens the confirm modal. The user
 // sees a clear summary of what will happen and
 // has to click CONFIRM in the modal to proceed.
 // 2. executeSplit(...) actually signs + broadcasts via cmd_split_utxo.
 // Uses the App-level sessionPassword (set once
 // in Settings) so the user doesn't have to retype
 // their password for every on-chain action.
 // Coin selection is delegated to bdk; the `u` argument from the caller
 // is informational only and used for the pre-flight "do you have
 // enough sats?" check that surfaces a fast error before any signing.
  const doSplit = async (u) => {
    if (!sync.synced) { setMsg("operations locked — block scan still catching up"); return; }
 // In-flight guard — refuse during an active broadcast. Previously
 // this `return` was silent, so a user who didn't see the toast
 // would re-click and accidentally chain a tx2 onto tx1's mempool
 // outputs. Now we surface the wait explicitly.
    if (splitBusy) {
      setToast({
        kind: "warn",
        msg: "a split is still broadcasting — wait for it to land before queueing another",
      });
      return;
    }
 // Cooldown — even after broadcast completes, give bdk's chain
 // sync a few seconds to register the spent inputs before allowing
 // the next split. Without this gap, the next split sees the just-
 // broadcast tx's outputs as available UTXOs and constructs a
 // CHILD tx spending them (the exact scenario the user hit
 // accidentally). The 3s window is long enough for a full chain
 // re-sync to land + short enough that a deliberate-second-split
 // workflow doesn't feel sluggish.
    const now = Date.now();
    if (now < splitCooldownUntil) {
      const remainSec = Math.ceil((splitCooldownUntil - now) / 1000);
      setToast({
        kind: "warn",
        msg: `previous split just landed — wait ${remainSec}s for chain sync to settle (prevents accidental chained spend)`,
      });
      return;
    }
    const cnt = parseInt(splitCount, 10);
    const amt = Math.floor(parseFloat(splitAmount || "0") * 1e8);
    const DUST = 546;
    if (cnt < 1)              { setMsg("count must be >= 1"); return; }
    if (cnt > 200)            { setMsg("count too high (max 200)"); return; }
    if (!Number.isFinite(amt) || amt < DUST) {
      setMsg(`amount must be >= ${(DUST / 1e8).toFixed(8)} BTC (dust limit)`); return;
    }
    if (!sessionPassword) {
      setMsg("");
      setToast({
        kind: "warn",
        msg: "wallet password not unlocked this session — open SETTINGS → Wallet password",
      });
      return;
    }
    setMsg("");
    setConfirmAction({
      kind: "split",
      count: cnt,
      amountSats: amt,
      feeRateSatVb: parseFloat(feeRate || "1") || 1,
      sourceUtxo: u,
    });
  };

 // Actual broadcast — called from the confirm modal's CONFIRM button.
 // Three modal states transition through here:
 // 1. "split" + result=null + splitBusy=false → INITIAL CONFIRM (CANCEL/CONFIRM)
 // 2. "split" + result=null + splitBusy=true → BROADCASTING
 // 3. "split" + result.txid set → DONE — show clickable txid + DONE button
 // Errors collapse the modal back to closed (toast surfaces the error).
  const executeSplit = async () => {
    if (!confirmAction || confirmAction.kind !== "split") return;
    if (confirmAction.result) return;  // already broadcast — modal is in DONE state
    const { count, amountSats, feeRateSatVb } = confirmAction;
 // CLOSE the modal immediately so the user isn't trapped staring at
 // "BROADCASTING..." while bdk runs a 5-30s full_scan (especially on
 // the first signed op after a wallet wipe / fresh install). All
 // subsequent feedback — progress, success txid, error detail — is
 // surfaced via the toast layer + LEDGER log entry. Matches the
 // inline-toast UX of MINE / SEND / DEPLOY buttons; no signed
 // operation should hold the UI captive on a network round-trip.
    setConfirmAction(null);
    setSplitBusy(true);
    setMsg("");
    setToast({
      kind: "info",
      msg: `signing + broadcasting split · ${count} × ${(amountSats / 1e8).toFixed(8)} BTC…`,
    });
    try {
      const result = await txSplitUtxo({
        count,
        amountSats,
        password: sessionPassword,
        network: walletMeta?.network || "bitcoin",
        feeRateSatVb,
      });
      setSplitBusy(false);
      const newTxid = result.txid;
      setMsg("");
      setTxid(newTxid);
 // Engage 3s cooldown — see doSplit comment for rationale (give
 // bdk + chain sync time to register spent inputs before another
 // split can chain onto unconfirmed outputs).
      setSplitCooldownUntil(Date.now() + SPLIT_COOLDOWN_MS);
 // Record into pendingSplitTxs so the UTXO MANAGER banner can
 // surface "N pending broadcast" until confirmation. Auto-prune
 // effect lives in a separate useEffect that watches chainState
 // for inclusion of these txids.
      setPendingSplitTxs((prev) => [
        ...prev,
        {
          txid: newTxid,
          broadcast_at: Date.now(),
          count,
          amountSats,
        },
      ]);
 // Self-tx — the split sends count×amountSats to external[0] (via
 // peek_address) and drain_to puts the change back to external[0]
 // too. So both sent_sats and received_sats are non-zero.
      recordLocalTx({
        txid: newTxid,
        kind: "split",
        payload: null,
        fee_sats: result.fee_sats,
        vsize: result.vsize,
        network: result.network || walletMeta?.network || "bitcoin",
 // Approximate: input = count × amount + fee + change. We don't
 // know the exact picked input without a bdk lookup, so use the
 // gross output as the sent figure — Esplora will replace with
 // canonical numbers once the tx indexes.
        sent_sats: count * amountSats + (result.fee_sats || 0),
        received_sats: count * amountSats,
      });
 // Pop the persistent SplitSuccessModal — same shape & position as
 // DeploySuccessModal / TransferSuccessModal so the user gets a
 // consistent "BROADCAST · awaiting confirmation" card with the
 // txid + VIEW ON MEMPOOL button. The earlier
 // `setConfirmAction((prev) => ...)` was a no-op (prev is null
 // because we closed the confirm modal at line 18110 immediately
 // after the user clicked CONFIRM); the inline DONE state inside
 // that modal therefore never rendered, leaving the user with only
 // a toast as feedback. SplitSuccessModal replaces that gap.
      setSplitSuccess({
        count,
        amountSats,
        txid: newTxid,
        network: result.network || (walletMeta?.network || "bitcoin"),
      });
      setActiveUtxo(null); setActionMode(null);
      setState((s) => ({
        ...s,
        logs: [{
          ts: ts(), kind: "ok",
          msg: `BTC split // ${count} pieces × ${(amountSats / 1e8).toFixed(8)} BTC // txid ${newTxid.slice(0, 8)}… // fee ${result.fee_sats} sat // vsize ${result.vsize} vB`,
        }, ...s.logs].slice(0, 80),
      }));
      setToast({ kind: "ok", msg: `Split broadcast — ${count} pieces · txid ${newTxid.slice(0, 8)}…` });
 // Re-sync chain so the consumed UTXO disappears + the N new pending
 // UTXOs show up. They'll be unconfirmed until the next block; the
 // LIVE CHAIN panel's amber "+ N sat pending" row surfaces them in
 // the meantime.
      if (onChainSync) {
        onChainSync().catch(() => { /* surfaced elsewhere */ });
      }
    } catch (e) {
      setSplitBusy(false);
      const errStr = String(e?.message ?? e);
      setMsg(`split broadcast failed: ${errStr}`);
      setToast({ kind: "err", msg: `split failed: ${errStr.slice(0, 80)}` });
 // Keep the modal open so the user can RETRY without re-typing all the
 // params. Stash the error onto confirmAction; the modal renders an
 // error block + RETRY/DISMISS buttons when error is set. Common
 // failure mode that benefits from this: transient mempool.space
 // hiccups (IncompleteMessage / 5xx) — the Rust backend already
 // retries 4×, but if even that fails, one more user click is
 // usually enough.
      setConfirmAction((prev) =>
        prev && prev.kind === "split"
          ? { ...prev, error: errStr }
          : prev
      );
    }
  };

 // Real on-chain send. Was previously local-only mock with fakeTxid().
 // Routes through cmd_send_to_address → bdk_wallet → mempool.space POST /tx.
 // Coin selection is delegated to bdk; the `u` argument is informational.
 // The whole UTXO is drained: send `u.sats - estimated_fee` to the
 // recipient. bdk handles fee deduction precisely from the change/output
 // when SetMax-style is requested.
  const doSend = async (u) => {
    if (!sync.synced) { setMsg("operations locked — block scan still catching up"); return; }
    if (!sendAddr) { setMsg("address required"); return; }
    if (!sendAddr.toLowerCase().startsWith(addrPrefix)) { setMsg(`recipient must start with "${addrPrefix}…"`); return; }
    if (!sessionPassword) {
      setMsg("");
      setToast({ kind: "warn", msg: "wallet locked — open SETTINGS to unlock" });
      return;
    }
    if (!sendConfirm) { setSendConfirm(true); return; }
    setSendConfirm(false);

 // Estimate fee for a 1-in / 1-out P2WPKH tx (the recipient field doesn't
 // know about change, so we pre-deduct fee from the chosen UTXO's sats).
    const rate = parseFloat(feeRate || "1") || 1;
    const vsize = 11 + 68 + 31; // 1 input, 1 output, no change
    const fee = Math.ceil(vsize * rate);
    const sendAmtSats = (u?.sats ?? 0) - fee;
    if (sendAmtSats < 546) {
      setMsg(`UTXO too small for send + fee (need >${fee + 546} sat)`);
      return;
    }

    setMsg("decrypting key + scanning chain + signing...");
    try {
      const result = await txSendToAddress({
        toAddress: sendAddr.trim(),
        amountSats: sendAmtSats,
        password: sessionPassword,
        network: walletMeta?.network || "bitcoin",
        feeRateSatVb: rate,
      });
      const newTxid = result.txid;
      setMsg("");
      setTxid(newTxid);
 // Single-UTXO send — drain a specific BTC UTXO to a recipient.
 // sendAmtSats already excludes the fee.
      recordLocalTx({
        txid: newTxid,
        kind: "send",
        payload: null,
        fee_sats: result.fee_sats,
        vsize: result.vsize,
        network: result.network || walletMeta?.network || "bitcoin",
        sent_sats: sendAmtSats + (result.fee_sats || 0),
        received_sats: 0,
      });
      setActiveUtxo(null); setActionMode(null);
      setSendAddr("");
      setState((s) => ({
        ...s,
        logs: [{
          ts: ts(), kind: "ok",
          msg: `BTC sent // ${(sendAmtSats / 1e8).toFixed(8)} → ${sendAddr.slice(0, 10)}…${sendAddr.slice(-6)} // txid ${newTxid.slice(0, 8)}… // fee ${result.fee_sats} sat // vsize ${result.vsize} vB`,
        }, ...s.logs].slice(0, 80),
      }));
      setToast({ kind: "ok", msg: `UTXO sent · txid ${newTxid.slice(0, 8)}…` });
      if (onChainSync) onChainSync().catch(() => {});
    } catch (e) {
      const errStr = String(e?.message ?? e);
      setMsg(`send failed: ${errStr}`);
      setToast({ kind: "err", msg: `send failed: ${errStr.slice(0, 80)}` });
    }
  };

 // Real on-chain batch send. Drains the full balance to a single recipient.
 // bdk's coin selector picks all/whichever inputs are needed; the user's
 // selection is treated as a hint (we just sum batchBtcTotal for the
 // user-facing amount preview).
  const doBatchSend = async () => {
    if (!sync.synced) { setMsg("operations locked — block scan still catching up"); return; }
    if (!batchAddr) { setMsg("address required"); return; }
    if (!batchAddr.toLowerCase().startsWith(addrPrefix)) { setMsg(`recipient must start with "${addrPrefix}…"`); return; }
    if (!isBtcBatch) { setMsg("batch send: BTC UTXOs only"); return; }
    if (!sessionPassword) {
      setMsg("");
      setToast({ kind: "warn", msg: "wallet locked — open SETTINGS to unlock" });
      return;
    }
    if (!batchConfirm) { setBatchConfirm(true); return; }
    setBatchConfirm(false); setBatchSending(true);

    const rate = parseFloat(feeRate || "1") || 1;
 // Estimate fee for an N-in / 1-out P2WPKH tx (drain all selected to recipient).
    const vsize = 11 + 68 * batchBtcCount + 31;
    const fee = Math.ceil(vsize * rate);
    const sendAmtSats = batchBtcTotal - fee;
    if (sendAmtSats < 546) {
      setBatchSending(false);
      setMsg(`selection too small for fee (need > ${fee + 546} sat total)`);
      return;
    }

    setMsg("decrypting key + scanning chain + signing batch...");
    try {
      const result = await txSendToAddress({
        toAddress: batchAddr.trim(),
        amountSats: sendAmtSats,
        password: sessionPassword,
        network: walletMeta?.network || "bitcoin",
        feeRateSatVb: rate,
      });
      const newTxid = result.txid;
 // Batch BTC send — drains all selected UTXOs to a single
 // recipient. sendAmtSats already excludes fee.
      recordLocalTx({
        txid: newTxid,
        kind: "send",
        payload: null,
        fee_sats: result.fee_sats,
        vsize: result.vsize,
        network: result.network || walletMeta?.network || "bitcoin",
        sent_sats: sendAmtSats + (result.fee_sats || 0),
        received_sats: 0,
      });
      setBatchSelected(new Set());
      setBatchAddr("");
      setBatchMode(null);
      setBatchSending(false);
      setTxid(newTxid);
      setMsg("");
      setState((s) => ({
        ...s,
        logs: [{
          ts: ts(), kind: "ok",
          msg: `BTC batch sent // ${(sendAmtSats / 1e8).toFixed(8)} → ${batchAddr.slice(0, 10)}…${batchAddr.slice(-6)} // txid ${newTxid.slice(0, 8)}… // fee ${result.fee_sats} sat`,
        }, ...s.logs].slice(0, 80),
      }));
      setToast({ kind: "ok", msg: `Batch sent ${(sendAmtSats / 1e8).toFixed(8)} BTC · txid ${newTxid.slice(0, 8)}…` });
      if (onChainSync) onChainSync().catch(() => {});
    } catch (e) {
      setBatchSending(false);
      const errStr = String(e?.message ?? e);
      setMsg(`batch send failed: ${errStr}`);
      setToast({ kind: "err", msg: `batch send failed: ${errStr.slice(0, 80)}` });
    }
  };

  const doBatchSplit = async () => {
    const u = selectedUtxos.find((x) => !x.token);
    if (!u) { setMsg("no BTC utxo selected"); return; }
    await doSplit(u);
    setBatchSelected(new Set());
    setBatchMode(null);
  };

  const formatBtc = (sats) => (sats / 1e8).toFixed(8);
 // LUCKYPROTOCOL tokens are raw integer counts (iron win = 100, gold = 200,000;
 // supply cap = 21M). Earlier this divided by 1e8 like BTC sats →
 // rendered 100 LUCKYPROTOCOL as "0.0000". Fixed to plain integer with
 // locale thousands separators, matching WalletScreen / TransferScreen.
  const formatTokenAmt = (n) => Number(n || 0).toLocaleString();

  const renderUtxo = (u) => {
    const key = utxoKeyOf(u);
    const token = u.token;
    const pending = (u.confirmations ?? 1) < 1;
    const locked = !!token || pending;
    const active = activeUtxo === key;
 // Unified UTXO color scheme:
 // - protocol-token UTXO → RED (locked, would burn token if spent)
 // - pending (0-conf) → AMBER (yellow — wait for confirmation)
 // - confirmed BTC → GREEN (available + spendable)
    const accent = token ? "var(--hxm-red)"
                  : pending ? "var(--hxm-amber)"
                  : "var(--hxm-green-dim)";
    const accentBright = token ? "var(--hxm-red)"
                       : pending ? "var(--hxm-amber)"
                       : "var(--hxm-green)";

    return (
      <div
        key={key}
        onClick={() => !locked && toggleUtxo(key)}
        style={{
          border: `1px solid ${accent}`,
          background: token
            ? "linear-gradient(180deg, rgba(40,4,8,0.55), rgba(20,2,4,0.85))"
            : pending
              ? "linear-gradient(180deg, rgba(40,24,4,0.45), rgba(20,12,2,0.85))"
              : "linear-gradient(180deg, rgba(8,28,16,0.55), rgba(4,16,8,0.85))",
          borderRadius: 3,
          padding: "10px 12px",
          marginBottom: 8,
          cursor: locked ? "not-allowed" : "pointer",
          transition: "border-color 0.15s, box-shadow 0.15s",
        }}
      >
        {/* Row 1 */}
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <input
            type="checkbox"
            checked={!locked && batchSelected.has(key)}
            disabled={locked}
            onClick={(e) => e.stopPropagation()}
            onChange={(e) => { e.stopPropagation(); if (!locked) toggleBatch(key); }}
            style={{
              width: 16, height: 16, flexShrink: 0,
              accentColor: accentBright,
              cursor: locked ? "not-allowed" : "pointer",
              opacity: locked ? 0.35 : 1,
            }}
            title={token ? "protocol token UTXO — locked" : pending ? "pending — wait for confirmation" : "confirmed — available to spend"}
          />
          <span className="hxm-mono" style={{
            fontSize: 14, fontWeight: 600,
            color: accentBright,
            minWidth: 150,
          }}>
            {formatBtc(u.sats)} BTC
          </span>
          {token ? (
            <span className="hxm-bebas" style={{
              fontSize: 11, letterSpacing: "0.16em",
              color: "var(--hxm-red)",
              border: "1px solid var(--hxm-red)",
              padding: "2px 8px", borderRadius: 2,
            }}>
              <Lock size={10} style={{ verticalAlign: "-1px", marginRight: 4 }} />
              {token.ticker} · {formatTokenAmt(token.amount)}
            </span>
          ) : (
            <span className="hxm-bebas" style={{
              fontSize: 11, letterSpacing: "0.16em",
              color: accentBright,
              border: `1px solid ${accent}`,
              padding: "2px 8px", borderRadius: 2,
            }}>
              ₿ BTC{pending ? " · PENDING" : " · AVAILABLE"}
            </span>
          )}
          <span className="hxm-mono" style={{
            fontSize: 10,
            color: pending ? "var(--hxm-amber)" : token ? "var(--hxm-red)" : "var(--hxm-green)",
            marginLeft: "auto",
          }}>
            {u.confirmations ?? 0} conf
          </span>
        </div>

        {/* Row 2: txid — clickable to mempool.space (network-aware via helper) */}
        <div style={{ marginTop: 6, fontSize: 10, color: "var(--hxm-text-mute)", fontFamily: "'JetBrains Mono', monospace" }}>
          <a
            href={txExplorerUrl(walletMeta?.network || "bitcoin", u.txid)}
            target="_blank"
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            style={{ color: "var(--hxm-gold-bright)", textDecoration: "underline", wordBreak: "break-all" }}
            title="open on mempool.space"
          >
            {u.txid.slice(0, 18)}…{u.txid.slice(-12)}:{u.vout}
          </a>
        </div>

        {/* Expanded actions */}
        {active && !locked && (
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              marginTop: 10,
              paddingTop: 10,
              borderTop: "1px solid var(--hxm-line)",
            }}
          >
            <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
              <button
                className={"btx-btn-ghost " + (actionMode === "split" ? "is-active" : "")}
                style={{
                  fontSize: 11, padding: "6px 14px",
                  borderColor: actionMode === "split" ? "var(--hxm-gold-bright)" : undefined,
                  color: actionMode === "split" ? "var(--hxm-gold-bright)" : undefined,
                }}
                onClick={() => setActionMode(actionMode === "split" ? null : "split")}
                disabled={!sync.synced}
              >
                <Scissors size={12} /> SPLIT
              </button>
              <button
                className={"btx-btn-ghost " + (actionMode === "send" ? "is-active" : "")}
                style={{
                  fontSize: 11, padding: "6px 14px",
                  borderColor: actionMode === "send" ? "var(--hxm-gold-bright)" : undefined,
                  color: actionMode === "send" ? "var(--hxm-gold-bright)" : undefined,
                }}
                onClick={() => setActionMode(actionMode === "send" ? null : "send")}
                disabled={!sync.synced}
              >
                <Send size={12} /> SEND
              </button>
            </div>

            {actionMode === "split" && (() => {
              const cnt = parseInt(splitCount, 10) || 0;
              const amtSats = Math.floor(parseFloat(splitAmount || "0") * 1e8);
              const vsize = 11 + 68 + (cnt + 1) * 31;
              const fee = Math.ceil(vsize * parseFloat(feeRate || "1"));
              const totalCost = cnt * amtSats + fee;
              const change = u.sats - totalCost;
              return (
                <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
                  <div>
                    <div className="btx-panel-label">COUNT</div>
                    <input type="number" min="1" max="200" value={splitCount}
                      onChange={(e) => setSplitCount(e.target.value)}
                      className="btx-input" style={{ width: 70, marginTop: 4, padding: "6px 8px", fontSize: 12 }} />
                  </div>
                  <div>
                    <div className="btx-panel-label">BTC EACH</div>
                    <input type="number" step="any" value={splitAmount}
                      onChange={(e) => setSplitAmount(e.target.value)}
                      placeholder="0.00010000"
                      className="btx-input" style={{ width: 130, marginTop: 4, padding: "6px 8px", fontSize: 12 }} />
                  </div>
                  <div>
                    <div className="btx-panel-label">FEE (sat/vB)</div>
                    <input type="number" min="0.1" step="0.1" value={feeRate}
                      onChange={(e) => setFeeRateLocal(e.target.value)}
                      className="btx-input" style={{ width: 70, marginTop: 4, padding: "6px 8px", fontSize: 12 }} />
                  </div>
                  <div className="hxm-mono" style={{ fontSize: 10, color: "var(--hxm-text-dim)", flex: "1 1 100%", marginTop: 4 }}>
                    total: {formatBtc(cnt * amtSats)} + fee {formatBtc(fee)} = {formatBtc(totalCost)} BTC
                    {change >= 0
                      ? <span style={{ color: "var(--hxm-green)", marginLeft: 12 }}>change: {formatBtc(change)} BTC</span>
                      : <span style={{ color: "var(--hxm-red)", marginLeft: 12 }}>insufficient on this UTXO ({formatBtc(Math.abs(change))} BTC short — bdk may still pull from others)</span>}
                  </div>
                  <button
                    className="btx-btn-primary"
                    style={{ padding: "8px 16px", fontSize: 12 }}
                    disabled={!sync.synced || splitBusy}
                    onClick={() => doSplit(u)}
                  >
                    {splitBusy ? "BROADCASTING..." : "SPLIT"}
                  </button>
                </div>
              );
            })()}

            {actionMode === "send" && (() => {
              const rate = parseFloat(feeRate) || 1;
              const vsize = 11 + 68 + 2 * 31;
              const fee = Math.ceil(vsize * rate);
              const sendAmt = u.sats - fee;
              return (
                <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
                  <div style={{ flex: 1, minWidth: 240 }}>
                    <div className="btx-panel-label">RECIPIENT ADDRESS</div>
                    <input
                      value={sendAddr}
                      onChange={(e) => { setSendAddr(e.target.value); setSendConfirm(false); }}
                      placeholder={`${addrPrefix}...`}
                      className="btx-input"
                      style={{ marginTop: 4, padding: "6px 8px", fontSize: 12 }}
                    />
                  </div>
                  <div>
                    <div className="btx-panel-label">FEE (sat/vB)</div>
                    <input type="number" min="0.1" step="0.1" value={feeRate}
                      onChange={(e) => setFeeRateLocal(e.target.value)}
                      className="btx-input" style={{ width: 70, marginTop: 4, padding: "6px 8px", fontSize: 12 }} />
                  </div>
                  <div className="hxm-mono" style={{ fontSize: 10, color: sendAmt > 0 ? "var(--hxm-text-dim)" : "var(--hxm-red)", flex: "1 1 100%" }}>
                    {sendAmt > 0
                      ? <>send: <b style={{ color: "var(--hxm-gold-bright)" }}>{formatBtc(sendAmt)} BTC</b> · fee ~{formatBtc(fee)} BTC</>
                      : "insufficient for fee"}
                  </div>
                  <button
                    className="btx-btn-primary"
                    style={{
                      padding: "8px 16px", fontSize: 12,
                      ...(sendConfirm ? {
                        background: "linear-gradient(180deg, #ffb84d 0%, #d4811e 50%, #6b3a08 100%)",
                        borderColor: "var(--hxm-amber)",
                      } : {}),
                    }}
                    disabled={sendAmt <= 0 || !sync.synced}
                    onClick={() => doSend(u)}
                  >
                    {sendConfirm ? `CONFIRM SEND ${formatBtc(sendAmt)} BTC?` : "SEND"}
                  </button>
                  {sendConfirm && (
                    <button className="btx-btn-ghost" onClick={() => setSendConfirm(false)} style={{ padding: "8px 12px", fontSize: 11 }}>
                      CANCEL
                    </button>
                  )}
                </div>
              );
            })()}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="btx-screen">
      <div className="btx-screen-head">
        <div>
          <div className="hxm-bebas" style={{ fontSize: 11, color: "var(--hxm-text-mute)", letterSpacing: "0.32em" }}>
            LUCKYPROTOCOL // UTXOS
          </div>
          <h2 className="hxm-cinzel metal-gold" style={{ margin: "4px 0 0", fontSize: 28, letterSpacing: "0.04em" }}>
            UTXO MANAGER
          </h2>
        </div>
      </div>

      <div style={{ marginTop: 18 }}>
        {!sync.synced
          ? <SyncBanner {...sync} />
          : <SyncedPill scanHeight={sync.scanHeight} tokenCount={sync.tokenCount} onScan={triggerScan} scanning={chainBusy} />
        }
      </div>

      {/* PENDING SPLIT BANNER — shown whenever there's at least one
          in-flight broadcast OR mid-broadcast op. Surfaces what would
          otherwise be invisible state: bdk's already done the split
          but the chain hasn't seen it yet, and clicking SPLIT again
          would chain a tx2 onto tx1's mempool outputs. The banner
          stays up until the chain sync flips the tx's outputs to
          confirmed=true (or 1 hour timeout). */}
      {(splitBusy || pendingSplitTxs.length > 0) && (
        <div style={{
          marginTop: 12,
          padding: "10px 14px",
          border: `1px solid ${splitBusy ? "var(--hxm-amber)" : "var(--hxm-gold-bright)"}`,
          background: splitBusy
            ? "linear-gradient(90deg, rgba(60,40,8,0.6), rgba(20,12,4,0.85))"
            : "linear-gradient(90deg, rgba(40,32,8,0.5), rgba(12,8,2,0.85))",
          borderRadius: 3,
          fontSize: 11.5,
          lineHeight: 1.6,
          display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap",
        }}>
          <span style={{
            display: "inline-flex", width: 22, height: 22, borderRadius: "50%",
            background: splitBusy ? "var(--hxm-amber)" : "var(--hxm-gold-dim)",
            color: "#1a0c00", fontWeight: 800, fontSize: 13,
            alignItems: "center", justifyContent: "center",
            animation: splitBusy ? "btx-spin 1.4s linear infinite" : undefined,
          }}>
            {splitBusy ? "…" : pendingSplitTxs.length}
          </span>
          <span className="hxm-mono" style={{
            color: splitBusy ? "var(--hxm-amber)" : "var(--hxm-gold-bright)",
            fontWeight: 600,
            flex: 1, minWidth: 0,
          }}>
            {splitBusy
              ? "split broadcast in progress — DO NOT start another op until this lands"
              : `${pendingSplitTxs.length} split tx${pendingSplitTxs.length === 1 ? "" : "s"} pending block confirmation — auto-clears when mined`}
          </span>
          {pendingSplitTxs.length > 0 && !splitBusy && (
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
              {pendingSplitTxs.slice(-3).map((p) => (
                <a
                  key={p.txid}
                  href={`https://mempool.space/tx/${p.txid}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="hxm-mono"
                  style={{
                    fontSize: 10,
                    color: "var(--hxm-gold)",
                    textDecoration: "underline",
                    padding: "3px 8px",
                    background: "rgba(0,0,0,0.4)",
                    border: "1px solid var(--hxm-line)",
                    borderRadius: 3,
                  }}
                  title={`Broadcast ${Math.round((Date.now() - p.broadcast_at) / 1000)}s ago · ${p.count} × ${(p.amountSats / 1e8).toFixed(8)} BTC`}
                >
                  {p.txid.slice(0, 10)}…
                </a>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Summary stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12 }}>
        {/* AVAILABLE = confirmed BTC UTXOs the user can spend right now.
            Painted green to match the per-row color scheme (green = ready,
            amber = waiting, red = locked). */}
        <div className="btx-panel" style={{
          textAlign: "center",
          borderColor: btcUtxos.length - pendingCount > 0 ? "var(--hxm-green-dim)" : undefined,
        }}>
          <div className="btx-panel-label" style={{
            color: btcUtxos.length - pendingCount > 0 ? "var(--hxm-green)" : "var(--hxm-text-mute)",
          }}>
            AVAILABLE BTC UTXOs
          </div>
          <div className="hxm-mono" style={{
            fontSize: 26, fontWeight: 600, marginTop: 4,
            color: btcUtxos.length - pendingCount > 0 ? "var(--hxm-green)" : "var(--hxm-text-mute)",
          }}>
            {btcUtxos.length - pendingCount}
          </div>
        </div>
        {/* PENDING = unconfirmed UTXOs (0-conf). Amber across the board. */}
        <div className="btx-panel" style={{
          textAlign: "center",
          borderColor: pendingCount > 0 ? "var(--hxm-amber)" : undefined,
        }}>
          <div className="btx-panel-label" style={{
            color: pendingCount > 0 ? "var(--hxm-amber)" : "var(--hxm-text-mute)",
          }}>
            PENDING UTXOs
          </div>
          <div className="hxm-mono" style={{
            fontSize: 26, fontWeight: 600, marginTop: 4,
            color: pendingCount > 0 ? "var(--hxm-amber)" : "var(--hxm-text-mute)",
          }}>
            {pendingCount}
          </div>
        </div>
        {/* LOCKED = protocol token UTXOs. Red — spending them would burn
            the token (no protocol-aware change handling at this layer). */}
        <div className="btx-panel" style={{
          textAlign: "center",
          borderColor: tokenUtxos.length > 0 ? "var(--hxm-red)" : undefined,
        }}>
          <div className="btx-panel-label" style={{
            color: tokenUtxos.length > 0 ? "var(--hxm-red)" : "var(--hxm-text-mute)",
          }}>
            TOKEN UTXOs (LOCKED)
          </div>
          <div className="hxm-mono" style={{
            fontSize: 26, fontWeight: 600, marginTop: 4,
            color: tokenUtxos.length > 0 ? "var(--hxm-red)" : "var(--hxm-text-mute)",
          }}>
            {tokenUtxos.length}
          </div>
        </div>
      </div>

      {/* Help text — color legend mirrors the per-UTXO border + amount
          coloring so users can read the list at a glance. */}
      <div style={{
        marginTop: 12,
        padding: "10px 12px",
        border: "1px solid var(--hxm-line)",
        background: "rgba(0,0,0,0.4)",
        borderRadius: 3,
        fontSize: 11, lineHeight: 1.7, color: "var(--hxm-text-dim)",
      }}>
        Click any unlocked UTXO to expand <b>SPLIT</b> / <b>SEND</b> actions.
        Use the checkboxes to batch-send several BTC UTXOs in one transaction,
        or pick exactly one to <b>SPLIT</b> it into N pieces.
        <br/>
        <span style={{ color: "var(--hxm-green)" }}>Green</span> = confirmed
        BTC UTXOs available to spend. <span style={{ color: "var(--hxm-amber)" }}>Amber</span> =
        pending (0-conf) UTXOs that need to wait for the next block.
        <span style={{ color: "var(--hxm-red)" }}> Red</span> = protocol-token
        UTXOs (locked — direct spend would burn the token; transfer them
        from the <b>WALLET</b> tab instead, which preserves token change).
      </div>

      {/* Batch select helpers */}
      {btcUtxos.filter((u) => (u.confirmations ?? 1) >= 1).length > 0 && (
        <div style={{ display: "flex", gap: 8, marginTop: 12, alignItems: "center", flexWrap: "wrap" }}>
          <button
            className="btx-btn-ghost"
            style={{ padding: "6px 14px", fontSize: 11 }}
            onClick={() => {
              const all = btcUtxos.filter((u) => (u.confirmations ?? 1) >= 1).map(utxoKeyOf);
              setBatchSelected(new Set(all));
              setBatchConfirm(false); setBatchMode(null);
            }}
          >
            SELECT ALL BTC ({btcUtxos.filter((u) => (u.confirmations ?? 1) >= 1).length})
          </button>
          {batchSelected.size > 0 && (
            <button
              className="btx-btn-ghost"
              style={{ padding: "6px 14px", fontSize: 11, opacity: 0.85 }}
              onClick={() => { setBatchSelected(new Set()); setBatchConfirm(false); setBatchMode(null); }}
            >
              CLEAR ({batchSelected.size})
            </button>
          )}
          <span style={{ marginLeft: "auto", fontSize: 10, color: "var(--hxm-text-mute)" }}>
            tokens excluded — use WALLET tab to send protocol tokens
          </span>
        </div>
      )}

      {/* Status / txid — txid links straight to mempool.space so the user
          can watch confirmations from outside the app. */}
      {(msg || txid) && (
        <div style={{ marginTop: 12 }}>
          {msg && (
            <div className="hxm-mono" style={{
              fontSize: 11,
              color: msg.includes("OK") ? "var(--hxm-green)" : "var(--hxm-red)",
            }}>{msg}</div>
          )}
          {txid && (
            <a
              href={txExplorerUrl(walletMeta?.network || "bitcoin", txid)}
              target="_blank"
              rel="noopener noreferrer"
              title="open on mempool.space"
              className="hxm-mono"
              style={{
                display: "block",
                fontSize: 11, color: "var(--hxm-gold-bright)",
                wordBreak: "break-all", marginTop: 4,
                textDecoration: "underline",
              }}
            >
              {txid}
            </a>
          )}
        </div>
      )}

      {/* UTXO list */}
      <div style={{ marginTop: 14 }}>
        {utxos.length === 0 && (
          <div style={{
            padding: 24, textAlign: "center", fontSize: 12, color: "var(--hxm-text-mute)",
            border: "1px dashed var(--hxm-line)", borderRadius: 3,
          }}>
            [ no UTXOs — deposit BTC to your wallet address first ]
          </div>
        )}
        {btcUtxos.map(renderUtxo)}
        {tokenUtxos.length > 0 && (
          <div className="hxm-bebas" style={{
            marginTop: 16, marginBottom: 10,
            fontSize: 11, letterSpacing: "0.22em",
            color: "var(--hxm-red)",
            display: "flex", alignItems: "center", gap: 8,
          }}>
            <Lock size={12} /> // PROTECTED — TOKEN-BEARING UTXOs
          </div>
        )}
        {tokenUtxos.map(renderUtxo)}
      </div>

      {/* Batch action bar — sticky at bottom of viewport */}
      {batchSelected.size > 0 && (() => {
        const splitUtxoPick = selectedUtxos.find((u) => !u.token);
        const splitCountN = parseInt(splitCount, 10) || 0;
        const splitAmtN = Math.floor(parseFloat(splitAmount || "0") * 1e8);
        const splitVsize = 11 + 68 + (splitCountN + 1) * 31;
        const splitFee = Math.ceil(splitVsize * (parseFloat(feeRate) || 1));
        const splitTotalCost = splitCountN * splitAmtN + splitFee;
        const splitChange = splitUtxoPick ? splitUtxoPick.sats - splitTotalCost : 0;
        return (
          <div style={{
            marginTop: 14,
            padding: "12px 14px",
            border: `1px solid ${isBtcBatch ? "var(--hxm-gold)" : "var(--hxm-red)"}`,
            background: "linear-gradient(180deg, rgba(40,20,4,0.55), rgba(20,8,4,0.85))",
            borderRadius: 3,
            display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap",
            boxShadow: "0 0 18px rgba(212,162,58,0.18)",
          }}>
            <span className="hxm-bebas" style={{ fontSize: 13, letterSpacing: "0.18em", color: "var(--hxm-gold-bright)" }}>
              {batchSelected.size} SELECTED
            </span>
            {isBtcBatch && (
              <span className="hxm-mono" style={{ fontSize: 13, color: "var(--hxm-gold-bright)" }}>
                {formatBtc(batchBtcTotal)} BTC
              </span>
            )}
            {!isBtcBatch && batchTokenCount > 0 && (
              <span className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-red)" }}>
                token UTXOs cannot be batched here
              </span>
            )}

            {batchMode === null && isBtcBatch && (
              <>
                {canSplit && (
                  <button className="btx-btn-ghost" style={{ padding: "7px 14px", fontSize: 11 }}
                    onClick={() => setBatchMode("split")} disabled={!sync.synced}>
                    <Scissors size={12} /> SPLIT
                  </button>
                )}
                <button className="btx-btn-primary" style={{ padding: "8px 16px", fontSize: 12 }}
                  onClick={() => setBatchMode("send")} disabled={!sync.synced}>
                  <Send size={12} style={{ marginRight: 6, verticalAlign: "-2px" }} />
                  SEND
                </button>
              </>
            )}

            {batchMode === "send" && isBtcBatch && (
              <>
                <input
                  value={batchAddr}
                  onChange={(e) => { setBatchAddr(e.target.value); setBatchConfirm(false); }}
                  placeholder={`${addrPrefix}...`}
                  className="btx-input"
                  style={{ flex: 1, minWidth: 200, padding: "6px 8px", fontSize: 12 }}
                />
                <input type="number" min="0.1" step="0.1" value={feeRate}
                  onChange={(e) => setFeeRateLocal(e.target.value)}
                  className="btx-input" style={{ width: 70, padding: "6px 8px", fontSize: 12 }} />
                <span style={{ fontSize: 10, color: "var(--hxm-text-mute)" }}>sat/vB</span>
                <button className="btx-btn-primary"
                  style={{
                    padding: "8px 14px", fontSize: 12,
                    ...(batchConfirm ? {
                      background: "linear-gradient(180deg, #ffb84d 0%, #d4811e 50%, #6b3a08 100%)",
                      borderColor: "var(--hxm-amber)",
                    } : {}),
                  }}
                  disabled={batchSending || !batchAddr || !sync.synced}
                  onClick={doBatchSend}
                >
                  {batchSending ? "SENDING..." : batchConfirm ? `CONFIRM ${formatBtc(batchBtcTotal)} BTC?` : "SEND"}
                </button>
                <button className="btx-btn-ghost" style={{ padding: "8px 12px", fontSize: 11 }}
                  onClick={() => { setBatchMode(null); setBatchConfirm(false); }}>
                  <ArrowLeft size={11} /> BACK
                </button>
              </>
            )}

            {batchMode === "split" && canSplit && (
              <>
                <span className="btx-panel-label">COUNT</span>
                <input type="number" min="1" max="200" value={splitCount}
                  onChange={(e) => setSplitCount(e.target.value)}
                  className="btx-input" style={{ width: 70, padding: "6px 8px", fontSize: 12 }} />
                <span className="btx-panel-label">BTC EACH</span>
                <input type="number" step="any" value={splitAmount}
                  onChange={(e) => setSplitAmount(e.target.value)}
                  placeholder="0.00010000"
                  className="btx-input" style={{ width: 130, padding: "6px 8px", fontSize: 12 }} />
                <span className="btx-panel-label">FEE</span>
                <input type="number" min="0.1" step="0.1" value={feeRate}
                  onChange={(e) => setFeeRateLocal(e.target.value)}
                  className="btx-input" style={{ width: 70, padding: "6px 8px", fontSize: 12 }} />
                <span className="hxm-mono" style={{ fontSize: 10, color: splitChange >= 0 ? "var(--hxm-text-dim)" : "var(--hxm-red)" }}>
                  {splitChange >= 0
                    ? <>fee ~{formatBtc(splitFee)} · change {formatBtc(splitChange)} BTC</>
                    : <>short {formatBtc(Math.abs(splitChange))} BTC</>}
                </span>
                <button className="btx-btn-primary" style={{ padding: "8px 14px", fontSize: 12 }}
                  disabled={splitChange < 0 || !sync.synced}
                  onClick={doBatchSplit}>
                  CONFIRM SPLIT
                </button>
                <button className="btx-btn-ghost" style={{ padding: "8px 12px", fontSize: 11 }}
                  onClick={() => setBatchMode(null)}>
                  <ArrowLeft size={11} /> BACK
                </button>
              </>
            )}

            <button
              onClick={() => { setBatchSelected(new Set()); setBatchConfirm(false); setBatchMode(null); }}
              style={{
                marginLeft: "auto",
                background: "transparent", border: "none", color: "var(--hxm-text-mute)",
                cursor: "pointer", fontSize: 18, padding: 4,
              }}
              title="Clear selection"
            >
              <X size={14} />
            </button>
          </div>
        );
      })()}

      {/* Post-broadcast success popup — same chrome as DeploySuccessModal
          / TransferSuccessModal. Floats centered, doesn't block clicks
          elsewhere. Closed via X or ESC. Mounted from executeSplit's
          success path via setSplitSuccess(...). */}
      {splitSuccess && (
        <SplitSuccessModal info={splitSuccess} onClose={() => setSplitSuccess(null)} />
      )}

      {/* CONFIRM / BROADCASTING / DONE / ERROR MODAL — four states driven
          by confirmAction shape:
          - splitBusy false + result null + no error  → INITIAL CONFIRM
          - splitBusy true                            → BROADCASTING (CANCEL
                                                       stays alive so a slow
                                                       Esplora can never trap
                                                       the user; backdrop
                                                       click also dismisses.)
          - splitBusy false + result.txid             → DONE — clickable txid
          - splitBusy false + error set               → ERROR — show message +
                                                       RETRY/DISMISS buttons
                                                       (params are preserved
                                                       so retry doesn't ask
                                                       the user to redo input).
          The wallet password comes from App-level sessionPassword, so this
          modal is the only per-op interaction the user needs. */}
      {confirmAction && confirmAction.kind === "split" && (() => {
        const { count, amountSats, feeRateSatVb, result, error } = confirmAction;
        const done = !!result;
        const errored = !done && !!error;
        const totalSats = count * amountSats;
        const estVsize = 11 + 68 + (count + 1) * 31;
        const estFee = Math.ceil(estVsize * feeRateSatVb);
        const txExplorer = result
          ? txExplorerUrl(result.network || (walletMeta?.network || "bitcoin"), result.txid)
          : null;
        const retrySplit = () => {
 // Clear the error so the modal re-renders in CONFIRM state, then
 // call executeSplit which transitions to BROADCASTING.
          setConfirmAction((prev) =>
            prev && prev.kind === "split" ? { ...prev, error: null } : prev
          );
 // Fire executeSplit on the next tick so it sees the cleared error.
          setTimeout(() => executeSplit(), 0);
        };
        return (
          <div
            onClick={() => setConfirmAction(null)}
            style={{
              position: "fixed", inset: 0, zIndex: 1000,
              background: "rgba(0,0,0,0.72)",
              backdropFilter: "blur(3px)",
              display: "flex", alignItems: "center", justifyContent: "center",
              padding: 20,
            }}
          >
            <div
              onClick={(e) => e.stopPropagation()}
              className="btx-panel"
              style={{
                maxWidth: 480, width: "100%",
                padding: 24,
                background: "linear-gradient(180deg, #1a1004 0%, #0a0602 100%)",
                border: `1px solid ${done ? "var(--hxm-green)" : errored ? "var(--hxm-red)" : "var(--hxm-gold-bright)"}`,
                borderRadius: 6,
                boxShadow: done
                  ? "0 0 40px rgba(58,180,90,0.35), inset 0 1px 0 rgba(120,220,140,0.18)"
                  : errored
                    ? "0 0 40px rgba(220,60,60,0.35), inset 0 1px 0 rgba(255,140,140,0.18)"
                    : "0 0 40px rgba(212,162,58,0.35), inset 0 1px 0 rgba(212,162,58,0.18)",
                position: "relative",
              }}
            >
              {/* Close (X) — always visible, always works, including during
                  broadcast. Lets the user dismiss a slow/stalled tx without
                  being stuck staring at a "BROADCASTING…" button. */}
              <button
                onClick={() => setConfirmAction(null)}
                style={{
                  position: "absolute", top: 10, right: 10,
                  background: "transparent", border: "none",
                  color: "var(--hxm-text-mute)",
                  cursor: "pointer", padding: 6,
                }}
                title="Close"
              >
                <X size={16} />
              </button>

              <div className="hxm-bebas" style={{
                fontSize: 18,
                color: done ? "var(--hxm-green)" : errored ? "var(--hxm-red)" : "var(--hxm-gold-bright)",
                letterSpacing: "0.22em", marginBottom: 4,
              }}>
                {done ? "SPLIT BROADCAST" : errored ? "SPLIT FAILED" : "CONFIRM SPLIT"}
              </div>
              <div className="hxm-mono" style={{ fontSize: 11, color: "var(--hxm-text-mute)", marginBottom: 16 }}>
                {done
                  ? "tx broadcast — confirmation arrives in the next block"
                  : errored
                    ? "broadcast did not complete — retry to send the same params again"
                    : "broadcast a real on-chain split tx"}
              </div>

              <div style={{
                display: "grid", gridTemplateColumns: "auto 1fr", gap: "8px 14px",
                fontSize: 12, marginBottom: 16,
              }}>
                <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)" }}>OUTPUTS</div>
                <div className="hxm-mono" style={{ color: "var(--hxm-gold-bright)" }}>
                  {count} × {(amountSats / 1e8).toFixed(8)} BTC
                </div>
                <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)" }}>TOTAL OUT</div>
                <div className="hxm-mono" style={{ color: "var(--hxm-gold-bright)" }}>
                  {(totalSats / 1e8).toFixed(8)} BTC
                </div>
                <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)" }}>FEE</div>
                {done ? (
                  <div className="hxm-mono" style={{ color: "var(--hxm-gold-bright)" }}>
                    {result.fee_sats.toLocaleString()} sat · {result.vsize} vB
                  </div>
                ) : (
                  <div className="hxm-mono">
                    {feeRateSatVb} sat/vB · ~{estFee.toLocaleString()} sat estimated
                  </div>
                )}
                <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)" }}>NETWORK</div>
                <div className="hxm-mono">{(walletMeta?.network || "bitcoin").toUpperCase()}</div>
                {!done && (
                  <>
                    <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)" }}>RECIPIENT</div>
                    <div className="hxm-mono" style={{ wordBreak: "break-all", fontSize: 11 }}>
                      your own wallet (each piece returns to your first BIP84 address)
                    </div>
                  </>
                )}
              </div>

              {done && (
                <div style={{ marginBottom: 16 }}>
                  <div className="hxm-mono" style={{ color: "var(--hxm-text-mute)", fontSize: 10, marginBottom: 4, letterSpacing: "0.18em" }}>
                    TXID
                  </div>
                  <a
                    href={txExplorer}
                    target="_blank"
                    rel="noopener noreferrer"
                    title="open on mempool.space"
                    style={{
                      display: "block",
                      fontFamily: "'JetBrains Mono', monospace",
                      fontSize: 12,
                      color: "var(--hxm-gold-bright)",
                      wordBreak: "break-all",
                      textDecoration: "underline",
                      padding: "8px 10px",
                      background: "rgba(0,0,0,0.45)",
                      border: "1px solid var(--hxm-line)",
                      borderRadius: 3,
                      lineHeight: 1.5,
                    }}
                  >
                    {result.txid}
                  </a>
                  {/* Auto-dismiss progress bar — drains from 100% → 0%
                      over 3s. Click anywhere on the modal (DONE button,
                      backdrop, X) to dismiss earlier. */}
                  <div style={{
                    marginTop: 10,
                    height: 3,
                    background: "rgba(0,0,0,0.5)",
                    border: "1px solid var(--hxm-line)",
                    borderRadius: 2,
                    overflow: "hidden",
                  }}>
                    <div style={{
                      width: `${autoDismissProgress}%`,
                      height: "100%",
                      background: "linear-gradient(90deg, var(--hxm-green) 0%, var(--hxm-green-dim) 100%)",
                      transition: "width 33ms linear",
                      boxShadow: "0 0 8px rgba(58,180,90,0.5)",
                    }} />
                  </div>
                </div>
              )}

              {errored && (
                <div style={{
                  fontSize: 11, lineHeight: 1.6,
                  color: "#ffb0b0",
                  padding: "10px 12px",
                  background: "rgba(60,12,12,0.55)",
                  border: "1px solid var(--hxm-red)",
                  borderRadius: 3, marginBottom: 18,
                  fontFamily: "'JetBrains Mono', monospace",
                  wordBreak: "break-word",
                  maxHeight: 140,
                  overflowY: "auto",
                }}>
                  <div style={{ color: "var(--hxm-red)", letterSpacing: "0.16em", fontFamily: "'Bebas Neue', sans-serif", fontSize: 10, marginBottom: 4 }}>
                    ERROR DETAIL
                  </div>
                  {error}
                </div>
              )}

              {!done && !errored && (
                <div style={{
                  fontSize: 10, lineHeight: 1.6,
                  color: "var(--hxm-text-dim)",
                  padding: "8px 10px",
                  background: "rgba(0,0,0,0.4)",
                  border: "1px solid var(--hxm-line)",
                  borderRadius: 3, marginBottom: 18,
                }}>
                  bdk_wallet will pick the input UTXO(s) automatically. Fee is
                  deducted from the change output. The new pieces appear as
                  pending in the wallet until the next block confirms.
                </div>
              )}

              <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", alignItems: "center" }}>
                {done ? (
                  <>
                    <span className="hxm-mono" style={{
                      fontSize: 10, color: "var(--hxm-text-mute)",
                      marginRight: "auto",
                      letterSpacing: "0.04em",
                    }}>
                      auto-closing in {Math.ceil((autoDismissProgress / 100) * (AUTO_DISMISS_MS / 1000))}s…
                    </span>
                    <a
                      className="btx-btn-ghost"
                      href={txExplorer}
                      target="_blank"
                      rel="noopener noreferrer"
                      style={{ padding: "8px 16px", fontSize: 12, textDecoration: "none" }}
                    >
                      VIEW ON MEMPOOL.SPACE
                    </a>
                    <button
                      className="btx-btn-primary"
                      style={{ padding: "8px 22px", fontSize: 12 }}
                      onClick={() => setConfirmAction(null)}
                    >
                      DONE
                    </button>
                  </>
                ) : errored ? (
                  <>
                    <button
                      className="btx-btn-ghost"
                      style={{ padding: "8px 18px", fontSize: 12 }}
                      onClick={() => setConfirmAction(null)}
                    >
                      DISMISS
                    </button>
                    <button
                      className="btx-btn-primary"
                      style={{ padding: "8px 22px", fontSize: 12 }}
                      onClick={retrySplit}
                    >
                      RETRY
                    </button>
                  </>
                ) : (
                  <>
                    {/* CANCEL is always enabled — even during BROADCASTING,
                        so a slow tx broadcast can't trap the user. The
                        in-flight promise still resolves in the background
                        and surfaces the txid via toast + the bet/utxo
                        history when it lands. */}
                    <button
                      className="btx-btn-ghost"
                      style={{ padding: "8px 18px", fontSize: 12 }}
                      onClick={() => setConfirmAction(null)}
                    >
                      {splitBusy ? "DISMISS" : "CANCEL"}
                    </button>
                    <button
                      className="btx-btn-primary"
                      style={{ padding: "8px 22px", fontSize: 12 }}
                      onClick={executeSplit}
                      disabled={splitBusy}
                    >
                      {splitBusy ? "BROADCASTING..." : "CONFIRM"}
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
}


// =============================================================================
// TRANSACTIONS SCREEN — wallet's on-chain transaction history at the
// external receive address. Polls Esplora for the most recent 25 txs;
// each row shows direction (incoming / outgoing / self), net delta in
// BTC, fee, time, LUCKYPROTOCOL payload (if any), and a clickable txid.
// =============================================================================
// Module-level reader for `luckyprotocol.local_txs.v1` + `luckyprotocol.bets.v1`,
// applying the same status-overlay logic the periodic 5s poll uses.
// Used as the lazy-init source for TransactionsScreen's `localTxs` and
// `bets` state so synthetic rows (the user's just-broadcast txs that
// Esplora's address index hasn't picked up yet) render on the first
// paint when the user clicks LEDGER — no waiting for the first
// useEffect tick before the table populates.
function _readLocalTxsAndBets() {
  try {
    const rawLocal = window.localStorage.getItem("luckyprotocol.local_txs.v1");
    const local = rawLocal ? JSON.parse(rawLocal) : [];
    const rawBets = window.localStorage.getItem("luckyprotocol.bets.v1");
    const betsArr = rawBets ? JSON.parse(rawBets) : [];
    const localTxids = new Set((local || []).map((e) => e.txid));
    const fromBets = (betsArr || [])
      .filter((b) => b && b.txid && !localTxids.has(b.txid))
      .map((b) => {
 // Synthesize payload from tier/pick/ticker for legacy bet
 // records that pre-date the `payload` field. Without this,
 // those rows would show as RECV/SELF in TransactionsScreen
 // (because directionMeta keys off payload presence) even
 // though they're real on-chain LUCKYPROTOCOL bets.
        let payload = b.payload;
        if (!payload && b.tier && b.pick && b.ticker) {
          payload = `LUCKYPROTOCOL|${b.tier}|${String(b.pick).toLowerCase()}|${b.ticker}`;
        }
        return {
          txid: b.txid, kind: "bet", payload,
          fee_sats: b.fee_sats, vsize: b.vsize, network: b.network,
          broadcast_at: b.broadcast_at,
          sent_sats: b.fee_sats || 0, received_sats: 0,
          confirmed: !!b.status?.confirmed,
          block_height: b.status?.block_height ?? null,
          block_time: b.status?.block_time ?? null,
        };
      });
    const betStatusByTxid = new Map();
    for (const b of betsArr || []) {
      if (b && b.txid && b.status?.confirmed) betStatusByTxid.set(b.txid, b.status);
    }
    const localWithStatus = (local || []).map((e) => {
      const s = betStatusByTxid.get(e.txid);
      if (!s) return e;
      return {
        ...e,
        confirmed: !!s.confirmed,
        block_height: s.block_height ?? null,
        block_time: s.block_time ?? null,
      };
    });
    return {
      localTxs: [...localWithStatus, ...fromBets],
      bets: Array.isArray(betsArr) ? betsArr : [],
    };
  } catch {
    return { localTxs: [], bets: [] };
  }
}

// =============================================================================
// BRIDGE — placeholder "COMING SOON" splash.
// Carries the casino-interior photo as the screen's own backdrop
